INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 1, 'Deus', 'A Natureza e os Atributos do Deus Eterno', 'Cremos que existe um só Deus, que por meio de Sua onisciência e onipotência criou o Céu e a Terra. Deus é um Ser espiritual, eterno, sem princípio e sem fim, presente em toda parte, porém invisível aos homens em seu estado pecaminoso. Somente pela fé podemos chegar a Deus.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"De acordo com os Princípios de Fé, quantos deuses existem?","opcoes":[{"id":"a","texto":"Existem três deuses distintos e independentes"},{"id":"b","texto":"Existe um só Deus, que por meio de Sua onisciência e onipotência criou o Céu e a Terra"},{"id":"c","texto":"Existem muitos deuses, mas apenas um é digno de adoração"},{"id":"d","texto":"A Bíblia não define quantos deuses existem"}],"resposta_correta":"b","explicacao":"A Bíblia e os Princípios de Fé afirmam categoricamente que existe um único Deus, não três nem muitos. Este Deus único criou o Céu e a Terra por Sua onisciência (conhecimento ilimitado) e onipotência (poder absoluto).","referencias":[{"texto":"Êxodo 20:2-3","livro":"Êxodo","capitulo":20,"versiculo":"2-3","conteudo":"Eu sou o Senhor, teu Deus, que te tirei da terra do Egito, da casa da servidão. Não terás outros deuses diante de mim."},{"texto":"Isaías 45:5-6","livro":"Isaías","capitulo":45,"versiculo":"5-6","conteudo":"Eu sou o Senhor, e não há outro; fora de mim não há Deus. Eu te cingir, embora tu não me conheces, para que se saiba desde o nascente do sol e desde o poente que só eu sou o Senhor e não há outro."}]},{"id":"q2","numero":2,"texto":"Qual é a natureza de Deus segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Deus é um Ser material, visível e limitado ao Céu"},{"id":"b","texto":"Deus é um Ser espiritual, eterno, sem princípio e sem fim"},{"id":"c","texto":"Deus é uma força impessoal que permeia o universo"},{"id":"d","texto":"Deus é um Ser que teve começo mas não terá fim"}],"resposta_correta":"b","explicacao":"Segundo a Bíblia, Deus é um Ser espiritual, não material. Ele é eterno, ou seja, sem começo e sem fim. Essa natureza espiritual e eterna o distingue de toda criação material.","referencias":[{"texto":"João 4:24","livro":"João","capitulo":4,"versiculo":"24","conteudo":"Deus é Espírito; e importa que os que o adoram o adorem em espírito e em verdade."},{"texto":"Apocalipse 21:6","livro":"Apocalipse","capitulo":21,"versiculo":"6","conteudo":"Disse-me ainda: Está feito. Eu sou o Alfa e o Ômega, o princípio e o fim. A quem tiver sede darei de beber gratuitamente da fonte da água da vida."}]},{"id":"q3","numero":3,"texto":"Por que Deus é invisível aos homens no presente estado?","opcoes":[{"id":"a","texto":"Porque Deus não deseja se revelar"},{"id":"b","texto":"Porque os homens não possuem tecnologia suficiente para vê-Lo"},{"id":"c","texto":"Por causa do estado pecaminoso dos homens"},{"id":"d","texto":"Porque Deus habita em outra dimensão inacessível"}],"resposta_correta":"c","explicacao":"A invisibilidade de Deus aos homens atuais não é falha de tecnologia ou recusa divina, mas consequência do pecado que separa o homem de Deus. O pecado criou uma barreira que impede a contemplação de Sua glória.","referencias":[{"texto":"1 Timóteo 6:16","livro":"1 Timóteo","capitulo":6,"versiculo":"16","conteudo":"Aquele que é o único detentor da imortalidade, que habita em luz inacessível, a quem nenhum dos homens viu, nem é possível ver. A ele seja honra e poder eterno. Amém."},{"texto":"Isaías 59:2","livro":"Isaías","capitulo":59,"versiculo":"2","conteudo":"Mas as vossas iniquidades fazem separação entre vós e o vosso Deus; e os vossos pecados encobrem seu rosto de vós, para que vos não ouça."}]},{"id":"q4","numero":4,"texto":"Onde Deus tem Seu trono e como podemos chegar até Ele?","opcoes":[{"id":"a","texto":"Seu trono está na Terra e chegamos por meio de boas obras"},{"id":"b","texto":"Seu trono está no Céu e somente pela fé podemos chegar a Deus"},{"id":"c","texto":"Seu trono está em toda parte e qualquer caminho leva a Ele"},{"id":"d","texto":"Seu trono está no templo terrestre e chegamos por meio de sacrifícios"}],"resposta_correta":"b","explicacao":"O trono de Deus está no Céu, não na Terra. O único caminho para chegar a Deus não é por boas obras ou rituais, mas pela fé em Sua Palavra e em Seu poder. A fé é o requisito fundamental para comunhão com Deus.","referencias":[{"texto":"Hebreus 11:6","livro":"Hebreus","capitulo":11,"versiculo":"6","conteudo":"Pois sem fé é impossível agradar a Deus; porque é necessário que quem se aproxima de Deus creia que ele existe e que é galardoador dos que o buscam."},{"texto":"Salmo 139:1-12","livro":"Salmo","capitulo":139,"versiculo":"1-12","conteudo":"Senhor, tu me sondas e conheces. Tu sabes quando me sento e quando me levanto; de longe penetras os meus pensamentos. Tu esquadrinhas o meu andar e o meu repouso, e todos os meus caminhos te são conhecidos. Pois a palavra ainda me não chegou à língua, e eis que, Senhor, a conheces toda. Tu me cercas por trás e por diante, e colocas sobre mim a tua mão."}]},{"id":"q5","numero":5,"texto":"Deus está presente em toda parte. Qual texto bíblico confirma esta onipresença?","opcoes":[{"id":"a","texto":"Gênesis 1:1 — No princípio criou Deus os céus e a terra"},{"id":"b","texto":"Salmo 139:1-12 — Para onde me irei do Teu Espírito, ou para onde fugirei da Tua face?"},{"id":"c","texto":"Apocalipse 21:6 — Eu sou o Alfa e o Ômega"},{"id":"d","texto":"João 4:24 — Deus é Espírito"}],"resposta_correta":"b","explicacao":"O Salmo 139 expressa claramente a onipresença divina: não há lugar onde se possa fugir da presença de Deus, Seu Espírito está em toda parte. Esta é a verdade central sobre a ubiquidade de Deus.","referencias":[{"texto":"Salmo 139:1-12","livro":"Salmo","capitulo":139,"versiculo":"1-12","conteudo":"Senhor, tu me sondas e conheces. Tu sabes quando me sento e quando me levanto; de longe penetras os meus pensamentos. Tu esquadrinhas o meu andar e o meu repouso, e todos os meus caminhos te são conhecidos. Pois a palavra ainda me não chegou à língua, e eis que, Senhor, a conheces toda. Tu me cercas por trás e por diante, e colocas sobre mim a tua mão."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que existe um só Deus, eterno e todo-poderoso, Criador do Céu e da Terra."},{"id":"cf2","texto":"Reconheço que somente pela fé posso me aproximar de Deus."},{"id":"cf3","texto":"Desejo conhecer mais profundamente os atributos de Deus revelados em Sua Palavra."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 2, 'Jesus Cristo', 'O Redentor e Mediador da Humanidade', 'Jesus Cristo é o vivo Filho de Deus, sendo em essência um com o Pai. Por meio dEle todas as coisas foram criadas e é o único Mediador entre Deus e os homens. Ele veio ao mundo gerado pelo Espírito Santo e nascido da virgem Maria, viveu sem pecado, morreu pela redenção de toda a humanidade e ressuscitou ao terceiro dia.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Quem é Jesus Cristo segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Um grande profeta enviado por Deus"},{"id":"b","texto":"O vivo Filho de Deus, sendo em essência um com o Pai"},{"id":"c","texto":"Um anjo exaltado que se tornou humano"},{"id":"d","texto":"Um homem comum que foi adotado por Deus"}],"resposta_correta":"b","explicacao":"Jesus Cristo é o Filho vivo de Deus em essência um com o Pai desde a eternidade. Ele é divino e foi enviado para efetuar a redenção da humanidade.","referencias":[{"texto":"Hebreus 1:1-3,5","livro":"Hebreus","capitulo":1,"versiculo":"1-3,5","conteudo":"Havendo Deus antigamente falado muitas vezes e de muitas maneiras aos pais pelos profetas, nestes últimos dias nos falou pelo Filho... que é o resplendor da Sua glória e a expressão do Seu ser."}]},{"id":"q2","numero":2,"texto":"Por que somente Jesus pode ser Mediador entre Deus e os homens?","opcoes":[{"id":"a","texto":"Porque Ele é o mais poderoso dos anjos"},{"id":"b","texto":"Porque todas as coisas foram criadas por meio dEle"},{"id":"c","texto":"Porque Ele é o único que nunca pecou enquanto era anjo"},{"id":"d","texto":"Porque Ele foi escolhido por votação no Céu"}],"resposta_correta":"b","explicacao":"Jesus é o único Mediador porque todas as coisas foram criadas por meio dEle, fazendo-O o instrumento criador de Deus e o único digno de representar tanto Deus como a humanidade.","referencias":[{"texto":"Colossenses 1:15-17","livro":"Colossenses","capitulo":1,"versiculo":"15-17","conteudo":"Ele é a imagem do Deus invisível, o primogênito de toda a criação; porque nEle foram criadas todas as coisas, nos céus e sobre a terra, visíveis e invisíveis."}]},{"id":"q3","numero":3,"texto":"Como Jesus veio ao mundo segundo a profecia e o testemunho bíblico?","opcoes":[{"id":"a","texto":"Desceu diretamente do Céu em forma adulta"},{"id":"b","texto":"Foi gerado pelo Espírito Santo e nasceu da virgem Maria em Belém"},{"id":"c","texto":"Nasceu como qualquer outro ser humano, de pai e mãe naturais"},{"id":"d","texto":"Surgiu milagrosamente no templo de Jerusalém"}],"resposta_correta":"b","explicacao":"Jesus foi gerado pelo Espírito Santo e nasceu da virgem Maria em Belém, cumprindo as profecias messiânicas. Sua encarnação teve início miraculoso mas Seu nascimento foi literal.","referencias":[{"texto":"Mateus 1:18-23","livro":"Mateus","capitulo":1,"versiculo":"18-23","conteudo":"Ora, o nascimento de Jesus Cristo foi assim: Estando Maria, Sua mãe, desposada com José, antes de coabitarem, achou-se que havia concebido do Espírito Santo."}]},{"id":"q4","numero":4,"texto":"Só por meio de que podemos ser salvos, segundo o texto?","opcoes":[{"id":"a","texto":"Por meio de boas obras e obediência à Lei"},{"id":"b","texto":"Por meio da morte de Jesus, e pela fé na graça que Ele nos deu"},{"id":"c","texto":"Por meio da mediação dos santos e da Igreja"},{"id":"d","texto":"Por meio do conhecimento intelectual das Escrituras"}],"resposta_correta":"b","explicacao":"A salvação é exclusivamente por meio da morte redentora de Jesus e pela fé pessoal nessa graça salvadora. Nenhuma outra pessoa ou obra pode nos redimir.","referencias":[{"texto":"Atos 4:12","livro":"Atos","capitulo":4,"versiculo":"12","conteudo":"E não há salvação em nenhum outro; porque também debaixo do céu nenhum outro nome há, dado entre os homens, pelo qual devamos ser salvos."}]},{"id":"q5","numero":5,"texto":"Desde quando todas as coisas no Céu e na Terra foram criadas por meio de Cristo?","opcoes":[{"id":"a","texto":"Desde o momento do Seu nascimento em Belém"},{"id":"b","texto":"Desde a eternidade — antes mesmo da criação do mundo"},{"id":"c","texto":"Desde o início do ministério terrestre de Jesus"},{"id":"d","texto":"Desde a Sua ressurreição e ascensão ao Céu"}],"resposta_correta":"b","explicacao":"Cristo criou todas as coisas desde a eternidade passada, muito antes de Sua encarnação em Belém. Sua criação foi anterior à fundação do mundo.","referencias":[{"texto":"Hebreus 1:1-3,5","livro":"Hebreus","capitulo":1,"versiculo":"1-3,5","conteudo":"Havendo Deus antigamente falado muitas vezes... nestes últimos dias nos falou pelo Filho, a quem constituiu herdeiro de tudo, por quem também fez o universo."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que Jesus Cristo é o Filho de Deus, meu Redentor pessoal."},{"id":"cf2","texto":"Reconheço a importância do sacrifício de Jesus na cruz para minha salvação."},{"id":"cf3","texto":"Desejo aceitar Jesus como Senhor e Salvador da minha vida."}]'::jsonb)
