INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 3, 'O Espírito Santo', 'O Representante de Cristo na Terra', 'O Espírito Santo é o Representante de Cristo na Terra, procede do Pai e do Filho e é onisciente. Sem o Espírito Santo, é impossível ao ser humano conhecer e cumprir a vontade de Deus. Ele opera entre os homens por meio de instrumentos humanos, guiando a Igreja na verdade e poder espiritual.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que é o Espírito Santo segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Uma força impessoal emanada de Deus"},{"id":"b","texto":"O Representante de Cristo na Terra"},{"id":"c","texto":"Apenas uma influência divina sobre os crentes"},{"id":"d","texto":"Um anjo especial enviado para guardar a Igreja"}],"resposta_correta":"b","explicacao":"O Espírito Santo é uma Pessoa divina, o Representante de Cristo na Terra, com atributos pessoais e poder para guiar e fortalecer a Igreja.","referencias":[{"texto":"João 14:16","livro":"João","capitulo":14,"versiculo":"16","conteudo":"E Eu rogarei ao Pai, e Ele vos dará outro Paráclito, para que fique convosco eternamente."}]},{"id":"q2","numero":2,"texto":"Sem o Espírito Santo, o que é impossível ao ser humano?","opcoes":[{"id":"a","texto":"Ler e entender qualquer livro religioso"},{"id":"b","texto":"Conhecer e cumprir a vontade de Deus, bem como interpretar corretamente a Palavra"},{"id":"c","texto":"Frequentar a igreja e participar dos cultos"},{"id":"d","texto":"Realizar obras de caridade e amor ao próximo"}],"resposta_correta":"b","explicacao":"Sem o Espírito Santo é impossível compreender e obedecer a vontade de Deus ou entender corretamente as verdades espirituais da Palavra divina.","referencias":[{"texto":"João 14:26","livro":"João","capitulo":14,"versiculo":"26","conteudo":"Mas o Paráclito, o Espírito Santo, que o Pai enviará em Meu nome, Esse vos ensinará todas as coisas."}]},{"id":"q3","numero":3,"texto":"O Espírito Santo é um poder de quem?","opcoes":[{"id":"a","texto":"Somente do Pai"},{"id":"b","texto":"Somente do Filho"},{"id":"c","texto":"Do Pai e do Filho"},{"id":"d","texto":"De todos os anjos celestiais"}],"resposta_correta":"c","explicacao":"O Espírito Santo é o poder divino comum ao Pai e ao Filho, procedendo de ambos e sendo manifestação do poder criador e redentor trinitário.","referencias":[{"texto":"1 Coríntios 2:11","livro":"1 Coríntios","capitulo":2,"versiculo":"11","conteudo":"Porque qual é o homem que sabe as coisas do homem, senão o espírito do homem que nele está? Assim também ninguém conhece as coisas de Deus, senão o Espírito de Deus."}]},{"id":"q4","numero":4,"texto":"Em nome de quem os crentes são batizados?","opcoes":[{"id":"a","texto":"Somente em nome de Jesus Cristo"},{"id":"b","texto":"Em nome do Pai, do Filho e do Espírito Santo"},{"id":"c","texto":"Em nome do Pai e do Filho somente"},{"id":"d","texto":"Em nome da Igreja e dos apóstolos"}],"resposta_correta":"b","explicacao":"O batismo é ministrado em nome dos Três —Pai, Filho e Espírito Santo — demonstrando a divindade e unidade funcional da Trindade divina.","referencias":[{"texto":"Mateus 28:19","livro":"Mateus","capitulo":28,"versiculo":"19","conteudo":"Portanto, ide, fazei discípulos de todas as nações, batizando-os em nome do Pai, e do Filho, e do Espírito Santo."}]},{"id":"q5","numero":5,"texto":"Como o Espírito Santo opera entre os homens?","opcoes":[{"id":"a","texto":"Diretamente, sem qualquer intermediário"},{"id":"b","texto":"Por meio dos homens, usando instrumentos humanos"},{"id":"c","texto":"Somente por meio dos anjos celestiais"},{"id":"d","texto":"Apenas por meio de sinais e milagres visíveis"}],"resposta_correta":"b","explicacao":"O Espírito Santo opera fundamentalmente através de seres humanos como Seus instrumentos, capacitando-os para realizar Sua obra na Terra.","referencias":[{"texto":"2 Pedro 1:21","livro":"2 Pedro","capitulo":1,"versiculo":"21","conteudo":"Porque a profecia nunca foi produzida por vontade de homem algum, mas os homens santos de Deus falaram sendo movidos pelo Espírito Santo."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o Espírito Santo é uma Pessoa divina distinta."},{"id":"cf2","texto":"Reconheço a necessidade do Espírito Santo para entender e cumprir a Palavra de Deus."},{"id":"cf3","texto":"Desejo render-me completamente ao poder transformador do Espírito Santo."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 4, 'A Escritura Sagrada', 'A Palavra de Deus como Regra de Fé', 'A Bíblia, tanto o Novo como o Velho Testamento, é a Palavra de Deus que revela a vontade divina. Foi escrita por inspiração do Espírito Santo e serve como norma e regra de vida para todo cristão. Não necessitamos de tradição humana ou catecismo além da Bíblia para entender o plano da salvação.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que são o Novo e o Velho Testamentos da Escritura Sagrada?","opcoes":[{"id":"a","texto":"Livros históricos escritos por homens sábios"},{"id":"b","texto":"A Palavra de Deus que revela a vontade de Deus"},{"id":"c","texto":"Compilações de tradições e lendas religiosas"},{"id":"d","texto":"Apenas o Novo Testamento é a Palavra de Deus"}],"resposta_correta":"b","explicacao":"Tanto o Novo como o Velho Testamento constituem a Palavra de Deus. Ambos revelam a vontade divina e são inspirados pelo Espírito Santo. Não são meros relatos históricos ou compilações de tradições humanas.","referencias":[{"texto":"João 5:39","livro":"João","capitulo":5,"versiculo":"39","conteudo":"Examinais as Escrituras, porque vós cuidais ter nelas a vida eterna, e são elas que de mim testificam."}]},{"id":"q2","numero":2,"texto":"Por quem foi escrita a Bíblia e qual é sua função?","opcoes":[{"id":"a","texto":"Pelos reis de Israel; serve como registro histórico"},{"id":"b","texto":"Por inspiração do Espírito Santo; é a norma e regra de vida"},{"id":"c","texto":"Pelos sacerdotes; serve como manual de rituais"},{"id":"d","texto":"Pelos apóstolos somente; é um guia moral opcional"}],"resposta_correta":"b","explicacao":"A Bíblia foi escrita por inspiração do Espírito Santo, não por iniciativa humana. Sua função primordial é ser a norma e regra de vida para todo cristão, orientando decisões e condutas.","referencias":[{"texto":"2 Timóteo 3:16","livro":"2 Timóteo","capitulo":3,"versiculo":"16","conteudo":"Toda a Escritura é divinamente inspirada e proveitosa para ensinar, para redarguir, para corrigir, para instruir em justiça."},{"texto":"Romanos 1:16","livro":"Romanos","capitulo":1,"versiculo":"16","conteudo":"Porque não me envergonho do evangelho de Cristo, pois é o poder de Deus para salvação de todo aquele que crê; primeiro do judeu, e também do grego."},{"texto":"Apocalipse 1:2","livro":"Apocalipse","capitulo":1,"versiculo":"2","conteudo":"Ele testificou da palavra de Deus, e do testemunho de Jesus Cristo, de tudo quanto viu."}]},{"id":"q3","numero":3,"texto":"De que não necessitamos além da Bíblia para entender o plano da salvação?","opcoes":[{"id":"a","texto":"De outros livros religiosos e comentários"},{"id":"b","texto":"De tradição humana ou de catecismo"},{"id":"c","texto":"De revelações pessoais e visões místicas"},{"id":"d","texto":"De educação teológica formal"}],"resposta_correta":"b","explicacao":"Tradição humana e catecismo não são necessários para compreender o plano salvação. A Bíblia é suficiente e completa em si mesma. Adições humanas podem obscurecer a verdade revelada por Deus.","referencias":[{"texto":"Isaías 34:16","livro":"Isaías","capitulo":34,"versiculo":"16","conteudo":"Buscai no livro do Senhor, e lede; nenhuma destas coisas faltará, nem uma nem outra faltará, porque a sua boca o mandou."},{"texto":"Apocalipse 22:18-19","livro":"Apocalipse","capitulo":22,"versiculo":"18-19","conteudo":"Eu, a todo aquele que ouve as palavras da profecia deste livro, testifico: Se alguém lhes acrescentar alguma coisa, Deus lhe acrescentará as pragas que estão escritas neste livro; e se alguém tirar alguma coisa das palavras do livro desta profecia, Deus tirará a sua parte da árvore da vida."},{"texto":"Mateus 15:9","livro":"Mateus","capitulo":15,"versiculo":"9","conteudo":"Mas em vão me adoram, ensinando doutrinas que são mandamentos de homens."},{"texto":"Provérbios 30:6","livro":"Provérbios","capitulo":30,"versiculo":"6","conteudo":"Nada acrescentes às suas palavras, para que não te repreenda, e sejas achado mentiroso."}]},{"id":"q4","numero":4,"texto":"O que está contido na Bíblia segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Apenas os ensinamentos morais de Jesus"},{"id":"b","texto":"Todo o plano da salvação, sem necessidade de tradição humana ou catecismo"},{"id":"c","texto":"Informações parciais que precisam ser completadas pela tradição"},{"id":"d","texto":"Somente profecias sobre o fim do mundo"}],"resposta_correta":"b","explicacao":"A Bíblia contém todo o plano da salvação de forma completa e suficiente. Não necessita ser complementada por tradição, catecismo ou interpretações humanas. É um documento integral e autossuficiente.","referencias":[{"texto":"2 Timóteo 3:16","livro":"2 Timóteo","capitulo":3,"versiculo":"16","conteudo":"Toda a Escritura é divinamente inspirada e proveitosa para ensinar, para redarguir, para corrigir, para instruir em justiça."},{"texto":"João 5:39","livro":"João","capitulo":5,"versiculo":"39","conteudo":"Examinais as Escrituras, porque vós cuidais ter nelas a vida eterna, e são elas que de mim testificam."}]},{"id":"q5","numero":5,"texto":"Qual é a posição da Bíblia em relação ao plano de Deus para a humanidade?","opcoes":[{"id":"a","texto":"É uma das muitas fontes de conhecimento espiritual"},{"id":"b","texto":"É a forma como Deus revela a Sua vontade ao ser humano"},{"id":"c","texto":"É importante mas não essencial para a salvação"},{"id":"d","texto":"Serve apenas como referência histórica"}],"resposta_correta":"b","explicacao":"A Bíblia é o meio único e supremo pelo qual Deus revela Sua vontade à humanidade. Não é uma entre várias fontes, mas a fonte autorizada e infalível da revelação divina para a salvação.","referencias":[{"texto":"João 5:39","livro":"João","capitulo":5,"versiculo":"39","conteudo":"Examinais as Escrituras, porque vós cuidais ter nelas a vida eterna, e são elas que de mim testificam."},{"texto":"2 Timóteo 3:16","livro":"2 Timóteo","capitulo":3,"versiculo":"16","conteudo":"Toda a Escritura é divinamente inspirada e proveitosa para ensinar, para redarguir, para corrigir, para instruir em justiça."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a Bíblia é a Palavra de Deus, inspirada e autorizada."},{"id":"cf2","texto":"Reconheço a Bíblia como a única norma infalível para minha fé e prática."},{"id":"cf3","texto":"Desejo estudar e obedecer fielmente os ensinamentos bíblicos."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 5, 'A Lei de Deus', 'Os Dez Mandamentos e Sua Eternidade', 'A Lei de Deus, expressa nos Dez Mandamentos, é perfeita e eterna. Cristo não veio derrogar a Lei, mas a cumprir e revelar seu espírito eterno. O reconhecimento e observância dos Dez Mandamentos é a forma como demonstramos nosso amor a Deus e nosso reconhecimento de Sua autoridade suprema.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Cristo veio fazer algum melhoramento na Lei de Deus dada no Sinai?","opcoes":[{"id":"a","texto":"Sim, Ele veio atualizar a Lei para os novos tempos"},{"id":"b","texto":"Não, pois os Dez Mandamentos são perfeitos e não há possibilidade de melhoramento"},{"id":"c","texto":"Sim, Ele aboliu a Lei e estabeleceu uma nova aliança"},{"id":"d","texto":"Ele substituiu a Lei por mandamentos mais simples"}],"resposta_correta":"b","explicacao":"Os Dez Mandamentos são perfeitos e eternos. Cristo não veio corrigi-los, modificá-los ou atualizá-los, mas a cumpri-los e revelar seu verdadeiro espírito. Não há possibilidade de melhoramento naquilo que é perfeito.","referencias":[{"texto":"Mateus 5:17","livro":"Mateus","capitulo":5,"versiculo":"17","conteudo":"Não penseis que vim revogar a lei ou os profetas; não vim revogar, mas cumprir."},{"texto":"Salmo 119:142","livro":"Salmo","capitulo":119,"versiculo":"142","conteudo":"A tua justiça é justiça eterna, e a tua lei é a verdade."}]},{"id":"q2","numero":2,"texto":"O que prova aquele que declara a Lei de Deus mudada ou anulada?","opcoes":[{"id":"a","texto":"Que tem uma compreensão superior da Palavra"},{"id":"b","texto":"Que peca contra Deus, consciente ou inconscientemente"},{"id":"c","texto":"Que entende melhor a graça de Cristo"},{"id":"d","texto":"Que é um estudante avançado da Bíblia"}],"resposta_correta":"b","explicacao":"Aquele que nega a Lei de Deus ou declara que foi mudada ou anulada comete pecado. Segundo a Bíblia, o pecado é transgressão da Lei. Negar a Lei é negar a definição do pecado e a medida da justiça.","referencias":[{"texto":"Tiago 2:10","livro":"Tiago","capitulo":2,"versiculo":"10","conteudo":"Pois qualquer que guardar toda a lei, mas tropeçar em um só ponto, tem-se tornado culpado de tudo."},{"texto":"1 João 3:10","livro":"1 João","capitulo":3,"versiculo":"10","conteudo":"Nisto são manifestos os filhos de Deus e os filhos do diabo: quem não pratica justiça não é de Deus, nem aquele que não ama a seu irmão."},{"texto":"Mateus 7:21","livro":"Mateus","capitulo":7,"versiculo":"21","conteudo":"Nem todo aquele que me diz: Senhor, Senhor, entrará no reino dos céus, mas aquele que faz a vontade de meu Pai, que está nos céus."}]},{"id":"q3","numero":3,"texto":"Como mostramos que amamos a Deus e ao Seu Filho Jesus?","opcoes":[{"id":"a","texto":"Frequentando a igreja todos os dias"},{"id":"b","texto":"Pelo reconhecimento e observância dos Dez Mandamentos"},{"id":"c","texto":"Fazendo orações longas e jejuns frequentes"},{"id":"d","texto":"Pregando o Evangelho em todas as nações"}],"resposta_correta":"b","explicacao":"A observância dos Dez Mandamentos é a verdadeira expressão de amor a Deus e a Jesus. Não é apenas sentimento, mas ação concreta. O amor a Deus se manifesta na obediência consciente à Sua vontade revelada.","referencias":[{"texto":"João 15:10","livro":"João","capitulo":15,"versiculo":"10","conteudo":"Se guardardes os meus mandamentos, permanecereis no meu amor; como também eu tenho guardado os mandamentos de meu Pai, e permaneço no seu amor."},{"texto":"João 14:15,21","livro":"João","capitulo":14,"versiculo":"15,21","conteudo":"Se me amais, guardai os meus mandamentos... Aquele que tem os meus mandamentos e os guarda, esse é o que me ama; e aquele que me ama será amado de meu Pai, e eu o amarei, e me manifestarei a ele."},{"texto":"1 João 2:3-6","livro":"1 João","capitulo":2,"versiculo":"3-6","conteudo":"E nisto sabemos que o conhecemos, se guardarmos os seus mandamentos. Aquele que diz: Eu o conheço, e não guarda os seus mandamentos, é mentiroso, e nele não está a verdade."}]},{"id":"q4","numero":4,"texto":"Deus admite transgressão de Sua Lei sob que circunstâncias?","opcoes":[{"id":"a","texto":"Em casos de emergência e necessidade extrema"},{"id":"b","texto":"Quando as autoridades civis assim determinam"},{"id":"c","texto":"Em nenhuma circunstância — nem mesmo sob coação ou perseguição por parte das autoridades"},{"id":"d","texto":"Quando a consciência individual assim permitir"}],"resposta_correta":"c","explicacao":"A Lei de Deus é absoluta e não admite exceções. Mesmo sob perseguição, coação ou pressão de autoridades civis, não podemos transgredir os mandamentos de Deus. Nossa obediência a Deus é incondicional e suprema.","referencias":[{"texto":"Atos 5:29","livro":"Atos","capitulo":5,"versiculo":"29","conteudo":"Respondeu Pedro e os apóstolos: Antes importa obedecer a Deus do que aos homens."},{"texto":"Daniel 3","livro":"Daniel","capitulo":3,"versiculo":"1-30","conteudo":"O rei Nabucodonosor fez uma estátua de ouro... e a mandou pôr na planície de Dura... Que ninguém se curve nem adore esta estátua, senão será lançado numa fornalha de fogo ardente."},{"texto":"Mateus 22:21","livro":"Mateus","capitulo":22,"versiculo":"21","conteudo":"Respondeu-lhes: Dai pois a César o que é de César, e a Deus o que é de Deus."}]},{"id":"q5","numero":5,"texto":"Quem tem o direito de promulgar leis em questões de fé?","opcoes":[{"id":"a","texto":"Os governos civis em conjunto com a Igreja"},{"id":"b","texto":"Os líderes religiosos de cada denominação"},{"id":"c","texto":"Nem homem nem poder algum tem esse direito"},{"id":"d","texto":"Os concílios eclesiásticos reunidos em assembleia"}],"resposta_correta":"c","explicacao":"Somente Deus tem o direito e a autoridade de estabelecer leis espirituais e de fé. Nem homens, nem governos, nem instituições religiosas podem promulgar novas leis em questões de fé. A Lei de Deus é suprema e exclusiva.","referencias":[{"texto":"Isaías 42:8","livro":"Isaías","capitulo":42,"versiculo":"8","conteudo":"Eu sou o Senhor; este é o meu nome; a minha glória não darei a outrem, nem a meus louva dores."},{"texto":"João 10:35","livro":"João","capitulo":10,"versiculo":"35","conteudo":"Se chamou deuses àqueles a quem a palavra de Deus foi dirigida (e a Escritura não pode ser anulada)..."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que os Dez Mandamentos são a expressão imutável da vontade de Deus."},{"id":"cf2","texto":"Reconheço a Lei de Deus como revelação perfeita de Seu caráter eterno."},{"id":"cf3","texto":"Desejo guardar os Mandamentos de Deus como expressão de amor e fidelidade."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 6, 'O Quarto Mandamento', 'O Sábado e Sua Santificação', 'O Sábado, sétimo dia da semana, foi criado e santificado por Deus na criação como um memorial de Sua criação e repouso. O quarto mandamento exige a observância do Sábado como dia de descanso e comunhão com Deus. O Sábado é o selo de Deus e revela o reconhecimento de Sua autoridade como Criador.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Qual é o dia chamado ''dia do Senhor'' segundo a Bíblia?","opcoes":[{"id":"a","texto":"O domingo, primeiro dia da semana"},{"id":"b","texto":"Somente o sétimo dia da semana (Sábado)"},{"id":"c","texto":"Qualquer dia pode ser o dia do Senhor"},{"id":"d","texto":"O sexto dia da semana (Sexta-feira)"}],"resposta_correta":"b","explicacao":"O Sábado, sétimo dia da semana, é o único dia designado nas Escrituras como ''dia do Senhor''. Foi criado e santificado por Deus na criação. O domingo não tem fundamento bíblico como dia sagrado.","referencias":[{"texto":"Êxodo 20:8-11","livro":"Êxodo","capitulo":20,"versiculo":"8-11","conteudo":"Lembra-te do dia de sábado, para o santificar... porque em seis dias fez o Senhor os céus e a terra, o mar e tudo que neles há, e ao sétimo dia descansou; por isso o Senhor abençoou o dia de sábado, e o santificou."},{"texto":"Marcos 2:27-28","livro":"Marcos","capitulo":2,"versiculo":"27-28","conteudo":"E disse-lhes: O sábado foi feito por causa do homem, e não o homem por causa do sábado; por isso o Filho do homem é Senhor até do sábado."}]},{"id":"q2","numero":2,"texto":"O que o quarto mandamento proíbe no Sábado?","opcoes":[{"id":"a","texto":"Apenas o trabalho manual e braçal"},{"id":"b","texto":"Atividades profissionais e trabalhos que não contribuem para a santificação do dia"},{"id":"c","texto":"Somente atividades comerciais e de compra e venda"},{"id":"d","texto":"Nada em específico, apenas recomenda descanso"}],"resposta_correta":"b","explicacao":"O quarto mandamento proíbe atividades que não contribuem para a santificação do Sábado. Não se trata apenas de evitar trabalho braçal, mas de abster-se de atividades profissionais, comerciais e mondanas que desviam da comunhão com Deus.","referencias":[{"texto":"Êxodo 20:8-11","livro":"Êxodo","capitulo":20,"versiculo":"8-11","conteudo":"Lembra-te do dia de sábado, para o santificar... porque em seis dias fez o Senhor os céus e a terra, o mar e tudo que neles há, e ao sétimo dia descansou; por isso o Senhor abençoou o dia de sábado, e o santificou."}]},{"id":"q3","numero":3,"texto":"Qual é o fim da santificação do Sábado?","opcoes":[{"id":"a","texto":"Observar regras e proibições detalhadas"},{"id":"b","texto":"A celebração de uma festa de regozijo do Pai com os Seus filhos"},{"id":"c","texto":"Demonstrar obediência mecânica à Lei"},{"id":"d","texto":"Separar-se completamente de todas as pessoas"}],"resposta_correta":"b","explicacao":"O propósito da santificação do Sábado é celebrar uma festa de regozijo com Deus. Não é mero cumprimento de regras, mas comunhão alegre entre o Pai e Seus filhos, revelando o amor e a ternura divinos.","referencias":[{"texto":"Gênesis 2:2-3","livro":"Gênesis","capitulo":2,"versiculo":"2-3","conteudo":"E, havendo Deus acabado no sétimo dia a obra que fizera, descansou nele de toda a obra que tinha feito. E Deus abençoou o sétimo dia, e o santificou..."},{"texto":"Mateus 12:10-12","livro":"Mateus","capitulo":12,"versiculo":"10-12","conteudo":"...e eis que havia ali um homem que tinha uma mão seca. E perguntaram-lhe para o acusarem: É lícito curar no sábado? Respondeu-lhes: Qual será entre vós o homem que tem uma ovelha, e se ela cair numa cova no sábado, não a levantará?"}]},{"id":"q4","numero":4,"texto":"A guarda do Sábado (selo de Deus) é o reconhecimento de quê?","opcoes":[{"id":"a","texto":"Da tradição judaica preservada pela Igreja"},{"id":"b","texto":"Da autoridade do Criador"},{"id":"c","texto":"Da autoridade da Igreja sobre os fiéis"},{"id":"d","texto":"Do poder dos pastores e líderes religiosos"}],"resposta_correta":"b","explicacao":"O Sábado é o selo de Deus que marca o reconhecimento de Sua autoridade como Criador. Guardar o Sábado é afirmar que aceitamos a autoridade soberana de Deus e rejeitamos toda autoridade que busque usurpar Seu lugar.","referencias":[{"texto":"Apocalipse 7:1-3","livro":"Apocalipse","capitulo":7,"versiculo":"1-3","conteudo":"Depois disto vi quatro anjos em pé nos quatro cantos da terra, retendo os quatro ventos da terra... E ouvi o número dos selados: cento e quarenta e quatro mil..."},{"texto":"Apocalipse 13:16-18","livro":"Apocalipse","capitulo":13,"versiculo":"16-18","conteudo":"E faz que a todos, pequenos e grandes, ricos e pobres, livres e servos, lhes seja posto um sinal na mão direita, ou na testa... e ninguém pode comprar ou vender, senão aquele que tiver o sinal ou o nome da besta..."}]},{"id":"q5","numero":5,"texto":"Segundo a profecia de Daniel, quem se atreveu a mudar a Lei de Deus e os tempos?","opcoes":[{"id":"a","texto":"Os imperadores romanos pagãos"},{"id":"b","texto":"O poder anticristão do papismo"},{"id":"c","texto":"Os reformadores protestantes"},{"id":"d","texto":"Os fariseus e saduceus de Israel"}],"resposta_correta":"b","explicacao":"Daniel 7:25 profetiza que o poder anticristão do papismo se atreveria a mudar a Lei de Deus e os tempos (alterando o dia de repouso do Sábado para o domingo). Esta é uma característica distintiva do sistema religioso papal.","referencias":[{"texto":"Daniel 7:25","livro":"Daniel","capitulo":7,"versiculo":"25","conteudo":"E proferirá palavras contra o Altíssimo, e desgastará os santos do Altíssimo, e cuidará em mudar os tempos e a lei; e eles lhe serão entregues nas mãos por um tempo, dois tempos, e metade de um tempo."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o Sábado é sagrado como dia especial da semana instituído por Deus."},{"id":"cf2","texto":"Reconheço o Sábado como dia de descanso e celebração com a família de Deus."},{"id":"cf3","texto":"Desejo guardar o Sábado em espírito e em verdade, rejeitando o domingo."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 7, 'A Lei Cerimonial', 'Os Sacrifícios e Cerimônias do Velho Testamento', 'A Lei Cerimonial era composta de preceitos relacionados a sacrifícios e cerimônias levíticas no serviço do templo. Era sombra e símbolo da obra de salvação de Cristo. Com a morte de Cristo na cruz, a Lei Cerimonial cumpriu seu propósito e deixou de vigorar para a Igreja do Novo Testamento.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"A Igreja do Novo Testamento está dispensada de que lei?","opcoes":[{"id":"a","texto":"Da Lei Moral dos Dez Mandamentos"},{"id":"b","texto":"Da Lei Cerimonial, Mosaica"},{"id":"c","texto":"De todas as leis bíblicas sem exceção"},{"id":"d","texto":"Da lei civil e das leis de saúde"}],"resposta_correta":"b","explicacao":"A Igreja do Novo Testamento está dispensada apenas da Lei Cerimonial, que era sombra e tipo de Cristo. A Lei Moral (Dez Mandamentos) permanece eterna e obrigatória. Cristo cumpriu os sacrifícios cerimoniais, tornando-os desnecessários.","referencias":[{"texto":"Hebreus 10:1","livro":"Hebreus","capitulo":10,"versiculo":"1","conteudo":"Porque a lei, tendo a sombra dos bens futuros, e não a imagem exata das coisas, nunca pode, pelos mesmos sacrifícios que continuamente se oferecem cada ano, aperfeiçoar os que se chegam."},{"texto":"Colossenses 2:17","livro":"Colossenses","capitulo":2,"versiculo":"17","conteudo":"Que são sombras das coisas futuras; mas o corpo é de Cristo."}]},{"id":"q2","numero":2,"texto":"O que a Lei Cerimonial continha?","opcoes":[{"id":"a","texto":"Os Dez Mandamentos escritos em pedra"},{"id":"b","texto":"Preceitos relacionados com sacrifícios e cerimônias levíticas no serviço do templo"},{"id":"c","texto":"Apenas regras alimentares e de higiene"},{"id":"d","texto":"Instruções para o governo civil de Israel"}],"resposta_correta":"b","explicacao":"A Lei Cerimonial era um sistema complexo de preceitos que incluía sacrifícios de animais, cerimônias levíticas, festas anuais, e serviços no templo. Seu propósito era prefigurar e apontar para Cristo.","referencias":[{"texto":"Hebreus 10:1","livro":"Hebreus","capitulo":10,"versiculo":"1","conteudo":"Porque a lei, tendo a sombra dos bens futuros, e não a imagem exata das coisas, nunca pode, pelos mesmos sacrifícios que continuamente se oferecem cada ano, aperfeiçoar os que se chegam."},{"texto":"Colossenses 2:17","livro":"Colossenses","capitulo":2,"versiculo":"17","conteudo":"Que são sombras das coisas futuras; mas o corpo é de Cristo."}]},{"id":"q3","numero":3,"texto":"O que as leis cerimoniais representavam?","opcoes":[{"id":"a","texto":"Leis permanentes para todas as gerações"},{"id":"b","texto":"Uma sombra e símbolo das coisas futuras — a obra de salvação de Cristo"},{"id":"c","texto":"Tradições humanas acrescentadas à Lei de Deus"},{"id":"d","texto":"Regras sociais para a convivência do povo de Israel"}],"resposta_correta":"b","explicacao":"A Lei Cerimonial era profética e tipológica. Cada sacrifício, cada cerimônia e cada festa apontava para a morte redentora de Cristo. Eram sombras das realidades futuras que se cumpriram em Jesus.","referencias":[{"texto":"Colossenses 2:17","livro":"Colossenses","capitulo":2,"versiculo":"17","conteudo":"Que são sombras das coisas futuras; mas o corpo é de Cristo."}]},{"id":"q4","numero":4,"texto":"Quando a Lei Cerimonial deixou de vigorar?","opcoes":[{"id":"a","texto":"Na destruição do templo de Jerusalém em 70 d.C."},{"id":"b","texto":"No momento em que Cristo foi pregado na cruz como verdadeiro Cordeiro"},{"id":"c","texto":"Quando os apóstolos se reuniram no concílio de Jerusalém"},{"id":"d","texto":"Quando o Evangelho começou a ser pregado aos gentios"}],"resposta_correta":"b","explicacao":"A Lei Cerimonial perdeu sua validade quando Cristo foi crucificado. Ele era o verdadeiro Cordeiro que todos os sacrifícios apontavam. Com Sua morte, o tipo se cumpriu na realidade, tornando os sacrifícios desnecessários.","referencias":[{"texto":"Hebreus 10:1","livro":"Hebreus","capitulo":10,"versiculo":"1","conteudo":"Porque a lei, tendo a sombra dos bens futuros, e não a imagem exata das coisas, nunca pode, pelos mesmos sacrifícios que continuamente se oferecem cada ano, aperfeiçoar os que se chegam."},{"texto":"Colossenses 2:17","livro":"Colossenses","capitulo":2,"versiculo":"17","conteudo":"Que são sombras das coisas futuras; mas o corpo é de Cristo."}]},{"id":"q5","numero":5,"texto":"Qual era a função da Lei Cerimonial em relação ao plano de salvação?","opcoes":[{"id":"a","texto":"Substituir a fé pela obediência ritual"},{"id":"b","texto":"Ilustrar a obra de salvação de Cristo no serviço do templo"},{"id":"c","texto":"Manter o povo de Israel separado dos outros povos"},{"id":"d","texto":"Ensinar princípios de saúde e alimentação"}],"resposta_correta":"b","explicacao":"A Lei Cerimonial tinha como função central ilustrar e prefigurar a morte e salvação de Cristo. Cada elemento do serviço do templo revelava algum aspecto da obra redentora de Jesus no calvário.","referencias":[{"texto":"Hebreus 10:1","livro":"Hebreus","capitulo":10,"versiculo":"1","conteudo":"Porque a lei, tendo a sombra dos bens futuros, e não a imagem exata das coisas, nunca pode, pelos mesmos sacrifícios que continuamente se oferecem cada ano, aperfeiçoar os que se chegam."},{"texto":"Colossenses 2:17","livro":"Colossenses","capitulo":2,"versiculo":"17","conteudo":"Que são sombras das coisas futuras; mas o corpo é de Cristo."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que os sacrifícios cerimoniais apontavam para Cristo, o Cordeiro de Deus."},{"id":"cf2","texto":"Reconheço que Cristo cumpriu e encerrou o sistema cerimonial."},{"id":"cf3","texto":"Desejo compreender como os tipos do Velho Testamento revelam Jesus no Novo Testamento."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 8, 'Os Sábados Cerimoniais', 'As Festas Anuais Distintas do Sábado Semanal', 'Os sábados cerimoniais eram festas anuais que tinham significado simbólico no plano da salvação. O Sábado semanal do sétimo dia é completamente diferente, sendo instituído na criação e não como parte do sistema de sombras. Apenas o Sábado semanal permanece obrigatório para os cristãos do Novo Testamento.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Os dias de festas, luas novas e outros sábados cerimoniais eram o quê?","opcoes":[{"id":"a","texto":"Parte integral da Lei Moral dos Dez Mandamentos"},{"id":"b","texto":"Somente uma sombra, que não devem ser confundidos com o Sábado semanal"},{"id":"c","texto":"Dias tão sagrados quanto o Sábado do sétimo dia"},{"id":"d","texto":"Celebrações criadas pelos sacerdotes de Israel"}],"resposta_correta":"b","explicacao":"Os sábados cerimoniais (festas anuais) eram tipos e sombras do plano de salvação de Cristo. Não devem ser confundidos com o Sábado semanal do sétimo dia, que é parte da Lei Moral e permanente.","referencias":[{"texto":"Colossenses 2:16","livro":"Colossenses","capitulo":2,"versiculo":"16","conteudo":"Portanto, ninguém vos julgue pela comida, ou pela bebida, ou por causa dos dias de festa, ou da lua nova, ou dos sábados."},{"texto":"Gálatas 4:10","livro":"Gálatas","capitulo":4,"versiculo":"10","conteudo":"Guardais dias, e meses, e tempos, e anos. Recebo me medo de vós, não vos haja eu trabalhado em vão."},{"texto":"Romanos 14:5","livro":"Romanos","capitulo":14,"versiculo":"5","conteudo":"Um faz diferença entre dia e dia; outro julga iguais todos os dias. Cada um esteja plenamente seguro em sua própria mente."}]},{"id":"q2","numero":2,"texto":"O Sábado semanal do sétimo dia tem relação com o plano de salvação?","opcoes":[{"id":"a","texto":"Sim, é um símbolo da redenção como os sábados anuais"},{"id":"b","texto":"Não, ele foi instituído na criação e não tem significação simbólica com relação ao plano de salvação"},{"id":"c","texto":"Sim, foi criado como parte da Lei Cerimonial"},{"id":"d","texto":"Não tem nenhuma relação com a criação nem com a salvação"}],"resposta_correta":"b","explicacao":"O Sábado semanal foi criado no princípio, não como tipo ou sombra, mas como memorial da criação e repouso de Deus. Ao contrário dos sábados cerimoniais, não representa o plano de salvação, mas a obra criadora de Deus.","referencias":[{"texto":"Colossenses 2:16","livro":"Colossenses","capitulo":2,"versiculo":"16","conteudo":"Portanto, ninguém vos julgue pela comida, ou pela bebida, ou por causa dos dias de festa, ou da lua nova, ou dos sábados."}]},{"id":"q3","numero":3,"texto":"Quantos sábados cerimoniais a lei cerimonial continha?","opcoes":[{"id":"a","texto":"Três sábados anuais"},{"id":"b","texto":"Sete sábados cerimoniais, que eram sombras"},{"id":"c","texto":"Doze sábados, um para cada mês"},{"id":"d","texto":"Apenas um sábado cerimonial por ano"}],"resposta_correta":"b","explicacao":"A Lei Cerimonial continha sete sábados cerimoniais principais, que juntos formavam um sistema tipológico. Cada um tinha significado profético relacionado com diferentes aspectos da salvação em Cristo.","referencias":[{"texto":"Êxodo 12:15-16","livro":"Êxodo","capitulo":12,"versiculo":"15-16","conteudo":"Sete dias comereis pão sem fermento... no primeiro dia haverá santa convocação, e no sétimo dia também haverá santa convocação..."},{"texto":"Levítico 23:6-7","livro":"Levítico","capitulo":23,"versiculo":"6-7","conteudo":"E no décimo quinto dia deste mês será festa das oferendas azimadas do Senhor; sete dias comereis pão sem fermento... no primeiro dia tereis uma santa convocação..."}]},{"id":"q4","numero":4,"texto":"Se Jesus tivesse derrogado o Sábado semanal, que declaração Sua estaria em contradição?","opcoes":[{"id":"a","texto":"''Eu e o Pai somos um''"},{"id":"b","texto":"''Não vim a derrogar, mas a cumprir''"},{"id":"c","texto":"''Ide por todo o mundo e pregai o Evangelho''"},{"id":"d","texto":"''O meu reino não é deste mundo''"}],"resposta_correta":"b","explicacao":"Jesus afirmou claramente que não veio derrogar a Lei, mas a cumprir. Se Ele tivesse abolido o Sábado, estaria derrogando a Lei de Deus, contradizendo Sua própria declaração e contradizendo a obra de Deus na criação.","referencias":[{"texto":"Mateus 5:17","livro":"Mateus","capitulo":5,"versiculo":"17","conteudo":"Não penseis que vim revogar a lei ou os profetas; não vim revogar, mas cumprir."}]},{"id":"q5","numero":5,"texto":"O que santifica o Sábado semanal e o diferencia dos sábados cerimoniais?","opcoes":[{"id":"a","texto":"A tradição religiosa e os costumes judaicos"},{"id":"b","texto":"Ele é o dia do Senhor na Lei Moral, instituído na criação e não como parte do sistema de sombras"},{"id":"c","texto":"A decisão dos apóstolos no concílio de Jerusalém"},{"id":"d","texto":"O fato de cair sempre no mesmo dia da semana"}],"resposta_correta":"b","explicacao":"O Sábado semanal é sagrado porque foi criado e santificado por Deus na criação. Não é uma sombra ou tipo, mas um memorial permanente da criação e da autoridade de Deus. Os sábados cerimoniais, ao contrário, eram meramente típicos e cerimoniais.","referencias":[{"texto":"Colossenses 2:16","livro":"Colossenses","capitulo":2,"versiculo":"16","conteudo":"Portanto, ninguém vos julgue pela comida, ou pela bebida, ou por causa dos dias de festa, ou da lua nova, ou dos sábados."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o Sábado semanal é distinto dos sábados cerimoniais."},{"id":"cf2","texto":"Reconheço que só o Sábado do sétimo dia é obrigatório para os cristãos."},{"id":"cf3","texto":"Desejo compreender a diferença entre a Lei Moral e a Lei Cerimonial."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 9, 'A Graça e Seus Meios', 'Como Recebermos a Salvação em Cristo', 'A graça é a cobertura de nossos pecados por meio de Cristo. A graça salvadora é um presente de Deus, não merecido nem alcançado por nossas obras. Os meios pelos quais Deus provê a graça incluem a Palavra de Deus, a Igreja de Deus, o Lava-pés e a Santa Ceia. Somente mediante a fé unida ao esforço conseguimos os benefícios da graça.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que significa a graça segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"A permissão divina para continuar no pecado"},{"id":"b","texto":"A cobertura de nossos pecados por meio de Cristo"},{"id":"c","texto":"O mérito humano acumulado por boas obras"},{"id":"d","texto":"Uma recompensa pelo cumprimento perfeito da Lei"}],"resposta_correta":"b","explicacao":"A graça é o amor e misericórdia de Deus manifestados na cobertura de nossos pecados por meio da morte de Cristo. Não é permissão para pecar, nem mérito humano, mas o favor imerecido de Deus.","referencias":[{"texto":"João 1:17","livro":"João","capitulo":1,"versiculo":"17","conteudo":"Porque a lei foi dada por Moisés; a graça e a verdade vieram por Jesus Cristo."},{"texto":"Hebreus 4:16","livro":"Hebreus","capitulo":4,"versiculo":"16","conteudo":"Cheguemos, pois, com confiança ao trono da graça, para que recebamos misericórdia e achemos graça, a fim de sermos ajudados em tempo oportuno."}]},{"id":"q2","numero":2,"texto":"Somente podemos ser beneficiados pela graça salvadora quando fazemos o quê?","opcoes":[{"id":"a","texto":"Quando cumprimos todos os rituais da Igreja"},{"id":"b","texto":"Se evitarmos o pecado pelo poder de Cristo unido à nossa vontade"},{"id":"c","texto":"Quando fazemos doações generosas à obra de Deus"},{"id":"d","texto":"Se frequentamos a Igreja todos os dias"}],"resposta_correta":"b","explicacao":"A graça opera quando respondemos com fé e esforço pessoal. O poder de Cristo, unido à nossa vontade e determinação, nos capacita a vencer o pecado e experimentar verdadeiramente a salvação.","referencias":[{"texto":"João 14:5","livro":"João","capitulo":14,"versiculo":"5","conteudo":"Respondeu-lhe Tomé: Senhor, não sabemos para onde vais, como podemos saber o caminho?"},{"texto":"Atos 2:38","livro":"Atos","capitulo":2,"versiculo":"38","conteudo":"Pedro disse-lhes: Arrependei-vos, e cada um de vós seja batizado em nome de Jesus Cristo para remissão dos vossos pecados; e recebereis o dom do Espírito Santo."}]},{"id":"q3","numero":3,"texto":"Quando foi estabelecido o reino da graça?","opcoes":[{"id":"a","texto":"Somente quando Jesus veio ao mundo em Belém"},{"id":"b","texto":"Logo após a queda, sendo introduzido o perdão por meio de Cristo, e estabelecido com plenitude na morte de Cristo"},{"id":"c","texto":"Na criação do mundo, antes da queda de Adão"},{"id":"d","texto":"Somente após a ascensão de Cristo ao Céu"}],"resposta_correta":"b","explicacao":"A graça foi estabelecida logo após a queda de Adão, quando Deus prometeu a redenção por meio de Cristo (Gênesis 3:15). Esta promessa foi plenamente cumprida e manifestada na morte de Cristo no Calvário.","referencias":[{"texto":"Gênesis 3:15","livro":"Gênesis","capitulo":3,"versiculo":"15","conteudo":"E porei inimizade entre ti e a mulher, e entre a tua descendência e a sua descendência; esta te ferirá a cabeça, e tu lhe ferirás o calcanhar."},{"texto":"Colossenses 1:15-20","livro":"Colossenses","capitulo":1,"versiculo":"15-20","conteudo":"Ele é a imagem do Deus invisível, o primogênito de toda a criação... e, tendo feito paz pelo sangue da sua cruz..."}]},{"id":"q4","numero":4,"texto":"Quais são os meios que Deus proveu para atrair os pecadores e dar-lhes a salvação?","opcoes":[{"id":"a","texto":"Somente a oração e o jejum"},{"id":"b","texto":"A Palavra de Deus, a Igreja de Deus, o Lava-pés e a Santa Ceia"},{"id":"c","texto":"Os sacramentos administrados pelos sacerdotes"},{"id":"d","texto":"A meditação e o estudo filosófico"}],"resposta_correta":"b","explicacao":"Deus estabeleceu meios concretos para transmitir Sua graça: a Palavra inspirada, a comunidade de fé, e as ordenanças simbólicas (Lava-pés e Santa Ceia). Estes são os canais pelos quais a graça opera na vida dos crentes.","referencias":[{"texto":"Efésios 2:8","livro":"Efésios","capitulo":2,"versiculo":"8","conteudo":"Porque pela graça sois salvos, mediante a fé; e isto não vem de vós, é dom de Deus."},{"texto":"Romanos 10:13-17","livro":"Romanos","capitulo":10,"versiculo":"13-17","conteudo":"Porque: Todo aquele que invocar o nome do Senhor será salvo. Como, pois, invocarão aquele em quem não creram? E como crerão naquele de quem não ouviram falar?"},{"texto":"Marcos 16:15","livro":"Marcos","capitulo":16,"versiculo":"15","conteudo":"E disse-lhes: Ide por todo o mundo, pregai o evangelho a toda criatura."}]},{"id":"q5","numero":5,"texto":"Pela graça somos o quê, segundo João 8:31-32?","opcoes":[{"id":"a","texto":"Escravos obrigados a obedecer"},{"id":"b","texto":"Livres"},{"id":"c","texto":"Merecedores do perdão por nossos méritos"},{"id":"d","texto":"Isentos de toda responsabilidade moral"}],"resposta_correta":"b","explicacao":"A graça nos liberta. Quando continuamos nas palavras de Jesus, conhecemos a verdade e somos libertos pela verdade. Esta liberdade não é licença para pecar, mas liberdade da escravidão do pecado para servir a Deus livremente.","referencias":[{"texto":"João 8:31-32","livro":"João","capitulo":8,"versiculo":"31-32","conteudo":"Disse Jesus aos judeus que nele tinham crido: Se vós permanecerdes na minha palavra, verdadeiramente sereis meus discípulos; e conhecereis a verdade, e a verdade vos libertará."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a graça é o dom gratuito de Deus mediante Cristo."},{"id":"cf2","texto":"Reconheço que a fé me capacita a receber e experimentar a graça de Deus."},{"id":"cf3","texto":"Desejo viver uma vida de gratidão pela graça salvadora recebida."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 10, 'Arrependimento, Obediência e Renascimento', 'A Transformação que Vem da Palavra de Deus', 'O arrependimento ou contrição pelos pecados opera-se por meio da Palavra e do Espírito de Deus. A sujeição ou obediência é fruto da conversão e o arrependimento é fruto da fé. O renascimento significa nascer de novo do Espírito, sendo guiados por Ele como uma nova criatura. Aquele que não se sujeita completamente à Palavra prova que não é perfeitamente convertido.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O arrependimento, ou contrição por causa dos pecados, opera-se por meio de quê?","opcoes":[{"id":"a","texto":"Do esforço humano e da disciplina pessoal"},{"id":"b","texto":"Da Palavra e do Espírito de Deus"},{"id":"c","texto":"De sentimentos de culpa e remorso naturais"},{"id":"d","texto":"Da influência dos líderes religiosos"}],"resposta_correta":"b","explicacao":"O arrependimento genuíno não vem de emoção humana ou esforço pessoal, mas da Palavra de Deus que convence do pecado e do Espírito Santo que regenera. Ambos trabalham juntos para produzir verdadeira contrição e transformação.","referencias":[{"texto":"Hebreus 4:12","livro":"Hebreus","capitulo":4,"versiculo":"12","conteudo":"Porque a palavra de Deus é viva, e eficaz, e mais penetrante do que qualquer espada de dois gumes, e penetra até à divisão de alma e espírito, e de juntas e tutanos, e é apta para discernir os pensamentos e intenções do coração."},{"texto":"Romanos 1:10-17","livro":"Romanos","capitulo":1,"versiculo":"10-17","conteudo":"Pois a justiça de Deus se revela nele, de fé em fé, como está escrito: O justo viverá de fé."}]},{"id":"q2","numero":2,"texto":"A sujeição (obediência) é um fruto de quê?","opcoes":[{"id":"a","texto":"Do medo do castigo divino"},{"id":"b","texto":"Da conversão, e o arrependimento é o fruto da fé"},{"id":"c","texto":"Da tradição religiosa familiar"},{"id":"d","texto":"Do desejo de agradar os líderes da Igreja"}],"resposta_correta":"b","explicacao":"A obediência genuína brota da conversão do coração. O arrependimento, por sua vez, é fruto da fé em Deus e Sua Palavra. Esta é uma sequência espiritual: fé produz arrependimento, e arrependimento produz obediência voluntária.","referencias":[{"texto":"Tiago 2:16","livro":"Tiago","capitulo":2,"versiculo":"16","conteudo":"Assim também a fé, se não tiver obras, é morta em si mesma."},{"texto":"Romanos 10:17","livro":"Romanos","capitulo":10,"versiculo":"17","conteudo":"Logo a fé é pelo ouvir, e o ouvir pela palavra de Deus."}]},{"id":"q3","numero":3,"texto":"O que significa o renascimento ou nascer de novo?","opcoes":[{"id":"a","texto":"Iniciar uma nova vida em outra denominação religiosa"},{"id":"b","texto":"Nascermos de novo do Espírito, sendo guiados pelo mesmo como uma nova criatura"},{"id":"c","texto":"Ser batizado por imersão na água"},{"id":"d","texto":"Mudar de comportamento por esforço próprio"}],"resposta_correta":"b","explicacao":"O renascimento é uma experiência espiritual genuína em que o Espírito Santo transforma o ser humano, tornando-o uma nova criatura em Cristo. Não é mudança de religião ou esforço próprio, mas renovação interior pelo Espírito.","referencias":[{"texto":"João 3:3","livro":"João","capitulo":3,"versiculo":"3","conteudo":"Jesus respondeu: Na verdade, na verdade te digo que se alguém não nascer de novo, não pode ver o reino de Deus."},{"texto":"2 Coríntios 5:17","livro":"2 Coríntios","capitulo":5,"versiculo":"17","conteudo":"Assim que, se alguém está em Cristo, é nova criatura; as coisas velhas já passaram; eis que tudo se fez novo."}]},{"id":"q4","numero":4,"texto":"Aquele que não se sujeita completamente à Palavra de Deus prova o quê?","opcoes":[{"id":"a","texto":"Que está em processo de aprendizado espiritual"},{"id":"b","texto":"Que não é perfeitamente convertido, pois ainda tem ligação com o pecado"},{"id":"c","texto":"Que precisa de mais estudo e tempo"},{"id":"d","texto":"Que tem uma fé madura e independente"}],"resposta_correta":"b","explicacao":"A falta de submissão completa à Palavra de Deus indica que a conversão não foi verdadeira ou não foi completa. Uma criatura verdadeiramente renascida submente-se inteiramente a Deus, pois o Espírito a guia.","referencias":[{"texto":"Mateus 5:19","livro":"Mateus","capitulo":5,"versiculo":"19","conteudo":"Aquele pois que revogar um destes mandamentos, por menor que seja, e assim ensinar aos homens, será chamado o menor no reino dos céus..."},{"texto":"Tiago 2:10","livro":"Tiago","capitulo":2,"versiculo":"10","conteudo":"Pois qualquer que guardar toda a lei, mas tropeçar em um só ponto, tem-se tornado culpado de tudo."}]},{"id":"q5","numero":5,"texto":"Enquanto o homem não é renascido do Espírito, o que ele não pode fazer?","opcoes":[{"id":"a","texto":"Frequentar a Igreja e participar dos cultos"},{"id":"b","texto":"Participar da vida em Cristo"},{"id":"c","texto":"Ler e compreender a Bíblia"},{"id":"d","texto":"Fazer orações e buscar a Deus"}],"resposta_correta":"b","explicacao":"Sem o renascimento espiritual, o ser humano não pode participar verdadeiramente da vida eterna em Cristo. A vida espiritual genuína é impossível sem a transformação operada pelo Espírito Santo na conversão.","referencias":[{"texto":"João 7:38-39","livro":"João","capitulo":7,"versiculo":"38-39","conteudo":"Quem crê em mim, como diz a Escritura, do seu interior manarão rios de água viva. Mas isto disse ele do Espírito que haviam de receber os que nele cressem..."},{"texto":"Romanos 8:9-13","livro":"Romanos","capitulo":8,"versiculo":"9-13","conteudo":"Vós, porém, não estais na carne, mas no Espírito, se é que o Espírito de Deus habita em vós. Mas se alguém não tem o Espírito de Cristo, esse tal não é dele."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o arrependimento verdadeiro leva à transformação de vida."},{"id":"cf2","texto":"Reconheço a necessidade do renascimento espiritual mediante o Espírito Santo."},{"id":"cf3","texto":"Desejo viver em completa submissão à Palavra e vontade de Deus."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 11, 'Batismo', 'A Imersão na Água como Rito Sagrado', 'O batismo é o rito sagrado pelo qual o crente professa sua fé em Jesus Cristo e demonstra sua conversão. Apenas os que creem em Jesus e se convertem devem ser batizados. O batismo é realizado por imersão, uma única vez, em nome do Pai, do Filho e do Espírito Santo, representando o sepultamento do homem velho e a ressurreição para uma vida nova em Cristo.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Segundo a Escritura Sagrada, quando o crente deve ser batizado?","opcoes":[{"id":"a","texto":"Ao nascer, como tradição familiar"},{"id":"b","texto":"Enquanto a graça de Cristo estiver na Terra"},{"id":"c","texto":"Somente após completar um curso teológico formal"},{"id":"d","texto":"Após atingir a idade de 21 anos"}],"resposta_correta":"b","explicacao":"A Bíblia ensina que o batismo deve ser recebido quando a pessoa crê em Jesus Cristo e se converte, não em uma idade específica ou por tradição. A pregação do evangelho e o batismo de crentes é o padrão neotestamentário.","referencias":[{"texto":"Mt 28:19-20","livro":"Mt","capitulo":28,"versiculo":"19-20","conteudo":"Portanto, ide, ensinai todos os povos, batizando-os em nome do Pai, e do Filho, e do Espírito Santo;"},{"texto":"Mc 16:15-16","livro":"Mc","capitulo":16,"versiculo":"15-16","conteudo":"E disse-lhes: Ide por todo o mundo, pregai o evangelho a toda criatura."}]},{"id":"q2","numero":2,"texto":"Quem pode receber o batismo segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Todas as pessoas, incluindo crianças de qualquer idade"},{"id":"b","texto":"Somente as almas que creem em Jesus Cristo como Salvador pessoal e se convertem de tudo que a Palavra condena"},{"id":"c","texto":"Apenas os que nasceram em famílias cristãs"},{"id":"d","texto":"Somente adultos acima de 30 anos, como Jesus"}],"resposta_correta":"b","explicacao":"O batismo é exclusivo para os que creem genuinamente em Jesus e se convertem. Não é baseado na idade ou em herança familiar, mas em fé pessoal e conversão.","referencias":[{"texto":"Mt 28:19-20","livro":"Mt","capitulo":28,"versiculo":"19-20","conteudo":"Portanto, ide, ensinai todos os povos, batizando-os em nome do Pai, e do Filho, e do Espírito Santo;"},{"texto":"At 2:37-38","livro":"At","capitulo":2,"versiculo":"37-38","conteudo":"Ouvindo eles isto, compungiram-se em seu coração, e perguntaram a Pedro e aos demais apóstolos: Varões irmãos, que faremos?"}]},{"id":"q3","numero":3,"texto":"Como é realizado o ato batismal?","opcoes":[{"id":"a","texto":"Por aspersão de água sobre a cabeça"},{"id":"b","texto":"Por imersão na água, uma só vez, em nome do Pai, do Filho e do Espírito Santo"},{"id":"c","texto":"Por derramamento de água três vezes"},{"id":"d","texto":"Por qualquer método, pois a forma não importa"}],"resposta_correta":"b","explicacao":"A forma correta do batismo é por imersão total na água, simbolizando a morte, sepultamento e ressurreição com Cristo. Isto é feito em nome da Trindade.","referencias":[{"texto":"Rm 6:2-5","livro":"Rm","capitulo":6,"versiculo":"2-5","conteudo":"De modo que nós, que morremos para o pecado, como viveremos ainda nele?"},{"texto":"Cl 2:12","livro":"Cl","capitulo":2,"versiculo":"12","conteudo":"Sepultados com ele no batismo, nele também ressuscitastes pela fé no poder de Deus, que o ressuscitou dentre os mortos."}]},{"id":"q4","numero":4,"texto":"O que o ato de batismo representa?","opcoes":[{"id":"a","texto":"Apenas um ritual de aceitação social na Igreja"},{"id":"b","texto":"O sepultamento do homem velho e a ressurreição para uma vida nova em Cristo"},{"id":"c","texto":"Um símbolo de purificação física"},{"id":"d","texto":"O início do estudo bíblico"}],"resposta_correta":"b","explicacao":"O batismo é um símbolo sagrado e profundo da morte ao pecado e da ressurreição para viver uma vida nova dedicada a Cristo. Representa a transformação espiritual do crente.","referencias":[{"texto":"Rm 6:2-5","livro":"Rm","capitulo":6,"versiculo":"2-5","conteudo":"De modo que nós, que morremos para o pecado, como viveremos ainda nele?"},{"texto":"Cl 2:12","livro":"Cl","capitulo":2,"versiculo":"12","conteudo":"Sepultados com ele no batismo, nele também ressuscitastes pela fé no poder de Deus, que o ressuscitou dentre os mortos."}]},{"id":"q5","numero":5,"texto":"Em que circunstância o batismo pode ser repetido?","opcoes":[{"id":"a","texto":"A cada ano como renovação de votos"},{"id":"b","texto":"Somente se da primeira vez não foi feito em conformidade com as regras da Bíblia ou se foi ministrado na incredulidade"},{"id":"c","texto":"Sempre que o crente mudar de igreja"},{"id":"d","texto":"Nunca, pois o batismo é irrepetível"}],"resposta_correta":"b","explicacao":"O batismo é fundamentalmente irrepetível quando realizado corretamente em fé verdadeira. Porém, se foi recebido indevidamente ou sem verdadeira conversão, pode ser repetido conforme os princípios bíblicos.","referencias":[{"texto":"At 19:2-6","livro":"At","capitulo":19,"versiculo":"2-6","conteudo":"E disse-lhes: Recebestes vós o Espírito Santo quando crestes? E eles lhe disseram: Nós nem ainda ouvimos que existe Espírito Santo."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o batismo por imersão é o rito ordenado por Cristo."},{"id":"cf2","texto":"Reconheço meu desejo de ser batizado em obediência ao Evangelho."},{"id":"cf3","texto":"Desejo testificar publicamente de minha fé em Jesus Cristo."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 12, 'Santa Ceia', 'A Memória do Sacrifício de Cristo', 'A Santa Ceia é uma cerimônia comemorativa dos sofrimentos e morte de Jesus Christ. O pão asmo simboliza o corpo de Cristo e o vinho não fermentado simboliza Seu sangue. A Santa Ceia não oferece perdão de pecados, mas fortalece a Igreja em humildade, amor e união. Somente os batizados podem participar da Santa Ceia.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que simboliza a participação no pão asmo e no vinho não fermentado na Santa Ceia?","opcoes":[{"id":"a","texto":"A prosperidade material dos membros"},{"id":"b","texto":"A morte de Jesus — uma ceia comemorativa dos sofrimentos e da morte de Jesus"},{"id":"c","texto":"A união política dos membros da Igreja"},{"id":"d","texto":"O nascimento de Jesus em Belém"}],"resposta_correta":"b","explicacao":"A Santa Ceia é um serviço comemorativo que celebra o sacrifício de Cristo na cruz. O pão e o vinho representam Seu corpo quebrantado e Seu sangue derramado pela salvação.","referencias":[{"texto":"1 Coríntios 11:23-24","livro":"1 Coríntios","capitulo":11,"versiculo":"23-24","conteudo":"Porque eu recebi do Senhor o que também vos entreguei: que o Senhor Jesus, na noite em que foi traído, tomou o pão; E, havendo dado graças, o partiu, e disse: Tomai, comei; isto é o meu corpo que é partido por vós; fazei isto em memória de mim."}]},{"id":"q2","numero":2,"texto":"O que o pão simboliza na Santa Ceia?","opcoes":[{"id":"a","texto":"A Palavra de Deus escrita"},{"id":"b","texto":"O corpo de Cristo"},{"id":"c","texto":"A criação do mundo"},{"id":"d","texto":"O pão que caiu do céu no deserto (maná)"}],"resposta_correta":"b","explicacao":"Na Santa Ceia, o pão asmo representa o corpo de Cristo que foi entregue como sacrifício perfeito pela redenção de nossas almas.","referencias":[{"texto":"1 Coríntios 10:16-17","livro":"1 Coríntios","capitulo":10,"versiculo":"16-17","conteudo":"Porventura o cálice de bênção que abençoamos não é a comunhão do sangue de Cristo? O pão que partimos não é porventura a comunhão do corpo de Cristo?"}]},{"id":"q3","numero":3,"texto":"Há perdão de pecados no ato de comer o pão e tomar o vinho?","opcoes":[{"id":"a","texto":"Sim, é um meio de obter o perdão dos pecados"},{"id":"b","texto":"Não, não há perdão de pecados no comer o pão e tomar o vinho — é comemorativa"},{"id":"c","texto":"Depende da fé individual de cada participante"},{"id":"d","texto":"Somente se o pastor abençoar os elementos"}],"resposta_correta":"b","explicacao":"A Santa Ceia é um rito comemorativo, não um meio de salvação. O perdão dos pecados vem unicamente através da fé em Cristo, não pelos elementos da ceia.","referencias":[{"texto":"João 3:16","livro":"João","capitulo":3,"versiculo":"16","conteudo":"Porque Deus amou o mundo de tal maneira que deu o seu Filho unigênito, para que todo aquele que nele crê não pereça, mas tenha a vida eterna."}]},{"id":"q4","numero":4,"texto":"Quem pode participar da Santa Ceia?","opcoes":[{"id":"a","texto":"Qualquer pessoa que esteja presente no culto"},{"id":"b","texto":"Somente os que são batizados"},{"id":"c","texto":"Apenas os líderes e oficiais da Igreja"},{"id":"d","texto":"Crianças e adultos indistintamente"}],"resposta_correta":"b","explicacao":"A Santa Ceia é exclusiva para os que foram batizados, pois o batismo é o requisito para a participação plena nos ritos da Igreja.","referencias":[{"texto":"Mt 28:19-20","livro":"Mt","capitulo":28,"versiculo":"19-20","conteudo":"Portanto, ide, ensinai todos os povos, batizando-os em nome do Pai, e do Filho, e do Espírito Santo;"}]},{"id":"q5","numero":5,"texto":"Para que deve servir a Santa Ceia segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Para demonstrar status social dentro da Igreja"},{"id":"b","texto":"Para fortalecimento da Igreja, devendo mantê-la em humildade, amor e união"},{"id":"c","texto":"Para substituir o batismo como rito principal"},{"id":"d","texto":"Para celebrar aniversários e datas especiais"}],"resposta_correta":"b","explicacao":"A Santa Ceia destina-se ao fortalecimento dos laços de comunhão entre os crentes, promovendo humildade, amor mútuo e união na fé em Cristo.","referencias":[{"texto":"1 Coríntios 11:26","livro":"1 Coríntios","capitulo":11,"versiculo":"26","conteudo":"Porque, todas as vezes que comerdes este pão e beberdes este cálice, anunciais a morte do Senhor até que venha."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a Santa Ceia é um memorial do sacrifício de Cristo."},{"id":"cf2","texto":"Reconheço a importância de participar dignamente desta ordenança sagrada."},{"id":"cf3","texto":"Desejo manter-me fiel aos votos feitos em meu batismo."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 13, 'O Lava-pés', 'A Expressão de Humildade e Serviço Mútuo', 'O Lava-pés é um rito santo instituído por Jesus como expressão de um novo mandamento de humildade. Não é apenas simbólico, mas deve ser executado fisicamente, não apenas em espírito. Todos os cristãos são chamados a obedecer a este rito, e são bem-aventurados os que seguem o exemplo de Jesus no Lava-pés.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O rito do Lava-pés é obrigatório para quem?","opcoes":[{"id":"a","texto":"Somente para os pastores e diáconos"},{"id":"b","texto":"Para todos os cristãos"},{"id":"c","texto":"Apenas para novos convertidos"},{"id":"d","texto":"Somente para os que participam da Santa Ceia pela primeira vez"}],"resposta_correta":"b","explicacao":"Jesus ensinou que o lava-pés é obrigatório para todos os Seus seguidores, não apenas para um grupo especial. Todos devem seguir este mandamento de humildade.","referencias":[{"texto":"Jo 13:14-15,17","livro":"Jo","capitulo":13,"versiculo":"14-15,17","conteudo":"Ora, se eu, sendo Senhor e Mestre, vos lavei os pés, vós deveis também lavar os pés uns aos outros."}]},{"id":"q2","numero":2,"texto":"O que Jesus ensina por meio do Lava-pés?","opcoes":[{"id":"a","texto":"Que os discípulos devem manter a higiene corporal"},{"id":"b","texto":"A humildade — um novo Mandamento, não um costume judaico nem oriental"},{"id":"c","texto":"Que devemos lavar os pés apenas dos líderes"},{"id":"d","texto":"Que é um ritual opcional para os que desejarem"}],"resposta_correta":"b","explicacao":"O lava-pés é um novo mandamento de Jesus que ensina humildade radical: estar disposto a servir uns aos outros, mesmo no que é considerado humilhante pela cultura.","referencias":[{"texto":"Jo 13:1-17","livro":"Jo","capitulo":13,"versiculo":"1-17","conteudo":"Ora, antes da festa da Páscoa, Jesus, sabendo que ia chegar a sua hora de passar deste mundo para o Pai, e tendo amado os seus que estavam no mundo, amou-os até ao fim."}]},{"id":"q3","numero":3,"texto":"O Lava-pés pode ser executado apenas em espírito (simbolicamente)?","opcoes":[{"id":"a","texto":"Sim, basta ter a intenção em espírito"},{"id":"b","texto":"Não — representa um rito santo que não pode ser executado só em espírito, mas em realidade (fisicamente)"},{"id":"c","texto":"Depende da tradição de cada congregação"},{"id":"d","texto":"Sim, se a pessoa estiver impossibilitada fisicamente"}],"resposta_correta":"b","explicacao":"O lava-pés é um rito concreto e físico, não apenas simbólico. Deve ser realizado efetivamente com água e toalha, demonstrando o serviço genuíno.","referencias":[{"texto":"Jo 13:1-17","livro":"Jo","capitulo":13,"versiculo":"1-17","conteudo":"Ora, antes da festa da Páscoa, Jesus, sabendo que ia chegar a sua hora de passar deste mundo para o Pai, e tendo amado os seus que estavam no mundo, amou-os até ao fim."}]},{"id":"q4","numero":4,"texto":"Quem são chamados bem-aventurados segundo João 13:17?","opcoes":[{"id":"a","texto":"Os que estudam teologia profundamente"},{"id":"b","texto":"Todos os que seguem o exemplo de Jesus no lava-pés"},{"id":"c","texto":"Os que dão grandes ofertas à Igreja"},{"id":"d","texto":"Os que ocupam cargos de liderança"}],"resposta_correta":"b","explicacao":"Jesus afirma que a bem-aventurança vem não apenas em conhecer Seus ensinamentos, mas em praticá-los. Quem segue o exemplo do lava-pés é bem-aventurado.","referencias":[{"texto":"Jo 13:17","livro":"Jo","capitulo":13,"versiculo":"17","conteudo":"Se vós sabeis estas coisas, bem-aventurados sois se as fizerdes."}]},{"id":"q5","numero":5,"texto":"Onde originalmente acontecia o lava-pés e por que isso é relevante?","opcoes":[{"id":"a","texto":"No templo, como parte do serviço sacerdotal"},{"id":"b","texto":"Fora da porta da casa — por isso não teria causado admiração, confirmando que é um novo mandamento de humildade"},{"id":"c","texto":"Dentro da sala da ceia, como ritual formal"},{"id":"d","texto":"Nas margens do rio Jordão, como parte do batismo"}],"resposta_correta":"b","explicacao":"O lava-pés acontecia fora da porta, era função de escravos. Jesus elevando isto à condição de mandamento novo mostra que institui um novo padrão de humildade.","referencias":[{"texto":"Jo 13:1-17","livro":"Jo","capitulo":13,"versiculo":"1-17","conteudo":"Ora, antes da festa da Páscoa, Jesus, sabendo que ia chegar a sua hora de passar deste mundo para o Pai, e tendo amado os seus que estavam no mundo, amou-os até ao fim."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o Lava-pés é um mandamento importante de Jesus."},{"id":"cf2","texto":"Reconheço a lição de humildade ensinada pelo Lava-pés."},{"id":"cf3","texto":"Desejo praticar o serviço mútuo e a humildade em relação aos irmãos."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 14, 'As 2.300 Tardes e Manhãs', 'O Período Profético e o Juízo de Investigação', 'O grande período profético de Daniel 8:14 terminou no ano de 1844. A purificação do santuário mencionada em Daniel refere-se ao começo do juízo de investigação no Céu. Antes do término deste período, um despertamento mundial aconteceu visando a preparação para a segunda vinda de Cristo e o anúncio da tríplice mensagem angélica.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Quando terminou o grande período profético de Daniel 8:14?","opcoes":[{"id":"a","texto":"No ano 70 d.C., com a destruição de Jerusalém"},{"id":"b","texto":"No ano de 1844"},{"id":"c","texto":"No ano 1517, com a Reforma Protestante"},{"id":"d","texto":"Ainda não terminou — é futuro"}],"resposta_correta":"b","explicacao":"Segundo a interpretação do período profético de 2.300 tardes e manhãs (dias-anos), este período encerrou em 1844, marcando o início do juízo de investigação no santuário celestial.","referencias":[{"texto":"Dn 8:14","livro":"Dn","capitulo":8,"versiculo":"14","conteudo":"E ele me disse: Até à noite e à manhã dois mil e trezentos dias; e o santuário será purificado."}]},{"id":"q2","numero":2,"texto":"O que significa a ''purificação do santuário'' mencionada em Daniel 8:14?","opcoes":[{"id":"a","texto":"A limpeza física do templo de Jerusalém"},{"id":"b","texto":"O começo do juízo de investigação no Céu"},{"id":"c","texto":"A construção de um novo templo na Terra"},{"id":"d","texto":"A reforma do sistema de sacrifícios"}],"resposta_correta":"b","explicacao":"A purificação do santuário celestial refere-se ao juízo de investigação que começou em 1844, quando Cristo iniciou a revisão dos registros de cada pessoa para a condenação ou justificação final.","referencias":[{"texto":"Dn 8:14","livro":"Dn","capitulo":8,"versiculo":"14","conteudo":"E ele me disse: Até à noite e à manhã dois mil e trezentos dias; e o santuário será purificado."},{"texto":"Ez 4:6","livro":"Ez","capitulo":4,"versiculo":"6","conteudo":"E tu também, tornado-me a dormir, deitado sobre o teu lado direito, levarás sobre ti a iniquidade da casa de Judá quarenta dias; um dia por um ano; um dia por um ano te dei."},{"texto":"Nm 14:34","livro":"Nm","capitulo":14,"versiculo":"34","conteudo":"Segundo o número dos dias em que lhes espiastes a terra, quarenta dias, levarão sobre si as vossas iniquidades quarenta anos; e conhecereis o meu desprazer."}]},{"id":"q3","numero":3,"texto":"Em que ano começou o período das 2.300 tardes e manhãs?","opcoes":[{"id":"a","texto":"No ano 539 a.C."},{"id":"b","texto":"No ano 457 a.C., segundo Esdras 7:11-26"},{"id":"c","texto":"No ano 34 d.C."},{"id":"d","texto":"No ano 31 d.C."}],"resposta_correta":"b","explicacao":"O período profético começou em 457 a.C., ano do decreto de Artaxerxes registrado em Esdras, que autorizava a restauração de Jerusalém. Daí contam-se os 2.300 anos-dia até 1844.","referencias":[{"texto":"Ed 7:11-26","livro":"Ed","capitulo":7,"versiculo":"11-26","conteudo":"Cópia da carta que o rei Artaxerxes deu ao sacerdote Esdras, escriba das palavras dos mandamentos do Senhor, e dos seus estatutos para Israel."},{"texto":"Dn 9:24-27","livro":"Dn","capitulo":9,"versiculo":"24-27","conteudo":"Setenta semanas estão determinadas sobre o teu povo, e sobre a tua santa cidade, para fazer cessar a transgressão, e para dar fim aos pecados, e para expiar a iniquidade, e trazer a justiça eterna, e selar a visão e a profecia, e para ungir o Santíssimo."}]},{"id":"q4","numero":4,"texto":"O que aconteceu antes do término do período das 2.300 tardes e manhãs?","opcoes":[{"id":"a","texto":"A Igreja parou de pregar o Evangelho"},{"id":"b","texto":"Um despertamento mundial visando a preparação para a segunda vinda de Cristo"},{"id":"c","texto":"Todas as igrejas cristãs se uniram em uma só"},{"id":"d","texto":"O templo de Jerusalém foi reconstruído"}],"resposta_correta":"b","explicacao":"Antes de 1844, Deus preparou um grande despertamento religioso para chamar Seu povo a se preparar para os últimos eventos da história. Este foi o cenário para o surgimento da mensagem adventista.","referencias":[{"texto":"Ap 14:6-8","livro":"Ap","capitulo":14,"versiculo":"6-8","conteudo":"E vi outro anjo voando pelo meio do céu, e tinha o evangelho eterno para pregar aos que habitam sobre a terra, e a toda nação, e tribo, e língua, e povo,"}]},{"id":"q5","numero":5,"texto":"No fim do período das 2.300 tardes e manhãs, onde Cristo entrou?","opcoes":[{"id":"a","texto":"No templo terrestre de Jerusalém reconstruído"},{"id":"b","texto":"No lugar santíssimo do santuário celestial como Sumo Sacerdote"},{"id":"c","texto":"No jardim do Éden restaurado"},{"id":"d","texto":"Na sala do trono para Sua coroação final"}],"resposta_correta":"b","explicacao":"Em 1844, Cristo iniciou Seu ministério no lugar santíssimo do santuário celestial, realizando o juízo de investigação pelos seus nomes registrados no livro da vida.","referencias":[{"texto":"Dn 8:14","livro":"Dn","capitulo":8,"versiculo":"14","conteudo":"E ele me disse: Até à noite e à manhã dois mil e trezentos dias; e o santuário será purificado."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o ano 1844 marca o início do juízo de investigação."},{"id":"cf2","texto":"Reconheço que estamos vivendo no tempo do fim profetizado."},{"id":"cf3","texto":"Desejo preparar-me para o glorioso retorno de Jesus."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 15, 'A Tríplice Mensagem Angélica', 'A Última Verdade Presente no Plano da Salvação', 'A Tríplice Mensagem Angélica de Apocalipse 14:6-12 é a última verdade presente e exorta todos os homens a guardar os Mandamentos de Deus, especialmente o Sábado. Esta mensagem adverte contra a adoração de sistemas religiosos terrestres. Seu fim é preparar um povo que se encontre com Jesus em Sua segunda vinda.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que constitui a mensagem de Apocalipse 14:6-12?","opcoes":[{"id":"a","texto":"Uma profecia sobre a criação do mundo"},{"id":"b","texto":"A última ''verdade presente'' do plano da salvação"},{"id":"c","texto":"Uma parábola sobre o Reino de Deus"},{"id":"d","texto":"Uma descrição do paraíso celestial"}],"resposta_correta":"b","explicacao":"A tríplice mensagem angélica apresentada em Apocalipse 14:6-12 é a última mensagem de graça para preparar o mundo para a segunda vinda de Cristo.","referencias":[{"texto":"Ap 14:6-12","livro":"Ap","capitulo":14,"versiculo":"6-12","conteudo":"E vi outro anjo voando pelo meio do céu, e tinha o evangelho eterno para pregar aos que habitam sobre a terra, e a toda nação, e tribo, e língua, e povo,"}]},{"id":"q2","numero":2,"texto":"Quando foi iniciada a tríplice mensagem angélica no tempo determinado?","opcoes":[{"id":"a","texto":"No ano 31 d.C., na cruz do Calvário"},{"id":"b","texto":"Em 1844"},{"id":"c","texto":"No ano 70 d.C., na destruição de Jerusalém"},{"id":"d","texto":"Em 1517, com Martinho Lutero"}],"resposta_correta":"b","explicacao":"A tríplice mensagem angélica começou em 1844, coincidindo com o término dos 2.300 dias/anos e o início do juízo de investigação no santuário celestial.","referencias":[{"texto":"Ap 14:6-12","livro":"Ap","capitulo":14,"versiculo":"6-12","conteudo":"E vi outro anjo voando pelo meio do céu, e tinha o evangelho eterno para pregar aos que habitam sobre a terra, e a toda nação, e tribo, e língua, e povo,"}]},{"id":"q3","numero":3,"texto":"A que a tríplice mensagem angélica exorta todos os homens?","opcoes":[{"id":"a","texto":"A construírem templos em todas as nações"},{"id":"b","texto":"A guardar os Mandamentos de Deus, especialmente o Sábado, e adverte contra a adoração de sistemas religiosos terrestres (a besta)"},{"id":"c","texto":"A fazerem peregrinações a Jerusalém"},{"id":"d","texto":"A se isolarem completamente da sociedade"}],"resposta_correta":"b","explicacao":"A mensagem exorta ao cumprimento dos mandamentos divinos, incluindo a guarda do Sábado, e adverte contra a adoração de poderes religiosos que contradizem a Palavra de Deus.","referencias":[{"texto":"Ap 14:6-12","livro":"Ap","capitulo":14,"versiculo":"6-12","conteudo":"E vi outro anjo voando pelo meio do céu, e tinha o evangelho eterno para pregar aos que habitam sobre a terra, e a toda nação, e tribo, e língua, e povo,"}]},{"id":"q4","numero":4,"texto":"Qual é o fim da última mensagem de graça?","opcoes":[{"id":"a","texto":"Converter todos os povos do mundo sem exceção"},{"id":"b","texto":"Preparar um povo que se encontre com Jesus na Sua segunda vinda e seja guardado das pragas"},{"id":"c","texto":"Estabelecer um governo teocrático na Terra"},{"id":"d","texto":"Unificar todas as religiões do mundo"}],"resposta_correta":"b","explicacao":"A tríplice mensagem visa preparar um remanescente que esteja pronto para encontrar Jesus em Sua vinda e ser preservado durante as pragas finais.","referencias":[{"texto":"Ap 15:8,16","livro":"Ap","capitulo":15,"versiculo":"8,16","conteudo":"[Verificar Ap 15:8,16]"}]},{"id":"q5","numero":5,"texto":"Sobre o que as pragas cairão ao terminar o tempo da graça?","opcoes":[{"id":"a","texto":"Sobre toda a humanidade, sem distinção"},{"id":"b","texto":"Sobre a cristandade apostatada, como ira pura de Deus"},{"id":"c","texto":"Sobre os animais e a natureza apenas"},{"id":"d","texto":"Somente sobre os líderes religiosos apóstatas"}],"resposta_correta":"b","explicacao":"As sete últimas pragas cairão especificamente sobre aqueles que rejeitarem a mensagem de Deus e adorarem o sistema da besta, não sobre o remanescente fiel.","referencias":[{"texto":"Ap 15:8,16","livro":"Ap","capitulo":15,"versiculo":"8,16","conteudo":"[Verificar Ap 15:8,16]"}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a Tríplice Mensagem é a última advertência de Deus."},{"id":"cf2","texto":"Reconheço meu dever de aceitar e proclamar esta mensagem."},{"id":"cf3","texto":"Desejo viver de acordo com os princípios da Tríplice Mensagem Angélica."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 16, 'O Alto Clamor', 'A Repetição Acentuada da Terceira Mensagem', 'O Alto Clamor de Apocalipse 18:1-4 é uma repetição acentuada da Tríplice Mensagem com o poder da terceira mensagem. Precede-o a rejeição e enfraquecimento da última mensagem. O povo de Laodiceia é chamado para uma reforma profunda mediante severas provas, a fim de anunciar a advertência final com poder divino.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que é o Alto Clamor mencionado em Apocalipse 18:1-4?","opcoes":[{"id":"a","texto":"Uma nova mensagem diferente da tríplice mensagem angélica"},{"id":"b","texto":"Uma repetição acentuada da tríplice mensagem angélica com o poder da terceira mensagem"},{"id":"c","texto":"O último sermão pregado antes do fim do mundo"},{"id":"d","texto":"Um chamado exclusivo para os membros da IASDMR"}],"resposta_correta":"b","explicacao":"O Alto Clamor é a terceira mensagem angélica apresentada com grande poder e clareza, com o objetivo final de chamar o povo de Deus para sair de Babilônia.","referencias":[{"texto":"Ap 18:1-4","livro":"Ap","capitulo":18,"versiculo":"1-4","conteudo":"E depois destas coisas vi descer do céu outro anjo, que tinha grande poder; e a terra foi iluminada com a sua glória."}]},{"id":"q2","numero":2,"texto":"O que deve preceder o Alto Clamor segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"A união de todas as igrejas cristãs"},{"id":"b","texto":"Uma rejeição por enfraquecimento e interpretação errônea da última mensagem"},{"id":"c","texto":"A construção de um templo em Jerusalém"},{"id":"d","texto":"A conversão dos governantes mundiais"}],"resposta_correta":"b","explicacao":"O Alto Clamor segue a rejeição da mensagem última por parte da cristandade apóstata, necessitando de uma preparação mais profunda e de maior separação do erro.","referencias":[{"texto":"Ap 18:1-4","livro":"Ap","capitulo":18,"versiculo":"1-4","conteudo":"E depois destas coisas vi descer do céu outro anjo, que tinha grande poder; e a terra foi iluminada com a sua glória."}]},{"id":"q3","numero":3,"texto":"O povo de Laodiceia (Ap 3:14-22) é chamado para quê?","opcoes":[{"id":"a","texto":"Para mudar de denominação religiosa"},{"id":"b","texto":"Para uma reforma por meio de severas provas de fé, a fim de anunciar a advertência final"},{"id":"c","texto":"Para construir mais igrejas"},{"id":"d","texto":"Para se separar da sociedade civil"}],"resposta_correta":"b","explicacao":"O povo de Laodiceia é chamado a passar por um refinamento de fé através de tribulações, a fim de estar preparado para proclamar a mensagem final com poder.","referencias":[{"texto":"Ap 3:14-22","livro":"Ap","capitulo":3,"versiculo":"14-22","conteudo":"E ao anjo da igreja que está em Laodiceia escreve: Isto diz o Amém, a testemunha fiel e verdadeira, o princípio da criação de Deus:"}]},{"id":"q4","numero":4,"texto":"O que os Testemunhos do Espírito de Deus declararam sobre os guardadores do Sábado?","opcoes":[{"id":"a","texto":"Que poderiam observar o domingo em casos especiais"},{"id":"b","texto":"Que os verdadeiros guardadores do Sábado se separariam daqueles que anularam o Sábado e outras exigências de Deus"},{"id":"c","texto":"Que o Sábado seria transferido para outro dia"},{"id":"d","texto":"Que a guarda do Sábado seria opcional nos últimos dias"}],"resposta_correta":"b","explicacao":"Os Testemunhos indicam uma clara separação entre aqueles que guardam os mandamentos de Deus e aqueles que os rejeitam, especialmente quanto ao Sábado.","referencias":[{"texto":"Ap 18:1-4","livro":"Ap","capitulo":18,"versiculo":"1-4","conteudo":"E depois destas coisas vi descer do céu outro anjo, que tinha grande poder; e a terra foi iluminada com a sua glória."}]},{"id":"q5","numero":5,"texto":"O Alto Clamor é a força e o poder de qual mensagem angélica?","opcoes":[{"id":"a","texto":"Da primeira mensagem angélica apenas"},{"id":"b","texto":"Da terceira mensagem angélica"},{"id":"c","texto":"De uma quarta mensagem ainda não revelada"},{"id":"d","texto":"Da segunda mensagem angélica apenas"}],"resposta_correta":"b","explicacao":"O Alto Clamor é o fortalecimento e a plenitude da terceira mensagem angélica, proclamada com todo o seu poder ao mundo antes do encerramento do tempo da graça.","referencias":[{"texto":"Ap 18:1-4","livro":"Ap","capitulo":18,"versiculo":"1-4","conteudo":"E depois destas coisas vi descer do céu outro anjo, que tinha grande poder; e a terra foi iluminada com a sua glória."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o Alto Clamor é a conclusão da mensagem de Deus."},{"id":"cf2","texto":"Reconheço a necessidade de reforma pessoal e congregacional."},{"id":"cf3","texto":"Desejo estar preparado para proclamar o Alto Clamor com poder divino."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 17, 'O Espírito de Profecia', 'O Testemunho de Jesus à Sua Igreja', 'Cristo falou à Sua Igreja ao longo da história por meio dos profetas, tanto no Velho como no Novo Testamento. A Igreja que perde ou menospreza o dom de profecia apostata e anda em trevas. O Espírito de Profecia está diretamente conectado ao conhecimento da vontade de Deus e à orientação de Sua Igreja nos últimos dias.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Como Cristo falou à Sua Igreja ao longo da história?","opcoes":[{"id":"a","texto":"Somente por meio da Bíblia escrita"},{"id":"b","texto":"Por meio dos profetas, tanto no Velho como no Novo Testamento"},{"id":"c","texto":"Apenas por meio dos apóstolos"},{"id":"d","texto":"Somente através de visões e sonhos individuais"}],"resposta_correta":"b","explicacao":"Cristo sempre falou à Sua Igreja através de profetas escolhidos, que recebiam mensagens divinas para guiar o povo de Deus em diferentes períodos.","referencias":[{"texto":"Ap 19:10","livro":"Ap","capitulo":19,"versiculo":"10","conteudo":"Então prostrei-me aos seus pés para adorá-lo; mas ele me disse: Olha, não faças tal; eu sou conservo teu, e de teus irmãos, que têm o testemunho de Jesus. Adora a Deus; porque o testemunho de Jesus é o espírito de profecia."},{"texto":"Cl 1:15-20","livro":"Cl","capitulo":1,"versiculo":"15-20","conteudo":"O qual é imagem do Deus invisível, o primogênito de toda a criação;"}]},{"id":"q2","numero":2,"texto":"O que acontece com a Igreja que perde ou despreza o dom de profecia?","opcoes":[{"id":"a","texto":"Continua crescendo normalmente"},{"id":"b","texto":"Ela apostata e anda em trevas"},{"id":"c","texto":"Recebe outro dom em substituição"},{"id":"d","texto":"Torna-se mais independente e forte"}],"resposta_correta":"b","explicacao":"Sem profecia o povo perece e apostata. O dom de profecia é essencial para manter a Igreja na verdade e no caminho correto, especialmente nos últimos dias.","referencias":[{"texto":"Pv 29:18","livro":"Pv","capitulo":29,"versiculo":"18","conteudo":"Não havendo profecia, o povo se corrompe; mas o que guarda a lei, esse é bem-aventurado."}]},{"id":"q3","numero":3,"texto":"Quem foi abençoada como manifestação da vontade divina desde 1844?","opcoes":[{"id":"a","texto":"Diversos profetas em várias denominações"},{"id":"b","texto":"A irmã Ellen G. White"},{"id":"c","texto":"Somente os pastores consagrados da Igreja"},{"id":"d","texto":"Nenhuma pessoa em particular"}],"resposta_correta":"b","explicacao":"Ellen G. White foi chamada como profetisa para guiar o remanescente de Deus, recebendo visões e mensagens que confirmam e expandem o ensino bíblico.","referencias":[{"texto":"Ef 4:11-14","livro":"Ef","capitulo":4,"versiculo":"11-14","conteudo":"E ele mesmo deu uns para apóstolos, e outros para profetas, e outros para evangelistas, e outros para pastores e mestres;"}]},{"id":"q4","numero":4,"texto":"Os Testemunhos do Espírito de Profecia estão acima da Bíblia?","opcoes":[{"id":"a","texto":"Sim, são superiores à Bíblia como revelação mais recente"},{"id":"b","texto":"Não — não estão acima da Bíblia nem formam um apêndice dela, mas são conselhos de Deus que nos encaminham na verdade da Palavra divina"},{"id":"c","texto":"São equivalentes à Bíblia em autoridade"},{"id":"d","texto":"Substituem a Bíblia para os tempos modernos"}],"resposta_correta":"b","explicacao":"Os Testemunhos de Ellen G. White são conselhos divinos que sustentam e aplicam a verdade bíblica, mas nunca contradizem ou substituem a Escritura Sagrada.","referencias":[{"texto":"Hc 2:2","livro":"Hc","capitulo":2,"versiculo":"2","conteudo":"Respondeu o Senhor: Escreve a visão, e torna-a bem legível em tábuas, para que a possa ler quem passa correndo."},{"texto":"Jr 30:2","livro":"Jr","capitulo":30,"versiculo":"2","conteudo":"Assim fala o Senhor, Deus de Israel, dizendo: Escreve num livro todas as palavras que te tenho dito."}]},{"id":"q5","numero":5,"texto":"A profecia haverá na Igreja até quando?","opcoes":[{"id":"a","texto":"Até que todos os membros sejam perfeitos"},{"id":"b","texto":"Até a segunda vinda do Senhor"},{"id":"c","texto":"Somente até o fim do tempo de graça"},{"id":"d","texto":"Até o estabelecimento do reino milenar"}],"resposta_correta":"b","explicacao":"O dom de profecia permanecerá na Igreja até a volta de Jesus Cristo, quando toda profecia será cumprida e já não será necessária.","referencias":[{"texto":"Mt 28:20","livro":"Mt","capitulo":28,"versiculo":"20","conteudo":"ensinando-os a guardar todas as coisas que vos tenho mandado; e eis que eu estou convosco todos os dias, até a consumação dos séculos."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que Deus continua falando à Sua Igreja por profetas."},{"id":"cf2","texto":"Reconheço a importância dos Testemunhos do Espírito para guia espiritual."},{"id":"cf3","texto":"Desejo valorizar e aceitar os conselhos dados pelo Espírito de Profecia."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 18, 'Matrimônio', 'A União Sagrada Entre Homem e Mulher', 'O matrimônio foi instituído por Deus desde o paraíso e deve durar até o fim do mundo. Os cristãos devem casar apenas com os da mesma fé em Cristo. O divórcio é permitido somente em caso de adultério, quando se pode permanecer sem casar até a morte da outra parte. O casamento deve ser contraído dentro da ordem civil e religiosa.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O matrimônio foi instituído por quem e desde quando?","opcoes":[{"id":"a","texto":"Pela Igreja, como tradição medieval"},{"id":"b","texto":"Por Deus, desde o paraíso até o fim do mundo"},{"id":"c","texto":"Pelos apóstolos, no início da Igreja primitiva"},{"id":"d","texto":"Pela sociedade civil, como contrato social"}],"resposta_correta":"b","explicacao":"O matrimônio foi ordenado por Deus no jardim do Éden, é uma instituição divina sagrada que deve ser honrada e mantida pura segundo a vontade de Deus.","referencias":[{"texto":"Gn 2:24","livro":"Gn","capitulo":2,"versiculo":"24","conteudo":"Portanto deixará o homem a seu pai e a sua mãe, e se unirá à sua mulher, e serão uma só carne."},{"texto":"Hb 13:4","livro":"Hb","capitulo":13,"versiculo":"4","conteudo":"Honroso seja entre todos o matrimônio, e o leito sem mácula; porque Deus julgará os fornicadores e aos adúlteros."},{"texto":"Ef 5:22-23","livro":"Ef","capitulo":5,"versiculo":"22-23","conteudo":"Vós, mulheres, sujeitai-vos a vossos maridos, como ao Senhor;"}]},{"id":"q2","numero":2,"texto":"Os cristãos devem casar com pessoas de que tipo de fé?","opcoes":[{"id":"a","texto":"De qualquer religião, desde que acreditem em Deus"},{"id":"b","texto":"Somente com os da mesma fé"},{"id":"c","texto":"Não importa a fé, desde que haja amor"},{"id":"d","texto":"Com pessoas que aceitem se converter após o casamento"}],"resposta_correta":"b","explicacao":"Os cristãos devem casar somente com outros cristãos da mesma fé, pois casamento com incrédulos leva à apostasia e compromete a vida espiritual.","referencias":[{"texto":"Js 23:12-13","livro":"Js","capitulo":23,"versiculo":"12-13","conteudo":"Porque se vos desviardes, e vos ajuntardes com o resto destas nações, com as que ainda vos ficaram; e com elas vos casardes, e vos misturardes com elas;"},{"texto":"Ne 13:23-28","livro":"Ne","capitulo":13,"versiculo":"23-28","conteudo":"Também vi naqueles dias judeus que tinham casado com mulheres asdoditas, amonitas, e moabitas;"}]},{"id":"q3","numero":3,"texto":"O divórcio está em conformidade com a Palavra de Deus?","opcoes":[{"id":"a","texto":"Sim, é permitido por qualquer motivo"},{"id":"b","texto":"Não — somente em caso de adultério é permitido separar-se e permanecer sem casar até a morte da outra parte"},{"id":"c","texto":"Sim, desde que ambos os cônjuges concordem"},{"id":"d","texto":"Não, em nenhuma circunstância é permitido"}],"resposta_correta":"b","explicacao":"O divórcio é permitido somente em caso de infidelidade conjugal. Noutros casos, a Bíblia ordena a reconciliação ou a permanência na viuvez até a morte do cônjuge.","referencias":[{"texto":"Mt 19:6-8","livro":"Mt","capitulo":19,"versiculo":"6-8","conteudo":"Assim já não são dois, mas uma só carne. Portanto, o que Deus ajuntou, não o separe o homem."}]},{"id":"q4","numero":4,"texto":"Perante quem o matrimônio deve ser contraído?","opcoes":[{"id":"a","texto":"Somente perante Deus em oração privada"},{"id":"b","texto":"Dentro da ordem civil e religiosa — perante autoridades civis e perante a Igreja"},{"id":"c","texto":"Somente perante o pastor da Igreja"},{"id":"d","texto":"Perante qualquer testemunha disponível"}],"resposta_correta":"b","explicacao":"O casamento deve ser contraído com a devida formalidade tanto civil quanto religiosa, respeitando as autoridades ordenadas por Deus e a Igreja.","referencias":[{"texto":"Rm 13:1","livro":"Rm","capitulo":13,"versiculo":"1","conteudo":"Toda a alma esteja sujeita às potestades superiores; porque não há potestade que não venha de Deus; e as potestades que há foram ordenadas por Deus."}]},{"id":"q5","numero":5,"texto":"O casamento com incrédulos é considerado o quê pela Escritura e pelos Testemunhos?","opcoes":[{"id":"a","texto":"Uma oportunidade missionária abençoada"},{"id":"b","texto":"Um grande pecado e separação de Jesus"},{"id":"c","texto":"Uma decisão pessoal sem consequências espirituais"},{"id":"d","texto":"Algo aceitável se o cônjuge não se opuser à fé"}],"resposta_correta":"b","explicacao":"O casamento com incrédulos é severamente condenado como um grande pecado que separa o crente de Jesus e compromete sua salvação.","referencias":[{"texto":"Ne 13:23-28","livro":"Ne","capitulo":13,"versiculo":"23-28","conteudo":"Também vi naqueles dias judeus que tinham casado com mulheres asdoditas, amonitas, e moabitas;"}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o casamento é uma instituição divina sagrada."},{"id":"cf2","texto":"Reconheço a importância de buscar um cônjuge com a mesma fé."},{"id":"cf3","texto":"Desejo honrar os votos matrimoniais e edificar uma família cristã."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 19, 'Temperança e Reforma de Saúde', 'O Cuidado Integral do Corpo e do Espírito', 'É da vontade de Deus que todos os homens gozem de saúde espiritual e física. Temperança significa abstinência total de bebidas e comidas que prejudicam o corpo e o espírito. A reforma de saúde é o braço direito da Terceira Mensagem Angélica e inclui rejeição de carne, pescado, gorduras animais, álcool, café, chá preto, fumo e medicamentos com venenos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que é da vontade de Deus segundo os Princípios de Fé sobre saúde?","opcoes":[{"id":"a","texto":"Que apenas a alma seja saudável"},{"id":"b","texto":"Que todos os homens gozem saúde espiritual e física"},{"id":"c","texto":"Que os cristãos se preocupem apenas com o espírito"},{"id":"d","texto":"Que a saúde física seja irrelevante para a vida espiritual"}],"resposta_correta":"b","explicacao":"A vontade de Deus inclui a saúde integral do ser humano: espiritual e físico. O corpo é templo do Espírito Santo e deve ser cuidado e preservado.","referencias":[{"texto":"1 Tessalonicenses 5:23","livro":"1 Tessalonicenses","capitulo":5,"versiculo":"23","conteudo":"E o mesmo Deus de paz vos santifique em tudo; e todo o vosso ser, o espírito, a alma, e o corpo, seja conservado irrepreensível para a vinda de nosso Senhor Jesus Cristo."}]},{"id":"q2","numero":2,"texto":"O que significa temperança segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Moderação no consumo de qualquer alimento"},{"id":"b","texto":"Total abstinência de bebidas e comidas que prejudicam o corpo e o espírito"},{"id":"c","texto":"Evitar apenas o consumo de álcool"},{"id":"d","texto":"Comer pouco e fazer jejum frequente"}],"resposta_correta":"b","explicacao":"Temperança significa abstinência de tudo que prejudica a saúde corporal e espiritual: álcool, fumo, carnes imundas, refrigerantes e outras substâncias nocivas.","referencias":[{"texto":"1 Coríntios 6:19-20","livro":"1 Coríntios","capitulo":6,"versiculo":"19-20","conteudo":"Não sabeis vós que o vosso corpo é o templo do Espírito Santo, que mora em vós, que vos foi dado por Deus, e que vós não sois de vós mesmos?"}]},{"id":"q3","numero":3,"texto":"A reforma de saúde é o braço direito de qual mensagem?","opcoes":[{"id":"a","texto":"Da primeira mensagem angélica"},{"id":"b","texto":"Da terceira mensagem angélica"},{"id":"c","texto":"Da mensagem do Evangelho em geral"},{"id":"d","texto":"Da segunda mensagem angélica"}],"resposta_correta":"b","explicacao":"A reforma de saúde é o braço direito da terceira mensagem angélica, ajudando a preparar um povo santo e saudável para encontrar Jesus.","referencias":[{"texto":"Apocalipse 14:12","livro":"Apocalipse","capitulo":14,"versiculo":"12","conteudo":"Aqui está a perseverança dos santos; aqui estão os que guardam os mandamentos de Deus e a fé em Jesus."}]},{"id":"q4","numero":4,"texto":"Quais itens são rejeitados pela reforma de saúde, entre outros?","opcoes":[{"id":"a","texto":"Apenas bebidas alcoólicas e cigarro"},{"id":"b","texto":"Carne, pescado, gorduras animais, bebidas alcoólicas, café, chá preto, fumo, medicamentos com venenos e vacinas"},{"id":"c","texto":"Somente alimentos industrializados"},{"id":"d","texto":"Qualquer alimento que não seja orgânico"}],"resposta_correta":"b","explicacao":"A reforma de saúde rejeita carnes imundas, bebidas alcoólicas, café, chá preto, fumo e outras substâncias que prejudicam o templo sagrado do Espírito Santo.","referencias":[{"texto":"Gn 1:29","livro":"Gn","capitulo":1,"versiculo":"29","conteudo":"E disse Deus: Eis que vos tenho dado toda a erva que dá sementes, que se acha na superfície de toda a terra; e todas as árvores, em que há fruto que dê sementes, ser-vos-ão para mantimento."}]},{"id":"q5","numero":5,"texto":"A temperança cristã pertence também a que área além da alimentação?","opcoes":[{"id":"a","texto":"Somente à área financeira"},{"id":"b","texto":"À reforma do vestuário — luxo, tolices, enfeites desnecessários e nudez ofensiva à moral"},{"id":"c","texto":"Apenas à área de entretenimento"},{"id":"d","texto":"Somente à área de trabalho e profissão"}],"resposta_correta":"b","explicacao":"A temperança inclui também a reforma do vestuário, rejeitando luxo excessivo, adornos vãos e roupas que violem a modéstia e a pureza moral.","referencias":[{"texto":"1 Timóteo 2:9-10","livro":"1 Timóteo","capitulo":2,"versiculo":"9-10","conteudo":"Que as mulheres se adornem de forma discreta e modesta, não com tranças, nem com ouro, nem com pérolas, nem com roupas muito custosas;"}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o corpo é templo do Espírito Santo."},{"id":"cf2","texto":"Reconheço a importância de práticas saudáveis para a vida espiritual."},{"id":"cf3","texto":"Desejo adotar a reforma de saúde como parte de meu compromisso com Deus."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 20, 'As Autoridades', 'O Respeito à Autoridade Legítima de Deus', 'Toda autoridade é ordenada por Deus e serve como ministro de Deus para proteger os que fazem o bem. Os deveres para com as autoridades devem ser cumpridos por consciência, não por força. Os seguidores de Cristo não podem participar de guerra, revolta ou derramamento de sangue. Quando o Estado força a consciência e ordena contra a vontade de Deus, devemos obedecer mais a Deus do que aos homens.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Qual é a origem da autoridade segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"A autoridade vem do povo por meio do voto"},{"id":"b","texto":"Toda autoridade é ordenada por Deus e serve como ministro de Deus para proteger os que fazem o bem"},{"id":"c","texto":"A autoridade vem da tradição e dos costumes"},{"id":"d","texto":"Toda autoridade é resultado do poder militar"}],"resposta_correta":"b","explicacao":"Toda autoridade, seja civil ou governamental, vem de Deus e é estabelecida para manter a ordem e proteger os que obedecem às leis justas.","referencias":[{"texto":"Rm 13:1-4","livro":"Rm","capitulo":13,"versiculo":"1-4","conteudo":"Toda a alma esteja sujeita às potestades superiores; porque não há potestade que não venha de Deus; e as potestades que há foram ordenadas por Deus."}]},{"id":"q2","numero":2,"texto":"Os deveres para com as autoridades devem ser cumpridos por quê?","opcoes":[{"id":"a","texto":"Por medo de punição"},{"id":"b","texto":"Por consciência, não por força"},{"id":"c","texto":"Por interesse em receber benefícios"},{"id":"d","texto":"Por obrigação imposta pela Igreja"}],"resposta_correta":"b","explicacao":"Os deveres devem ser cumpridos por consciência e por reconhecer que as autoridades são ministras de Deus, não por medo ou coação.","referencias":[{"texto":"Rm 13:5-7","livro":"Rm","capitulo":13,"versiculo":"5-7","conteudo":"Por isso sois obrigados a sujeitar-vos, não somente pelo castigo, mas também pela consciência."},{"texto":"Tt 3:1-3","livro":"Tt","capitulo":3,"versiculo":"1-3","conteudo":"Lembra-lhes que se sujeitem aos magistrados e às autoridades, e que lhes obedeçam, e estejam prontos para toda a boa obra;"},{"texto":"Mt 22:21","livro":"Mt","capitulo":22,"versiculo":"21","conteudo":"Disseram-lhe: De César. Então lhes disse: Dai, pois, a César o que é de César, e a Deus o que é de Deus."}]},{"id":"q3","numero":3,"texto":"Quando o Estado perde a autoridade perante os cristãos?","opcoes":[{"id":"a","texto":"Quando aumenta os impostos"},{"id":"b","texto":"Ao forçar a consciência e ordenar contra a vontade de Deus — então os cristãos devem obedecer mais a Deus do que aos homens"},{"id":"c","texto":"Quando muda de regime político"},{"id":"d","texto":"Quando não protege a religião oficial do país"}],"resposta_correta":"b","explicacao":"Quando a autoridade tenta forçar a consciência ou exigir desobediência a Deus, o cristão deve obedecer a Deus em primeiro lugar, mesmo que isto resulte em sofrimento.","referencias":[{"texto":"At 5:29-42","livro":"At","capitulo":5,"versiculo":"29-42","conteudo":"Mas Pedro e os apóstolos responderam, e disseram: Mais importa obedecer a Deus do que aos homens."},{"texto":"Dn 3:8-30","livro":"Dn","capitulo":3,"versiculo":"8-30","conteudo":"Então, naquele mesmo tempo, aproximaram-se alguns homens caldeus, e acusaram os judeus."}]},{"id":"q4","numero":4,"texto":"Os seguidores de Cristo podem tomar parte em planos políticos, guerra ou revolta?","opcoes":[{"id":"a","texto":"Sim, quando for por uma causa justa"},{"id":"b","texto":"Não, segundo a doutrina de Cristo não podemos participar de guerra, revolta ou derramamento de sangue"},{"id":"c","texto":"Somente em caso de defesa da pátria"},{"id":"d","texto":"Depende das circunstâncias e da consciência individual"}],"resposta_correta":"b","explicacao":"Os cristãos são chamados a ser pacíficos e não devem participar de guerras, revoltas ou qualquer forma de violência, confiando unicamente em Deus.","referencias":[{"texto":"Mateus 26:52","livro":"Mateus","capitulo":26,"versiculo":"52","conteudo":"Disse-lhe Jesus: Embainha a tua espada; porque todos os que lançarem mão da espada, pela espada morrerão."},{"texto":"João 18:36","livro":"João","capitulo":18,"versiculo":"36","conteudo":"Respondeu Jesus: O meu reino não é deste mundo; se o meu reino fosse deste mundo, os meus servos lutariam para que eu não fosse entregue aos judeus; mas agora o meu reino não é daqui."}]},{"id":"q5","numero":5,"texto":"As autoridades devem conceder a cada cidadão o quê?","opcoes":[{"id":"a","texto":"Proteção militar e econômica"},{"id":"b","texto":"Liberdade para o exercício da sua fé"},{"id":"c","texto":"Educação religiosa obrigatória"},{"id":"d","texto":"Participação no governo da nação"}],"resposta_correta":"b","explicacao":"Cada cidadão tem direito à liberdade de consciência e de religião. As autoridades têm o dever de proteger este direito fundamental.","referencias":[{"texto":"At 5:29-42","livro":"At","capitulo":5,"versiculo":"29-42","conteudo":"Mas Pedro e os apóstolos responderam, e disseram: Mais importa obedecer a Deus do que aos homens."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a autoridade legítima vem de Deus."},{"id":"cf2","texto":"Reconheço meu dever de obedecer às autoridades constituídas."},{"id":"cf3","texto":"Desejo manter-me fiel a Deus mesmo sob pressão das autoridades humanas."}]'::jsonb)
