INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 21, 'O Assinalamento dos 144.000', 'A Restauração do Caráter de Deus nos Últimos Dias', 'O assinalamento significa a restauração do caráter de Deus por meio do Evangelho de Cristo, em obediência completa à Sua santa Lei. O Sábado é o sinal ou selo exterior dos verdadeiros combatentes de Deus. Com a terceira mensagem angélica começou a obra do assinalamento dos 144.000, que é o Israel espiritual escolhido de todos os povos, tribos e línguas.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que significa o assinalamento segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Uma marca física nos crentes"},{"id":"b","texto":"A restauração do caráter de Deus por meio do Evangelho de Cristo, em obediência completa à Sua santa Lei"},{"id":"c","texto":"Um número simbólico sem significado literal"},{"id":"d","texto":"A eleição dos líderes da Igreja"}],"resposta_correta":"b","explicacao":"O assinalamento significa a restauração do caráter de Deus através do Evangelho. Isto ocorre quando os crentes aceitam completamente o Cristo e obedecem Sua santa Lei de forma integral.","referencias":[{"texto":"Ap 7:1-8","livro":"Ap","capitulo":7,"versiculo":"1-8","conteudo":"Depois destas coisas, vi quatro anjos em pé nos quatro cantos da terra, retendo os quatro ventos da terra, para que nenhum vento soprasse sobre a terra, nem sobre o mar, nem sobre árvore alguma. Vi também outro anjo subindo do lado do oriente, tendo o selo do Deus vivo; e clamou com grande voz aos quatro anjos, a quem fora dado fazer dano à terra e ao mar, dizendo: Não danifiqueis a terra, nem o mar, nem as árvores, até que tenhamos assinalado com um selo os servos do nosso Deus na fronte. E ouvi o número dos assinalados, cento e quarenta e quatro mil, assinalados de todas as tribos dos filhos de Israel."},{"texto":"Ap 14:1-5","livro":"Ap","capitulo":14,"versiculo":"1-5","conteudo":"Então, olhei, e eis que estava o Cordeiro em pé sobre o monte Sião, e com ele cento e quarenta e quatro mil, tendo na fronte o nome dele e o nome de seu Pai escrito. Ouvi uma voz que vinha do céu, como a voz de muitas águas e como a voz de um grande trovão; e a voz que ouvi era como a de harpistas, tocando suas harpas. E cantavam um cântico novo diante do trono, e diante dos quatro seres viventes, e dos anciãos; e ninguém podia aprender aquele cântico, senão os cento e quarenta e quatro mil que foram comprados da terra. Estes são os que não se contaminaram com mulheres; porque são virgens. Estes são os que seguem o Cordeiro para onde quer que ele vá. Estes foram comprados dentre os homens para primícias para Deus e para o Cordeiro. E na sua boca não se achou mentira; porque são imaculados."}]},{"id":"q2","numero":2,"texto":"Qual é o sinal ou selo exterior dos verdadeiros combatentes de Deus?","opcoes":[{"id":"a","texto":"O batismo por imersão"},{"id":"b","texto":"O Sábado, pelo qual sempre foi provada a fiel obediência dos crentes"},{"id":"c","texto":"A participação na Santa Ceia"},{"id":"d","texto":"O uso de vestimentas religiosas especiais"}],"resposta_correta":"b","explicacao":"O Sábado é apresentado como o sinal exterior dos que obedecem verdadeiramente a Deus. Ele sempre foi e continua sendo a marca distintiva da fiel observância aos mandamentos divinos.","referencias":[{"texto":"Ez 20:20","livro":"Ez","capitulo":20,"versiculo":"20","conteudo":"E santificai os meus sábados; e eles serão um sinal entre mim e vós; para que saibais que eu sou o Senhor vosso Deus."}]},{"id":"q3","numero":3,"texto":"Com a proclamação de que mensagem começou a obra do assinalamento dos 144.000?","opcoes":[{"id":"a","texto":"Com a primeira mensagem angélica"},{"id":"b","texto":"Com a terceira mensagem angélica, que exige obediência completa aos Mandamentos"},{"id":"c","texto":"Com a pregação dos apóstolos no Pentecostes"},{"id":"d","texto":"Com o sermão do monte de Jesus"}],"resposta_correta":"b","explicacao":"A terceira mensagem angélica em Apocalipse 14 chama à obediência completa aos Mandamentos de Deus, marcando o início do assinalamento do povo remanescente nos últimos dias.","referencias":[{"texto":"Ap 14:6-12","livro":"Ap","capitulo":14,"versiculo":"6-12","conteudo":"Vi outro anjo voando pelo meio do céu, tendo o evangelho eterno para pregar aos que habitam sobre a terra, e a toda nação, e tribo, e língua, e povo, dizendo com grande voz: Temei a Deus, e dai-lhe glória; porque vinda é a hora do seu juízo. E adorai aquele que fez o céu, e a terra, e o mar, e as fontes das águas."}]},{"id":"q4","numero":4,"texto":"O número de 144.000 é composto de que tipo de Israel?","opcoes":[{"id":"a","texto":"Israel segundo a carne (judeus literais)"},{"id":"b","texto":"O Israel espiritual — escolhido maravilhosamente de todos os povos, tribos e línguas"},{"id":"c","texto":"Descendentes biológicos das 12 tribos"},{"id":"d","texto":"Membros de uma única denominação religiosa"}],"resposta_correta":"b","explicacao":"O número 144.000 não representa apenas judeus literais, mas o Israel espiritual escolhido de todas as nações, povos, tribos e línguas, composto por verdadeiros crentes em Cristo.","referencias":[{"texto":"Ap 7:2-8","livro":"Ap","capitulo":7,"versiculo":"2-8","conteudo":"Texto bíblico indisponível"}]},{"id":"q5","numero":5,"texto":"Mediante uma ressurreição especial, o que acontecerá com os assinalados que morreram?","opcoes":[{"id":"a","texto":"Permanecerão dormindo até a segunda vinda"},{"id":"b","texto":"Se ajuntarão aos assinalados vivos antes da vinda de Cristo e serão transformados como primícias da salvação"},{"id":"c","texto":"Serão julgados separadamente dos demais"},{"id":"d","texto":"Não participarão do grupo dos 144.000"}],"resposta_correta":"b","explicacao":"Uma ressurreição especial ocorrerá antes da segunda vinda, reunindo os assinalados que morreram com os vivos para serem transformados como primícias da salvação.","referencias":[{"texto":"Dn 12:2","livro":"Dn","capitulo":12,"versiculo":"2","conteudo":"E muitos dos que dormem no pó da terra acordarão, uns para a vida eterna, e outros para a vergonha e desprezo eterno."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que Deus está assinalando um povo especial para Sua glória."},{"id":"cf2","texto":"Reconheço meu desejo de ser parte dos 144.000 assinalados."},{"id":"cf3","texto":"Desejo manter fidelidade a Deus nos dias finais."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 22, 'A Igreja do Senhor', 'O Corpo Vivo de Cristo na Terra', 'A Igreja é o conjunto dos crentes em associação, segundo a vontade de Deus, que remonta ao princípio da obra salvadora de Cristo. Tornamo-nos membros pelo batismo e fé. Um cristão não pode viver independente da Igreja, assim como os membros do corpo não podem viver separados uns dos outros. A Lei de Deus é a norma imutável da Igreja e forma de reconhecer a apostasia.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que é a Igreja segundo os Princípios de Fé?","opcoes":[{"id":"a","texto":"Um edifício ou templo físico"},{"id":"b","texto":"O conjunto dos crentes em associação, segundo a vontade de Deus, que remonta ao princípio da obra salvadora de Cristo"},{"id":"c","texto":"Uma organização política religiosa"},{"id":"d","texto":"Qualquer grupo de pessoas reunidas para oração"}],"resposta_correta":"b","explicacao":"A Igreja de Cristo é o conjunto de crentes em associação conforme a vontade de Deus, com raízes na obra salvadora que começou com Jesus Cristo.","referencias":[{"texto":"At 15:16","livro":"At","capitulo":15,"versiculo":"16","conteudo":"Depois disto voltarei, e reedificarei o tabernáculo de Davi, que está caído; e repararei as suas ruínas, e o levantarei de novo."},{"texto":"At 20:28","livro":"At","capitulo":20,"versiculo":"28","conteudo":"Olhai, pois, por vós e por todo o rebanho sobre o qual o Espírito Santo vos constituiu bispos, para apascentardes a Igreja de Deus, que ele resgatou com seu próprio sangue."},{"texto":"1 Co 16:19","livro":"1 Co","capitulo":16,"versiculo":"19","conteudo":"As igrejas da Ásia vos saúdam. Áquila e Priscila vos saúdam muito no Senhor, com a igreja que está em sua casa."}]},{"id":"q2","numero":2,"texto":"Como podemos nos tornar membros da Igreja de Cristo?","opcoes":[{"id":"a","texto":"Por tradição familiar e herança religiosa"},{"id":"b","texto":"Somente por meio da fé, conversão e batismo"},{"id":"c","texto":"Por indicação dos líderes da Igreja"},{"id":"d","texto":"Pelo pagamento de dízimos e ofertas"}],"resposta_correta":"b","explicacao":"A entrada na Igreja de Cristo ocorre única e exclusivamente através da fé genuína, da conversão pessoal e do batismo realizado em obediência à ordenança divina.","referencias":[{"texto":"1 Co 12:13","livro":"1 Co","capitulo":12,"versiculo":"13","conteudo":"Porque em um só Espírito fomos todos nós batizados em um só corpo, quer judeus, quer gregos, quer servos, quer livres; e a todos nós foi dado beber de um só Espírito."},{"texto":"Mt 28:19-20","livro":"Mt","capitulo":28,"versiculo":"19-20","conteudo":"Portanto, ide, ensinai todas as nações, batizando-as em nome do Pai, e do Filho, e do Espírito Santo; ensinando-as a guardar todas as coisas que vos tenho mandado; e eis que eu estou convosco todos os dias, até à consumação dos séculos. Amém."}]},{"id":"q3","numero":3,"texto":"Um filho de Deus pode ficar separado ou independente da Igreja?","opcoes":[{"id":"a","texto":"Sim, a fé individual é suficiente"},{"id":"b","texto":"Não — como os membros do corpo não podem viver independentes uns dos outros, tão pouco podem os membros da Igreja"},{"id":"c","texto":"Depende da maturidade espiritual de cada um"},{"id":"d","texto":"Sim, se tiver acesso à Bíblia e ao Espírito de Profecia"}],"resposta_correta":"b","explicacao":"Assim como no corpo humano os membros dependem uns dos outros para funcionar, na Igreja também não é possível aos crentes viverem separados ou independentes uns dos outros.","referencias":[{"texto":"1 Co 12:12-27","livro":"1 Co","capitulo":12,"versiculo":"12-27","conteudo":"Porque, como o corpo é um, e tem muitos membros, e todos os membros do corpo, sendo muitos, formam um só corpo, assim também é Cristo."}]},{"id":"q4","numero":4,"texto":"Qual é a imutável norma da Igreja de Cristo?","opcoes":[{"id":"a","texto":"As tradições e costumes de cada época"},{"id":"b","texto":"A Lei de Deus, por meio da qual é possível reconhecer a apostasia"},{"id":"c","texto":"As decisões dos concílios eclesiásticos"},{"id":"d","texto":"A opinião da maioria dos membros"}],"resposta_correta":"b","explicacao":"A Lei de Deus é a norma imutável da Igreja, servindo como padrão eterno para reconhecer apostasia e para guiar os crentes em verdade.","referencias":[{"texto":"Ef 2:20-22","livro":"Ef","capitulo":2,"versiculo":"20-22","conteudo":"Edificados sobre o fundamento dos apóstolos e dos profetas, sendo Jesus Cristo mesmo a pedra angular; em quem todo o edifício, bem ajustado, cresce para templo santo no Senhor; em quem também vós juntamente sois edificados para habitação de Deus em Espírito."},{"texto":"Cl 2:1-5","livro":"Cl","capitulo":2,"versiculo":"1-5","conteudo":"Porque quero que saibais quão grande é o combate que tenho por vós, e pelos de Laodiceia, e por quantos não viram o meu rosto na carne; para que os seus corações sejam consolados, e estejam unidos em amor, e enriquecidos da plenitude da inteligência, para conhecimento do mistério de Deus e Pai, e de Cristo; em quem estão escondidos todos os tesouros da sabedoria e da ciência."},{"texto":"1 Co 3:9-11","livro":"1 Co","capitulo":3,"versiculo":"9-11","conteudo":"Porque nós somos cooperadores de Deus; vós sois lavoura de Deus e edifício de Deus. Segundo a graça de Deus que me foi dada, eu, como sábio arquiteto, lancei o fundamento, e outro edifica sobre ele; mas vede cada um como edifica sobre ele. Porque ninguém pode lançar outro fundamento, além do que já está posto, o qual é Jesus Cristo."}]},{"id":"q5","numero":5,"texto":"Para que serve a Igreja como escola de Cristo?","opcoes":[{"id":"a","texto":"Para ensinar profissões e ofícios"},{"id":"b","texto":"Para que todos aprendam, por meio de instruções, experiências, exortações e consolações, preparando-se para a Igreja da eternidade"},{"id":"c","texto":"Para administrar os bens materiais dos membros"},{"id":"d","texto":"Para promover eventos sociais e culturais"}],"resposta_correta":"b","explicacao":"A Igreja funciona como escola de Cristo para que todos aprendam através de instruções bíblicas, experiências de fé, exortações amorosas e consolações, preparando-se para a eternidade.","referencias":[{"texto":"1 Co 12:12-27","livro":"1 Co","capitulo":12,"versiculo":"12-27","conteudo":"Porque, como o corpo é um, e tem muitos membros, e todos os membros do corpo, sendo muitos, formam um só corpo, assim também é Cristo."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a Igreja é o corpo vivo de Cristo."},{"id":"cf2","texto":"Reconheço minha necessidade de comunhão com os irmãos na fé."},{"id":"cf3","texto":"Desejo ser membro ativo e fiel da Igreja do Senhor."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 23, 'Os Cargos na Igreja', 'A Estrutura de Liderança Divina', 'Os servidores ou oficiais da Igreja devem ser eleitos pela própria Igreja conforme a Palavra de Deus. Os três principais oficiais são: Ministro consagrado (apóstolo), Ancião consagrado (pastor/intendente) e Diácono consagrado (despenseiro). São consagrados pela Igreja mediante a oração e imposição das mãos. A consagração não confere capacidade ou dignidade; as qualidades já devem estar presentes no serviço anterior.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Quem deve eleger os servidores (oficiais) da Igreja?","opcoes":[{"id":"a","texto":"O pastor principal da região"},{"id":"b","texto":"A própria Igreja, conforme a Palavra de Deus"},{"id":"c","texto":"A Conferência Geral diretamente"},{"id":"d","texto":"Os membros mais antigos da congregação"}],"resposta_correta":"b","explicacao":"De acordo com a Palavra de Deus, a própria Igreja, através de seus membros, deve eleger seus servidores e oficiais, não imposição externa.","referencias":[{"texto":"At 6:1-6","livro":"At","capitulo":6,"versiculo":"1-6","conteudo":"Naqueles dias, multiplicando-se o número dos discípulos, houve uma murmuração dos gregos contra os hebreus, porque as suas viúvas eram desprezadas na distribuição diária. Então os doze, convocando a multidão dos discípulos, disseram: Não é razão que deixemos a palavra de Deus, e sirvamos às mesas. Escolhei, pois, dentre vós, sete homens de boa reputação, cheios do Espírito Santo e de sabedoria, aos quais encarreguemos deste negócio. E apresentaremos este negócio aos apóstolos. E este parecer agradou a toda a multidão; e elegeram Estêvão, homem cheio de fé e do Espírito Santo, e Filipe, e Prócoro, e Nicanor, e Timão, e Pármenas, e Nicolau, prosélito de Antioquia; e os apresentaram ante os apóstolos, e oraram, e lhes impuseram as mãos."},{"texto":"At 20:28","livro":"At","capitulo":20,"versiculo":"28","conteudo":"Olhai, pois, por vós e por todo o rebanho sobre o qual o Espírito Santo vos constituiu bispos, para apascentardes a Igreja de Deus, que ele resgatou com seu próprio sangue."},{"texto":"At 13:1-5","livro":"At","capitulo":13,"versiculo":"1-5","conteudo":"Havia na igreja que estava em Antioquia profetas e mestres; Barnabé, Simeão chamado Níger, Lúcio, cirenaico, Manaém, colega de infância de Herodes o tetrarca, e Saulo. Enquanto ministravam ao Senhor, e jejuavam, disse o Espírito Santo: Separai-me a Barnabé e a Saulo para a obra a que os tenho chamado. Então, jejuando e orando, e impondo sobre eles as mãos, os despediram."}]},{"id":"q2","numero":2,"texto":"Quais são os três principais oficiais da Igreja?","opcoes":[{"id":"a","texto":"Pastor, evangelista e professor"},{"id":"b","texto":"Ministro consagrado (apóstolo), Ancião consagrado (pastor/intendente) e Diácono consagrado (despenseiro)"},{"id":"c","texto":"Presidente, secretário e tesoureiro"},{"id":"d","texto":"Bispo, presbítero e leigo"}],"resposta_correta":"b","explicacao":"Os três principais oficiais são: o Ministro Consagrado (apóstolo/pastor), o Ancião Consagrado (pastor/intendente) e o Diácono Consagrado (despenseiro/administrador).","referencias":[{"texto":"At 6:1-6","livro":"At","capitulo":6,"versiculo":"1-6","conteudo":"Naqueles dias, multiplicando-se o número dos discípulos, houve uma murmuração dos gregos contra os hebreus, porque as suas viúvas eram desprezadas na distribuição diária. Então os doze, convocando a multidão dos discípulos, disseram: Não é razão que deixemos a palavra de Deus, e sirvamos às mesas. Escolhei, pois, dentre vós, sete homens de boa reputação, cheios do Espírito Santo e de sabedoria, aos quais encarreguemos deste negócio. E apresentaremos este negócio aos apóstolos. E este parecer agradou a toda a multidão; e elegeram Estêvão, homem cheio de fé e do Espírito Santo, e Filipe, e Prócoro, e Nicanor, e Timão, e Pármenas, e Nicolau, prosélito de Antioquia; e os apresentaram ante os apóstolos, e oraram, e lhes impuseram as mãos."},{"texto":"At 20:28","livro":"At","capitulo":20,"versiculo":"28","conteudo":"Olhai, pois, por vós e por todo o rebanho sobre o qual o Espírito Santo vos constituiu bispos, para apascentardes a Igreja de Deus, que ele resgatou com seu próprio sangue."}]},{"id":"q3","numero":3,"texto":"Como são consagrados estes oficiais?","opcoes":[{"id":"a","texto":"Por votação secreta dos membros"},{"id":"b","texto":"Pela Igreja mediante a oração e a imposição das mãos"},{"id":"c","texto":"Por nomeação da Conferência Geral"},{"id":"d","texto":"Por autodeclaração e reconhecimento público"}],"resposta_correta":"b","explicacao":"Estes oficiais são consagrados pela Igreja mediante oração solene e a imposição das mãos, reconhecendo a Deus como a fonte de toda autoridade.","referencias":[{"texto":"1 Tm 5:22","livro":"1 Tm","capitulo":5,"versiculo":"22","conteudo":"Não imponhas as mãos a ninguém levianamente, e não participes dos pecados alheios; conserva-te a ti mesmo puro."},{"texto":"Tt 1:5","livro":"Tt","capitulo":1,"versiculo":"5","conteudo":"Por esta causa te deixei em Creta, para que pusesses em ordem as coisas que ainda faltavam, e constituísses presbíteros em cada cidade, como também te mandei:"}]},{"id":"q4","numero":4,"texto":"A consagração confere dignidade ou capacidade ao consagrado?","opcoes":[{"id":"a","texto":"Sim, eleva a pessoa a um status especial"},{"id":"b","texto":"Não — não se alcança capacidade ou dignidade por meio da consagração; as qualidades já devem ter sido constatadas pelo serviço anterior"},{"id":"c","texto":"Parcialmente — ajuda no desenvolvimento espiritual"},{"id":"d","texto":"Sim, é o que qualifica para o ministério"}],"resposta_correta":"b","explicacao":"A consagração não confere capacidade ou dignidade pessoal ao consagrado; estas qualidades já devem ter sido evidenciadas por seu serviço anterior e fidelidade.","referencias":[{"texto":"1 Tm 5:22","livro":"1 Tm","capitulo":5,"versiculo":"22","conteudo":"Não imponhas as mãos a ninguém levianamente, e não participes dos pecados alheios; conserva-te a ti mesmo puro."}]},{"id":"q5","numero":5,"texto":"Somente quem está autorizado a dirigir a obra evangélica, batizar e repartir a Santa Ceia?","opcoes":[{"id":"a","texto":"Qualquer membro da Igreja com boa reputação"},{"id":"b","texto":"Somente os servos consagrados"},{"id":"c","texto":"Os anciãos e diáconos indistintamente"},{"id":"d","texto":"Qualquer pessoa com formação teológica"}],"resposta_correta":"b","explicacao":"Apenas os servos consagrados pela Igreja estão autorizados a dirigir a obra evangélica, batizar os conversos e distribuir a Santa Ceia em obediência ao padrão bíblico.","referencias":[{"texto":"At 6:1-6","livro":"At","capitulo":6,"versiculo":"1-6","conteudo":"Naqueles dias, multiplicando-se o número dos discípulos, houve uma murmuração dos gregos contra os hebreus, porque as suas viúvas eram desprezadas na distribuição diária. Então os doze, convocando a multidão dos discípulos, disseram: Não é razão que deixemos a palavra de Deus, e sirvamos às mesas. Escolhei, pois, dentre vós, sete homens de boa reputação, cheios do Espírito Santo e de sabedoria, aos quais encarreguemos deste negócio. E apresentaremos este negócio aos apóstolos. E este parecer agradou a toda a multidão; e elegeram Estêvão, homem cheio de fé e do Espírito Santo, e Filipe, e Prócoro, e Nicanor, e Timão, e Pármenas, e Nicolau, prosélito de Antioquia; e os apresentaram ante os apóstolos, e oraram, e lhes impuseram as mãos."},{"texto":"At 20:28","livro":"At","capitulo":20,"versiculo":"28","conteudo":"Olhai, pois, por vós e por todo o rebanho sobre o qual o Espírito Santo vos constituiu bispos, para apascentardes a Igreja de Deus, que ele resgatou com seu próprio sangue."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio na forma de governo da Igreja segundo a Palavra de Deus."},{"id":"cf2","texto":"Reconheço a importância da liderança consagrada e fiel."},{"id":"cf3","texto":"Desejo apoiar e respeitar os oficiais da Igreja em seu ministério."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 24, 'A Recepção na Igreja', 'A Aceitação Formal de Novos Membros', 'A recepção pode ter lugar quando as almas alcançarem conhecimento e convicção básicos dos princípios da fé. Exige a saída de qualquer outra corporação religiosa, de toda sociedade secreta e de todo sindicato. O seguro de vida é contrário à doutrina de Cristo. A recepção é confirmada por testemunho perante a congregação e pelo estender da mão do servo consagrado.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Quando pode ter lugar a recepção na Igreja?","opcoes":[{"id":"a","texto":"Quando a pessoa frequenta os cultos por pelo menos um ano"},{"id":"b","texto":"Quando as almas já tenham alcançado conhecimento e convicção básicos dos princípios de nossa fé, e a Igreja não tiver objeção"},{"id":"c","texto":"Quando a pessoa demonstra bom comportamento social"},{"id":"d","texto":"Quando faz uma doação significativa à congregação"}],"resposta_correta":"b","explicacao":"A recepção na Igreja pode ocorrer quando a pessoa demonstra conhecimento e convicção básicos dos princípios de fé, e a congregação não apresenta objeção fundamentada.","referencias":[{"texto":"At 2:37-38,41","livro":"At","capitulo":2,"versiculo":"37-38","conteudo":"Ouvindo isto, compungiram-se em seu coração, e perguntaram a Pedro e aos demais apóstolos: Varões irmãos, que faremos? E Pedro lhes disse: Arrependei-vos, e cada um de vós seja batizado em nome de Jesus Cristo, para perdão dos pecados; e recebereis o dom do Espírito Santo. De sorte que foram batizados os que de bom grado receberam a sua palavra; e naquele dia agregaram-se-lhes cerca de três mil almas."}]},{"id":"q2","numero":2,"texto":"O que a recepção na Igreja exige em relação a outras organizações?","opcoes":[{"id":"a","texto":"Apenas a desvinculação de igrejas concorrentes"},{"id":"b","texto":"A saída de qualquer outra corporação religiosa, de toda sociedade secreta e de todo sindicato"},{"id":"c","texto":"Somente uma declaração verbal de fidelidade"},{"id":"d","texto":"Nenhuma exigência quanto a outras organizações"}],"resposta_correta":"b","explicacao":"A recepção exige a saída de qualquer corporação religiosa rival, de toda sociedade secreta e de qualquer sindicato, para evitar compromisso com práticas contrárias à fé.","referencias":[{"texto":"2 Co 6:14-18","livro":"2 Co","capitulo":6,"versiculo":"14-18","conteudo":"Não vos prendais a um jugo desigual com os infiéis; porque, que sociedade tem a justiça com a injustiça? E que comunhão tem a luz com as trevas? E que harmonia há entre Cristo e Belial? Ou que parte tem o fiel com o infiel? E que consenso tem o templo de Deus com os ídolos? Pois vós sois o templo do Deus vivo, como Deus disse: Habitarei neles, e entre eles andarei; e serei o seu Deus e eles serão o meu povo. Portanto saí do meio deles, e apartai-vos, diz o Senhor; e não toqueis nada imundo, e eu vos receberei; e serei para vós Pai, e vós sereis para mim filhos e filhas, diz o Senhor Todo-Poderoso."},{"texto":"Ap 18:4","livro":"Ap","capitulo":18,"versiculo":"4","conteudo":"Ouvi outra voz do céu, dizendo: Saí dela, povo meu, para que não sejas participante dos seus pecados, e para que não incorras nas suas pragas."},{"texto":"Tg 5:7-9","livro":"Tg","capitulo":5,"versiculo":"7-9","conteudo":"Portanto, irmãos, tende paciência até à vinda do Senhor. Eis que o lavrador espera o precioso fruto da terra, aguardando-o com paciência, até que receba as chuvas temporã e serôdia. Tende vós também paciência, e fortificai os vossos corações; porque a vinda do Senhor está próxima. Não vos queixeis uns dos outros, irmãos, para que não sejais condenados; eis que o juiz está à porta."}]},{"id":"q3","numero":3,"texto":"O seguro de vida é compatível com a doutrina de Cristo?","opcoes":[{"id":"a","texto":"Sim, é prudência financeira"},{"id":"b","texto":"Não, é contrário à doutrina de Cristo; um seguidor de Cristo não pode participar dele"},{"id":"c","texto":"Depende do tipo de seguro"},{"id":"d","texto":"Somente se for para proteger a família"}],"resposta_correta":"b","explicacao":"O seguro de vida é contrário à doutrina de Cristo porque representa desconfiança no cuidado divino e participação em sistemas comerciais incompatíveis com a fé.","referencias":[{"texto":"1 Pe 1:17-19","livro":"1 Pe","capitulo":1,"versiculo":"17-19","conteudo":"E, se invocais por Pai aquele que sem acepção de pessoas julga segundo a obra de cada um, conduzi-vos em temor durante o tempo da vossa peregrinação; sabendo que não foi com coisas corruptíveis, como ouro ou prata, que fostes resgatados da vossa vã maneira de viver que por tradição recebestes dos vossos pais; mas com o precioso sangue de Cristo, como de um cordeiro imaculado e incontaminado."}]},{"id":"q4","numero":4,"texto":"Como é confirmada a recepção do novo membro?","opcoes":[{"id":"a","texto":"Por votação secreta do conselho da Igreja"},{"id":"b","texto":"Por testemunho perante a congregação e por meio do estender da mão do servo consagrado"},{"id":"c","texto":"Por assinatura de um documento formal"},{"id":"d","texto":"Por participação na Santa Ceia"}],"resposta_correta":"b","explicacao":"A recepção é confirmada pelo testemunho perante toda a congregação e pelo ato do servo consagrado estender a mão do acolhimento fraterna ao novo membro.","referencias":[{"texto":"At 2:37-38,41","livro":"At","capitulo":2,"versiculo":"37-38","conteudo":"Ouvindo isto, compungiram-se em seu coração, e perguntaram a Pedro e aos demais apóstolos: Varões irmãos, que faremos? E Pedro lhes disse: Arrependei-vos, e cada um de vós seja batizado em nome de Jesus Cristo, para perdão dos pecados; e recebereis o dom do Espírito Santo. De sorte que foram batizados os que de bom grado receberam a sua palavra; e naquele dia agregaram-se-lhes cerca de três mil almas."},{"texto":"1 Tm 6:12","livro":"1 Tm","capitulo":6,"versiculo":"12","conteudo":"Milita a boa milícia da fé, toma posse da vida eterna, para a qual foste chamado, tendo feito a boa confissão diante de muitas testemunhas."}]},{"id":"q5","numero":5,"texto":"Como os membros da Igreja devem se tratar entre si?","opcoes":[{"id":"a","texto":"Com formalidade e distância profissional"},{"id":"b","texto":"Como irmãos e irmãs em Cristo, com o ósculo santo"},{"id":"c","texto":"Com respeito hierárquico baseado nos cargos"},{"id":"d","texto":"De acordo com o grau de contribuição financeira"}],"resposta_correta":"b","explicacao":"Os membros da Igreja devem tratar-se mutuamente como irmãos e irmãs em Cristo, expressando essa fraternidade com o ósculo santo de pura comunhão cristã.","referencias":[{"texto":"2 Co 13:12","livro":"2 Co","capitulo":13,"versiculo":"12","conteudo":"Saudai-vos uns aos outros com um santo ósculo. Todos os santos vos saúdam."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a Igreja deve manter normas de recepção claras e bíblicas."},{"id":"cf2","texto":"Reconheço o significado profundo da recepção como entrada formal."},{"id":"cf3","texto":"Desejo que todos os membros vivam segundo os princípios da fé."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 25, 'Deveres dos Membros da Igreja', 'O Compromisso de Fidelidade no Corpo de Cristo', 'Todos os deveres dos membros baseiam-se no amor mútuo. É privilégio e dever de cada membro tomar parte no Lava-pés, na Santa Ceia e nos cultos no Sábado e em outros dias. Somente a doença ou outra causa justa desculpa a ausência dos cultos. Os membros devem aceitar as exortações com amor e frequentar reuniões para ouvir a Palavra de Deus na Escola Sabatina.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Em que se baseiam todos os deveres dos membros da Igreja?","opcoes":[{"id":"a","texto":"Na tradição e nos costumes da congregação"},{"id":"b","texto":"No amor mútuo"},{"id":"c","texto":"Na obediência aos líderes"},{"id":"d","texto":"Na contribuição financeira regular"}],"resposta_correta":"b","explicacao":"Todos os deveres dos membros da Igreja fundamentam-se no amor mútuo, conforme ensinou Jesus, que resumiu toda Lei neste princípio supremo.","referencias":[{"texto":"Jo 13:34-35","livro":"Jo","capitulo":13,"versiculo":"34-35","conteudo":"Um mandamento novo vos dou: Que vos ameis uns aos outros; como eu vos amei a vós, que também vós uns aos outros vos ameis. Nisto conhecerão todos que sois meus discípulos, se vos amardes uns aos outros."}]},{"id":"q2","numero":2,"texto":"É privilégio e dever de cada membro tomar parte em quê?","opcoes":[{"id":"a","texto":"Na administração financeira da Igreja"},{"id":"b","texto":"No lava-pés e na Santa Ceia, e frequentar os cultos no Sábado e nos outros dias"},{"id":"c","texto":"Somente nos cultos do Sábado"},{"id":"d","texto":"Apenas nas atividades sociais da congregação"}],"resposta_correta":"b","explicacao":"É privilégio e dever de cada membro participar do lava-pés e da Santa Ceia, frequentar os cultos no Sábado e também em outros dias da semana.","referencias":[{"texto":"Sl 116:18","livro":"Sl","capitulo":116,"versiculo":"18","conteudo":"Pagarei os meus votos ao Senhor agora na presença de todo o seu povo."},{"texto":"1 Co 11:17-34","livro":"1 Co","capitulo":11,"versiculo":"17-34","conteudo":"Porém, naquilo que vou dizer-vos, não vos louvo; porque vos ajuntais, não para melhor, mas para pior. Porque, em primeiro lugar, ouço que há divisões entre vós quando vos congregais; e em parte vos creia."}]},{"id":"q3","numero":3,"texto":"Somente o que pode desculpar a ausência dos cultos?","opcoes":[{"id":"a","texto":"Viagens de lazer ou trabalho"},{"id":"b","texto":"A doença ou outra causa justa"},{"id":"c","texto":"A distância da Igreja"},{"id":"d","texto":"O cansaço e as ocupações pessoais"}],"resposta_correta":"b","explicacao":"Apenas a doença ou outra causa justa pode desculpar legitimamente a ausência dos cultos; outras razões não são aceitáveis diante de Deus.","referencias":[{"texto":"Sl 116:18","livro":"Sl","capitulo":116,"versiculo":"18","conteudo":"Pagarei os meus votos ao Senhor agora na presença de todo o seu povo."}]},{"id":"q4","numero":4,"texto":"Todo membro tem também o dever de aceitar o quê com amor?","opcoes":[{"id":"a","texto":"As críticas públicas dos líderes"},{"id":"b","texto":"As exortações feitas com amor"},{"id":"c","texto":"Apenas os elogios dos irmãos"},{"id":"d","texto":"As decisões unilaterais do pastor"}],"resposta_correta":"b","explicacao":"Todo membro deve aceitar com amor as exortações feitas com sinceridade e amor fraternal, reconhecendo-as como beneficiosas para seu crescimento espiritual.","referencias":[{"texto":"Pv 15:31-32","livro":"Pv","capitulo":15,"versiculo":"31-32","conteudo":"O ouvido que ouve as repreensões da vida, entre os sábios habitará. O que rejeita a correção, menospreza a sua alma; mas o que ouve a repreensão adquire inteligência."}]},{"id":"q5","numero":5,"texto":"Cada membro deve assistir às reuniões para ouvir o quê?","opcoes":[{"id":"a","texto":"As notícias da comunidade local"},{"id":"b","texto":"A Palavra de Deus — na Escola Sabatina e nos cultos"},{"id":"c","texto":"Apenas os relatórios administrativos"},{"id":"d","texto":"As opiniões dos membros mais experientes"}],"resposta_correta":"b","explicacao":"Cada membro deve assistir regularmente às reuniões para ouvir a Palavra de Deus sendo ensinada na Escola Sabatina e nos cultos de adoração.","referencias":[{"texto":"Jo 13:34-35","livro":"Jo","capitulo":13,"versiculo":"34-35","conteudo":"Um mandamento novo vos dou: Que vos ameis uns aos outros; como eu vos amei a vós, que também vós uns aos outros vos ameis. Nisto conhecerão todos que sois meus discípulos, se vos amardes uns aos outros."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que todo membro tem responsabilidades na Igreja."},{"id":"cf2","texto":"Reconheço meu dever de participar ativamente da vida congregacional."},{"id":"cf3","texto":"Desejo viver sob amor mútuo e comunhão fraterna."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 26, 'Disciplina da Igreja', 'O Procedimento Ordenado de Correção Fraterna', 'A disciplina da Igreja baseia-se na ordem dada por Jesus em Mateus 18:15-17 e deve ser observada com exatidão e sem acepção de pessoas. Somente a exclusão da Igreja autoriza dissolver a irmandade em Cristo. A disciplina deve seguir três etapas: pessoal, com testemunhas, e perante a Igreja. Todo membro deve aceitar as exortações com amor, reconhecendo-as como benéficas.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Em que se baseia a disciplina da Igreja?","opcoes":[{"id":"a","texto":"Nas tradições eclesiásticas acumuladas"},{"id":"b","texto":"Na ordem dada por Jesus em Mateus 18:15-17"},{"id":"c","texto":"Nas leis civis de cada país"},{"id":"d","texto":"Nos regulamentos internos de cada congregação"}],"resposta_correta":"b","explicacao":"A disciplina da Igreja baseia-se na ordem direta de Jesus em Mateus 18:15-17, que estabelece o processo bíblico para lidar com o pecado de forma amorosa.","referencias":[{"texto":"Mt 18:15-17","livro":"Mt","capitulo":18,"versiculo":"15-17","conteudo":"Ora, se teu irmão pecar contra ti, vai, e repreende-o entre ti e ele só; se te ouvir, ganhaste a teu irmão. Mas, se não te ouvir, leva contigo ainda um ou dois, para que pela boca de duas ou três testemunhas toda a palavra seja confirmada. E, se não as ouvir, dize-o à igreja; e, se nem à igreja ouvir, considera-o como um gentio e publicano."}]},{"id":"q2","numero":2,"texto":"Todo membro da Igreja deve observar esta regra com o quê?","opcoes":[{"id":"a","texto":"Com rigor e punição severa"},{"id":"b","texto":"Com exatidão, sem acepção de pessoas"},{"id":"c","texto":"Com flexibilidade dependendo de quem é a pessoa"},{"id":"d","texto":"Com discrição para não causar constrangimento"}],"resposta_correta":"b","explicacao":"Toda disciplina deve ser observada com exatidão e sem acepção de pessoas, aplicando-se igualmente a todos os membros independentemente de posição ou influência.","referencias":[{"texto":"Mt 18:15-17","livro":"Mt","capitulo":18,"versiculo":"15-17","conteudo":"Ora, se teu irmão pecar contra ti, vai, e repreende-o entre ti e ele só; se te ouvir, ganhaste a teu irmão. Mas, se não te ouvir, leva contigo ainda um ou dois, para que pela boca de duas ou três testemunhas toda a palavra seja confirmada. E, se não as ouvir, dize-o à igreja; e, se nem à igreja ouvir, considera-o como um gentio e publicano."}]},{"id":"q3","numero":3,"texto":"O que autoriza os membros e a Igreja?","opcoes":[{"id":"a","texto":"Impor punições físicas ou financeiras"},{"id":"b","texto":"Somente a exclusão da Igreja autoriza dissolver a irmandade em Cristo"},{"id":"c","texto":"Qualquer tipo de sanção que pareça apropriada"},{"id":"d","texto":"Expulsar membros por questões pessoais"}],"resposta_correta":"b","explicacao":"A única autoridade que justifica dissolução da comunhão fraterna é a exclusão formal da Igreja, nunca por outras sanções como punições físicas ou financeiras.","referencias":[{"texto":"Mt 18:15-17","livro":"Mt","capitulo":18,"versiculo":"15-17","conteudo":"Ora, se teu irmão pecar contra ti, vai, e repreende-o entre ti e ele só; se te ouvir, ganhaste a teu irmão. Mas, se não te ouvir, leva contigo ainda um ou dois, para que pela boca de duas ou três testemunhas toda a palavra seja confirmada. E, se não as ouvir, dize-o à igreja; e, se nem à igreja ouvir, considera-o como um gentio e publicano."}]},{"id":"q4","numero":4,"texto":"Todo membro tem o dever de aceitar as exortações com que atitude?","opcoes":[{"id":"a","texto":"Com resistência e questionamento público"},{"id":"b","texto":"Com amor, reconhecendo-as como benéficas"},{"id":"c","texto":"Com indiferença passiva"},{"id":"d","texto":"Com submissão silenciosa e sem questionar"}],"resposta_correta":"b","explicacao":"Todo membro deve aceitar as exortações com amor, reconhecendo-as como expressão da preocupação genuína com seu bem-estar espiritual eterno.","referencias":[{"texto":"Pv 15:31-32","livro":"Pv","capitulo":15,"versiculo":"31-32","conteudo":"O ouvido que ouve as repreensões da vida, entre os sábios habitará. O que rejeita a correção, menospreza a sua alma; mas o que ouve a repreensão adquire inteligência."}]},{"id":"q5","numero":5,"texto":"A disciplina deve ser aplicada seguindo quantas etapas segundo Jesus?","opcoes":[{"id":"a","texto":"Uma única advertência pública"},{"id":"b","texto":"Três etapas: pessoal, com testemunhas, e perante a Igreja"},{"id":"c","texto":"Duas etapas: aviso e exclusão"},{"id":"d","texto":"Quatro etapas conforme a gravidade"}],"resposta_correta":"b","explicacao":"Segundo Jesus, a disciplina segue três etapas: pessoal e privada, depois com testemunhas presentes, e finalmente perante toda a congregação se necessário.","referencias":[{"texto":"Mt 18:15-17","livro":"Mt","capitulo":18,"versiculo":"15-17","conteudo":"Ora, se teu irmão pecar contra ti, vai, e repreende-o entre ti e ele só; se te ouvir, ganhaste a teu irmão. Mas, se não te ouvir, leva contigo ainda um ou dois, para que pela boca de duas ou três testemunhas toda a palavra seja confirmada. E, se não as ouvir, dize-o à igreja; e, se nem à igreja ouvir, considera-o como um gentio e publicano."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio na disciplina como meio de correção e reabilitação."},{"id":"cf2","texto":"Reconheço a importância de advertências fraternas em amor."},{"id":"cf3","texto":"Desejo manter-me sob a disciplina piedosa da Igreja."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 27, 'Exclusão', 'O Rompimento da Irmandade por Apostasia', 'A Igreja deve excluir os membros cujo proceder seja aberta e continuamente contrário aos princípios da fé. A exclusão pode ser confirmada somente de acordo com a Palavra de Deus, baseada em proceder aberto e contínuo contrário à fé, não por acusações sem prova. A exclusão dissolve a irmandade em Cristo entre os membros.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"A Igreja tem o dever de excluir que tipo de membros?","opcoes":[{"id":"a","texto":"Os que discordam da liderança"},{"id":"b","texto":"Aqueles cujo proceder é aberta e continuamente contrário aos princípios da fé"},{"id":"c","texto":"Os que faltam aos cultos ocasionalmente"},{"id":"d","texto":"Os que não pagam dízimos regularmente"}],"resposta_correta":"b","explicacao":"A Igreja tem o dever de excluir aqueles membros cujo proceder é aberta e continuamente contrário aos princípios fundamentais da fé cristã.","referencias":[{"texto":"1 Co 5:11-13","livro":"1 Co","capitulo":5,"versiculo":"11-13","conteudo":"Mas agora vos escrevi, que não vos associeis com ninguém que, dizendo-se irmão, for fornicador, ou avarento, ou idólatra, ou maldizente, ou beberrão, ou roubador; com esse tal nem comais. Porque que tenho eu em julgar também os que estão fora? Não julgais vós os que estão dentro? Aos que estão fora Deus os julgará. Tirai, pois, dentre vós a esse iníquo."}]},{"id":"q2","numero":2,"texto":"A exclusão pode ser confirmada somente de acordo com o quê?","opcoes":[{"id":"a","texto":"A opinião da maioria dos membros presentes"},{"id":"b","texto":"A Palavra de Deus"},{"id":"c","texto":"A decisão unilateral do pastor"},{"id":"d","texto":"As regras internas de cada congregação local"}],"resposta_correta":"b","explicacao":"A exclusão pode ser confirmada única e exclusivamente de acordo com a Palavra de Deus, nunca por opinião humana, voto de maioria ou decisão arbitrária.","referencias":[{"texto":"1 Tm 1:19-20","livro":"1 Tm","capitulo":1,"versiculo":"19-20","conteudo":"Mantendo fé e boa consciência, que alguns rejeitaram e naufragaram na fé. Entre os quais estão Himeneu e Alexandre, que entreguei a Satanás, para que aprendam a não blasfemar."},{"texto":"1 Co 5:1-13","livro":"1 Co","capitulo":5,"versiculo":"1-13","conteudo":"Geralmente se ouve que há entre vós fornicação, e tal fornicação, qual nem ainda entre os gentios; a saber, que alguém tem a mulher de seu pai."},{"texto":"Tt 3:10-11","livro":"Tt","capitulo":3,"versiculo":"10-11","conteudo":"Ao homem herege, depois de uma e outra admoestação, evita; sabendo que tal homem é pervertido, e peca, condenando-se a si mesmo."}]},{"id":"q3","numero":3,"texto":"Assim como na recepção, a exclusão segue que princípio?","opcoes":[{"id":"a","texto":"É decidida em reunião secreta dos líderes"},{"id":"b","texto":"É baseada igualmente nas ordens de Cristo e na Palavra de Deus"},{"id":"c","texto":"É automática após certo período de ausência"},{"id":"d","texto":"Depende do voto da Conferência Geral"}],"resposta_correta":"b","explicacao":"Assim como a recepção segue o padrão de Cristo, a exclusão também é baseada igualmente nas ordens de Cristo e na autoridade das Escrituras Sagradas.","referencias":[{"texto":"1 Co 5:11-13","livro":"1 Co","capitulo":5,"versiculo":"11-13","conteudo":"Mas agora vos escrevi, que não vos associeis com ninguém que, dizendo-se irmão, for fornicador, ou avarento, ou idólatra, ou maldizente, ou beberrão, ou roubador; com esse tal nem comais. Porque que tenho eu em julgar também os que estão fora? Não julgais vós os que estão dentro? Aos que estão fora Deus os julgará. Tirai, pois, dentre vós a esse iníquo."}]},{"id":"q4","numero":4,"texto":"A exclusão dissolve o quê entre os membros?","opcoes":[{"id":"a","texto":"Apenas os compromissos financeiros"},{"id":"b","texto":"A irmandade em Cristo"},{"id":"c","texto":"Somente os laços sociais"},{"id":"d","texto":"Todas as formas de comunicação"}],"resposta_correta":"b","explicacao":"A exclusão dissolve a irmandade em Cristo entre os membros, interrompendo a comunhão espiritual que havia sido estabelecida no batismo.","referencias":[{"texto":"1 Co 5:11-13","livro":"1 Co","capitulo":5,"versiculo":"11-13","conteudo":"Mas agora vos escrevi, que não vos associeis com ninguém que, dizendo-se irmão, for fornicador, ou avarento, ou idólatra, ou maldizente, ou beberrão, ou roubador; com esse tal nem comais. Porque que tenho eu em julgar também os que estão fora? Não julgais vós os que estão dentro? Aos que estão fora Deus os julgará. Tirai, pois, dentre vós a esse iníquo."}]},{"id":"q5","numero":5,"texto":"A exclusão deve ser feita com base em que tipo de evidência?","opcoes":[{"id":"a","texto":"Rumores e testemunhos não confirmados"},{"id":"b","texto":"Proceder aberto e contínuo contrário à fé — não por acusações sem prova"},{"id":"c","texto":"Qualquer denúncia de outro membro"},{"id":"d","texto":"Avaliação subjetiva do pastor"}],"resposta_correta":"b","explicacao":"A exclusão deve basear-se em proceder aberto e contínuo contrário à fé, nunca em acusações sem prova verificada ou em rumores não confirmados.","referencias":[{"texto":"1 Tm 1:19-20","livro":"1 Tm","capitulo":1,"versiculo":"19-20","conteudo":"Mantendo fé e boa consciência, que alguns rejeitaram e naufragaram na fé. Entre os quais estão Himeneu e Alexandre, que entreguei a Satanás, para que aprendam a não blasfemar."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a exclusão é necessária quando a apostasia é clara."},{"id":"cf2","texto":"Reconheço que a exclusão busca preservar a pureza da Igreja."},{"id":"cf3","texto":"Desejo permanecer fiel para não ser necessária minha exclusão."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 28, 'Dízimo', 'A Santa Propriedade do Senhor Dedicada ao Ministério', 'O dízimo foi ordenado por Deus no princípio da obra da salvação e vigora tanto no Velho como no Novo Testamento. O dízimo não é uma oferta, mas a santa propriedade do Senhor. É empregado exclusivamente para a proclamação do Evangelho pelo ministério. A retenção do dízimo é uma fraude que resulta em maldição. O dízimo deve ser dado de todos os bens e de toda renda com que Deus nos abençoou.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Por quem foi ordenada a entrega do dízimo?","opcoes":[{"id":"a","texto":"Pelos apóstolos no Novo Testamento apenas"},{"id":"b","texto":"Por Deus, no princípio da obra da salvação, tanto no Velho como no Novo Testamento"},{"id":"c","texto":"Pela Igreja medieval como fonte de receita"},{"id":"d","texto":"Pelos profetas de Israel como tradição cultural"}],"resposta_correta":"b","explicacao":"O dízimo foi ordenado por Deus no princípio da obra da salvação e permanece vigente tanto no Velho como no Novo Testamento.","referencias":[{"texto":"Gn 14:18-20","livro":"Gn","capitulo":14,"versiculo":"18-20","conteudo":"E Melquisedeque, rei de Salém, trouxe pão e vinho; pois era sacerdote do Deus Altíssimo. E abençoou-o, e disse: Bendito seja Abrão pelo Deus Altíssimo, que entregou os teus inimigos nas tuas mãos. E deu-lhe o dízimo de tudo."},{"texto":"Nm 18:20-24","livro":"Nm","capitulo":18,"versiculo":"20-24","conteudo":"E o Senhor disse a Arão: Na sua terra não terás herança, nem entre eles terás parte; eu sou a tua parte e a tua herança entre os filhos de Israel."},{"texto":"1 Co 9:7-14","livro":"1 Co","capitulo":9,"versiculo":"7-14","conteudo":"Quem jamais vai à guerra à sua própria custa? Quem planta uma vinha, e não come do seu fruto? Ou quem apascenta um rebanho, e não come do leite do rebanho? Acaso não falo isto como homem? Ou não diz a lei o mesmo? Pois na lei de Moisés está escrito: Não colocarás focinheira ao boi que está malhando. Porventura, Deus cuida dos bois? Ou o diz totalmente por causa de nós?"}]},{"id":"q2","numero":2,"texto":"O dízimo é uma oferta?","opcoes":[{"id":"a","texto":"Sim, é a principal oferta do cristão"},{"id":"b","texto":"Não — o dízimo não é uma oferta, mas a santa propriedade do Senhor"},{"id":"c","texto":"Depende da intenção de quem o entrega"},{"id":"d","texto":"É oferta quando voluntário e dízimo quando obrigatório"}],"resposta_correta":"b","explicacao":"O dízimo não é uma oferta voluntária, mas a propriedade sagrada do Senhor, um reconhecimento de que Deus é o proprietário de tudo.","referencias":[{"texto":"Ml 3:6-18","livro":"Ml","capitulo":3,"versiculo":"6-18","conteudo":"Porque eu, o Senhor, não mudo; por isso vós, filhos de Jacó, não sois consumidos. Desde os dias de vossos pais vos desviastes dos meus decretos, e não os guardastes. Tornai-vos para mim, e eu me tornarei para vós, diz o Senhor dos Exércitos. Mas vós dizeis: Em que havemos de nos tornar? Roubar-me-á o homem a Deus? Todavia vós me roubais, e dizeis: Em que te roubamos? Nos dízimos e nas ofertas. Com maldição sois amaldiçoados, porque a mim me roubais, vós, toda esta nação."}]},{"id":"q3","numero":3,"texto":"Para que é empregado exclusivamente o dízimo?","opcoes":[{"id":"a","texto":"Para qualquer necessidade da Igreja"},{"id":"b","texto":"Somente para a proclamação do Evangelho pelo ministério"},{"id":"c","texto":"Para construção e manutenção de templos"},{"id":"d","texto":"Para obras sociais e assistência aos pobres"}],"resposta_correta":"b","explicacao":"O dízimo é empregado exclusivamente para a proclamação do Evangelho pelo ministério, conforme estabelecido nas Escrituras.","referencias":[{"texto":"1 Co 9:7-14","livro":"1 Co","capitulo":9,"versiculo":"7-14","conteudo":"Quem jamais vai à guerra à sua própria custa? Quem planta uma vinha, e não come do seu fruto? Ou quem apascenta um rebanho, e não come do leite do rebanho? Acaso não falo isto como homem? Ou não diz a lei o mesmo? Pois na lei de Moisés está escrito: Não colocarás focinheira ao boi que está malhando. Porventura, Deus cuida dos bois? Ou o diz totalmente por causa de nós?"},{"texto":"2 Co 11:8","livro":"2 Co","capitulo":11,"versiculo":"8","conteudo":"De outras igrejas tirei o sustento para vos servir, e, estando convosco e tendo necessidade, a ninguém fui pesado."}]},{"id":"q4","numero":4,"texto":"O que resulta da retenção do dízimo segundo Malaquias?","opcoes":[{"id":"a","texto":"Nenhuma consequência espiritual"},{"id":"b","texto":"Uma fraude que resulta em maldição"},{"id":"c","texto":"Apenas uma falta administrativa"},{"id":"d","texto":"Atraso no crescimento espiritual pessoal"}],"resposta_correta":"b","explicacao":"A retenção do dízimo constitui fraude contra Deus e resulta em maldição, conforme advertência clara de Malaquias 3.","referencias":[{"texto":"Ml 3:6-18","livro":"Ml","capitulo":3,"versiculo":"6-18","conteudo":"Porque eu, o Senhor, não mudo; por isso vós, filhos de Jacó, não sois consumidos. Desde os dias de vossos pais vos desviastes dos meus decretos, e não os guardastes. Tornai-vos para mim, e eu me tornarei para vós, diz o Senhor dos Exércitos. Mas vós dizeis: Em que havemos de nos tornar? Roubar-me-á o homem a Deus? Todavia vós me roubais, e dizeis: Em que te roubamos? Nos dízimos e nas ofertas. Com maldição sois amaldiçoados, porque a mim me roubais, vós, toda esta nação."}]},{"id":"q5","numero":5,"texto":"De que deve o crente dar o dízimo?","opcoes":[{"id":"a","texto":"Somente do salário mensal"},{"id":"b","texto":"De todos os seus bens e de toda renda com que Deus o abençoou"},{"id":"c","texto":"Apenas do lucro líquido após despesas"},{"id":"d","texto":"Somente quando tiver abundância"}],"resposta_correta":"b","explicacao":"O crente deve dar dízimo de todos os seus bens e de toda renda com que Deus o abençoou, reconhecendo Sua provisão contínua.","referencias":[{"texto":"Ne 13:10-12","livro":"Ne","capitulo":13,"versiculo":"10-12","conteudo":"Descobri também que as porções dos levitas não lhes tinham sido dadas; e tanto os levitas como os cantores, que faziam a obra, tinham fugido cada um para a sua terra. Então repreendi os magistrados, dizendo: Por que está a casa de Deus desamparada? E reuni-os, e os coloquei no seu lugar."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que o dízimo é a propriedade do Senhor."},{"id":"cf2","texto":"Reconheço o privilégio de sustentar o ministério através do dízimo."},{"id":"cf3","texto":"Desejo ser fiel na entrega do dízimo como ato de adoração."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 29, 'Ofertas Voluntárias', 'Contribuições de Coração Generoso ao Trabalho de Deus', 'As ofertas voluntárias são meios ordenados pelo Senhor para ajudar dentro e fora da Igreja. As ofertas do primeiro dia da semana são destinadas aos pobres da Igreja. A coleta da Escola Sabatina destina-se a espalhar os princípios da fé oralmente e por escrito. As ofertas missionárias são contribuições voluntárias dos membros e não-membros para a missão de Deus.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"As ofertas voluntárias são meios ordenados por quem?","opcoes":[{"id":"a","texto":"Pela liderança da Igreja local"},{"id":"b","texto":"Pelo Senhor, para ajudar dentro e fora da Igreja"},{"id":"c","texto":"Pelos tesoureiros para cobrir despesas"},{"id":"d","texto":"Pelos diáconos para manter os prédios"}],"resposta_correta":"b","explicacao":"As ofertas voluntárias são meios ordenados pelo Senhor especificamente para ajudar necessitados tanto dentro quanto fora da Igreja.","referencias":[{"texto":"Lc 6:30-36","livro":"Lc","capitulo":6,"versiculo":"30-36","conteudo":"A todo o que te pedir, dá-lhe; e ao que tomar o que é teu, não o reclames. E como quereis que vos façam, assim fazei vós também a outros."},{"texto":"Dt 15:1-15","livro":"Dt","capitulo":15,"versiculo":"1-15","conteudo":"De sete em sete anos farás remissão. E este é o modo da remissão: todo o possuidor de algo que emprestou a seu próximo, perdoará o débito; não o cobrará mais a seu próximo, nem a seu irmão, porque se tem proclamado remissão ao Senhor."}]},{"id":"q2","numero":2,"texto":"As ofertas do primeiro dia da semana são destinadas a quem?","opcoes":[{"id":"a","texto":"Ao fundo de construção da Igreja"},{"id":"b","texto":"Aos pobres da Igreja, segundo 1 Coríntios 16:1-3"},{"id":"c","texto":"Ao pastor como remuneração extra"},{"id":"d","texto":"Ao fundo missionário internacional"}],"resposta_correta":"b","explicacao":"As ofertas do primeiro dia da semana (domingo) são destinadas aos pobres da Igreja conforme instrução do apóstolo Paulo em 1 Coríntios.","referencias":[{"texto":"1 Co 16:1-3","livro":"1 Co","capitulo":16,"versiculo":"1-3","conteudo":"Quanto à coleta para os santos, fazei vós também como ordenei às igrejas da Galácia. No primeiro dia da semana, cada um de vós ponha de parte o que puder poupar, conforme a sua prosperidade, para que não haja coletas quando eu chegar."},{"texto":"Gl 6:9-10","livro":"Gl","capitulo":6,"versiculo":"9-10","conteudo":"E não nos cansemos de fazer bem; porque a seu tempo ceifaremos, se não desfalecermos. Portanto, enquanto temos oportunidade, façamos bem a todos, principalmente aos domésticos da fé."}]},{"id":"q3","numero":3,"texto":"A coleta da Escola Sabatina destina-se a quê?","opcoes":[{"id":"a","texto":"Ao sustento dos professores da Escola"},{"id":"b","texto":"A espalhar os princípios da fé oralmente e por escrito"},{"id":"c","texto":"Ao fundo de reserva da Igreja"},{"id":"d","texto":"À compra de materiais didáticos"}],"resposta_correta":"b","explicacao":"A coleta da Escola Sabatina destina-se a espalhar os princípios da fé oralmente e por escrito através de recursos educacionais e publicações.","referencias":[{"texto":"Lc 6:30-36","livro":"Lc","capitulo":6,"versiculo":"30-36","conteudo":"A todo o que te pedir, dá-lhe; e ao que tomar o que é teu, não o reclames. E como quereis que vos façam, assim fazei vós também a outros."}]},{"id":"q4","numero":4,"texto":"As ofertas missionárias são contribuições de quem?","opcoes":[{"id":"a","texto":"Somente dos membros mais abastados"},{"id":"b","texto":"Voluntárias, dos membros e dos não-membros, empregadas em prol da missão"},{"id":"c","texto":"Obrigatórias de todos os membros batizados"},{"id":"d","texto":"Exclusivas dos líderes e oficiais da Igreja"}],"resposta_correta":"b","explicacao":"As ofertas missionárias são contribuições voluntárias tanto de membros quanto de não-membros, utilizadas em prol da missão de levar o Evangelho.","referencias":[{"texto":"Dt 15:1-15","livro":"Dt","capitulo":15,"versiculo":"1-15","conteudo":"De sete em sete anos farás remissão. E este é o modo da remissão: todo o possuidor de algo que emprestou a seu próximo, perdoará o débito; não o cobrará mais a seu próximo, nem a seu irmão, porque se tem proclamado remissão ao Senhor."}]},{"id":"q5","numero":5,"texto":"As coletas gerais levantadas na saída das reuniões são usadas para quê?","opcoes":[{"id":"a","texto":"Para o fundo missionário"},{"id":"b","texto":"Para cobrir despesas de aluguel, calefação da sala de reunião e celebração da Santa Ceia"},{"id":"c","texto":"Para pagar o pastor e os anciãos"},{"id":"d","texto":"Para obras sociais na comunidade"}],"resposta_correta":"b","explicacao":"As coletas gerais levantadas na saída das reuniões cobrem despesas de aluguel, calefação da sala de reunião e necessários para celebrar a Santa Ceia.","referencias":[{"texto":"Lc 6:30-36","livro":"Lc","capitulo":6,"versiculo":"30-36","conteudo":"A todo o que te pedir, dá-lhe; e ao que tomar o que é teu, não o reclames. E como quereis que vos façam, assim fazei vós também a outros."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que as ofertas expressam meu amor a Deus."},{"id":"cf2","texto":"Reconheço a importância de contribuir voluntariamente para a obra."},{"id":"cf3","texto":"Desejo ser generoso e compassivo com os necessitados."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 30, 'Juramento', 'A Veracidade e a Palavra Confiável do Cristão', 'O juramento falso e desnecessário é abominável a Deus. A palavra do verdadeiro crente em geral deve ser: sim, sim; não, não. Deus permite o juramento necessário quando se invoca a Deus como testemunha de que o que se diz é verdade. Paulo invocou a Deus como testemunha de que dizia a verdade. Segundo Mateus 5:34-37, Jesus ensinou que não devemos jurar de modo algum.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O juramento falso e desnecessário é o quê perante Deus?","opcoes":[{"id":"a","texto":"Apenas uma falta leve"},{"id":"b","texto":"Abominável a Deus"},{"id":"c","texto":"Aceitável em determinadas circunstâncias"},{"id":"d","texto":"Irrelevante para a vida espiritual"}],"resposta_correta":"b","explicacao":"O juramento falso e desnecessário é abominável a Deus, pois viola a verdade que deve caracterizar todo discípulo genuíno de Cristo.","referencias":[{"texto":"Mt 5:34-37","livro":"Mt","capitulo":5,"versiculo":"34-37","conteudo":"Eu, porém, vos digo que não jureis de maneira nenhuma; nem pelo céu, porque é o trono de Deus; nem pela terra, porque é o escabelo de seus pés; nem por Jerusalém, porque é a cidade do grande Rei. Nem jures pela tua cabeça, porque não podes fazer um só cabelo branco ou preto. Seja, porém, o vosso falar: Sim, sim; Não, não; porque o que passa disto vem do mal."},{"texto":"Tg 5:12","livro":"Tg","capitulo":5,"versiculo":"12","conteudo":"Mas, sobretudo, meus irmãos, não jureis, nem pelo céu, nem pela terra, nem por qualquer outro juramento; seja, porém, o vosso sim, sim, e o vosso não, não; para que não caiais em condenação."}]},{"id":"q2","numero":2,"texto":"Qual é a palavra do verdadeiro crente em geral?","opcoes":[{"id":"a","texto":"Depende da situação e das circunstâncias"},{"id":"b","texto":"Sim, sim; não, não"},{"id":"c","texto":"Uma promessa formal com testemunhas"},{"id":"d","texto":"Um compromisso escrito e assinado"}],"resposta_correta":"b","explicacao":"A palavra do verdadeiro crente em geral é caracterizada por sinceridade absoluta: sim significa sim e não significa não, sem necessidade de juramentos.","referencias":[{"texto":"Mt 5:34-37","livro":"Mt","capitulo":5,"versiculo":"34-37","conteudo":"Eu, porém, vos digo que não jureis de maneira nenhuma; nem pelo céu, porque é o trono de Deus; nem pela terra, porque é o escabelo de seus pés; nem por Jerusalém, porque é a cidade do grande Rei. Nem jures pela tua cabeça, porque não podes fazer um só cabelo branco ou preto. Seja, porém, o vosso falar: Sim, sim; Não, não; porque o que passa disto vem do mal."}]},{"id":"q3","numero":3,"texto":"Deus permite o juramento necessário em que condição?","opcoes":[{"id":"a","texto":"Nunca, em nenhuma circunstância"},{"id":"b","texto":"De acordo com o Evangelho — quando se invoca a Deus como testemunha de que o que se diz é verdade"},{"id":"c","texto":"Somente perante tribunais civis"},{"id":"d","texto":"Apenas perante a Igreja"}],"resposta_correta":"b","explicacao":"Deus permite o juramento necessário conforme o Evangelho, quando se invoca legitimamente a Deus como testemunha de que o que se afirma é verdade.","referencias":[{"texto":"Rm 1:9","livro":"Rm","capitulo":1,"versiculo":"9","conteudo":"Porque Deus, a quem sirvo em meu espírito, no evangelho de seu Filho, é minha testemunha de como continuamente faço menção de vós em minhas orações."},{"texto":"2 Co 1:23","livro":"2 Co","capitulo":1,"versiculo":"23","conteudo":"Mas eu tomo a Deus por testemunha da minha alma, de que é unicamente para vos poupar que ainda não voltei a Corinto."},{"texto":"Gl 1:20","livro":"Gl","capitulo":1,"versiculo":"20","conteudo":"Ora, naquilo que vos escrevo, eis que diante de Deus, não minto."}]},{"id":"q4","numero":4,"texto":"O que Paulo fez em suas epístolas que demonstra o juramento permitido?","opcoes":[{"id":"a","texto":"Prometeu riquezas aos fiéis"},{"id":"b","texto":"Invocou a Deus como testemunha de que dizia a verdade"},{"id":"c","texto":"Amaldiçoou os que duvidavam dele"},{"id":"d","texto":"Pediu garantias financeiras das igrejas"}],"resposta_correta":"b","explicacao":"Paulo invocou a Deus como testemunha em suas epístolas, demonstrando que juramentos necessários e solenes são permitidos no contexto apropriado.","referencias":[{"texto":"Rm 1:9","livro":"Rm","capitulo":1,"versiculo":"9","conteudo":"Porque Deus, a quem sirvo em meu espírito, no evangelho de seu Filho, é minha testemunha de como continuamente faço menção de vós em minhas orações."},{"texto":"2 Co 1:23","livro":"2 Co","capitulo":1,"versiculo":"23","conteudo":"Mas eu tomo a Deus por testemunha da minha alma, de que é unicamente para vos poupar que ainda não voltei a Corinto."},{"texto":"Gl 1:20","livro":"Gl","capitulo":1,"versiculo":"20","conteudo":"Ora, naquilo que vos escrevo, eis que diante de Deus, não minto."}]},{"id":"q5","numero":5,"texto":"Segundo Mateus 5:34-37, o que Jesus ensinou sobre juramentos?","opcoes":[{"id":"a","texto":"Que todo juramento é válido se feito com sinceridade"},{"id":"b","texto":"Que não devemos jurar de modo algum — que o nosso sim seja sim e o nosso não seja não"},{"id":"c","texto":"Que juramentos são obrigatórios em contratos"},{"id":"d","texto":"Que somente anciãos podem fazer juramentos"}],"resposta_correta":"b","explicacao":"Jesus ensinou em Mateus 5:34-37 que não devemos jurar de modo algum; nosso compromisso deve ser de tal integridade que nossa palavra seja suficiente.","referencias":[{"texto":"Mt 5:34-37","livro":"Mt","capitulo":5,"versiculo":"34-37","conteudo":"Eu, porém, vos digo que não jureis de maneira nenhuma; nem pelo céu, porque é o trono de Deus; nem pela terra, porque é o escabelo de seus pés; nem por Jerusalém, porque é a cidade do grande Rei. Nem jures pela tua cabeça, porque não podes fazer um só cabelo branco ou preto. Seja, porém, o vosso falar: Sim, sim; Não, não; porque o que passa disto vem do mal."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio na importância de uma vida de verdade e honestidade."},{"id":"cf2","texto":"Reconheço que minha palavra deve ser confiável e digna."},{"id":"cf3","texto":"Desejo viver em total transparência e integridade moral."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 31, 'Pregação do Evangelho', 'A Proclamação Universal da Mensagem de Salvação', 'A ordem do Senhor que vigora especialmente hoje é: Ide, ensinai todas as nações, batizando-as em nome do Pai, do Filho e do Espírito Santo. Proclamamos o Evangelho verbalmente e por meio de publicações. Todos os membros da Igreja sentem a obrigação de participar. A Grande Comissão vigora até a consumação do mundo, todos os dias.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Qual é a ordem do Senhor que vigora especialmente hoje?","opcoes":[{"id":"a","texto":"Construir templos em todas as nações"},{"id":"b","texto":"Ide, ensinai todas as nações, batizando-as em nome do Pai, do Filho e do Espírito Santo"},{"id":"c","texto":"Guardar o Sábado em silêncio e solidão"},{"id":"d","texto":"Estabelecer escolas em todos os países"}],"resposta_correta":"b","explicacao":"A Grande Comissão de ir, ensinar e batizar todas as nações é a ordem central que o Senhor deixou e que vigora especialmente nos últimos dias.","referencias":[{"texto":"Mt 28:19-20","livro":"Mt","capitulo":28,"versiculo":"19-20","conteudo":"Portanto, ide, ensinai todas as nações, batizando-as em nome do Pai, e do Filho, e do Espírito Santo; ensinando-as a guardar todas as coisas que vos tenho mandado; e eis que eu estou convosco todos os dias, até à consumação dos séculos. Amém."}]},{"id":"q2","numero":2,"texto":"De que formas devemos proclamar o Evangelho?","opcoes":[{"id":"a","texto":"Somente por meio de sermões nos cultos"},{"id":"b","texto":"Verbalmente e por meio de publicações"},{"id":"c","texto":"Apenas por meio de redes sociais"},{"id":"d","texto":"Somente quando solicitados"}],"resposta_correta":"b","explicacao":"O Evangelho deve ser proclamado tanto verbalmente através da pregação quanto por publicações escritas e diversos meios de comunicação disponíveis.","referencias":[{"texto":"Mc 16:15-16","livro":"Mc","capitulo":16,"versiculo":"15-16","conteudo":"E disse-lhes: Ide por todo o mundo, pregai o evangelho a toda criatura. Quem crer e for batizado será salvo; mas quem não crer será condenado."},{"texto":"Ec 11:1-6","livro":"Ec","capitulo":11,"versiculo":"1-6","conteudo":"Lança o teu pão sobre as águas; porque depois de muitos dias o encontrarás. Reparte com sete, e até com oito; porque não sabes qual mal virá sobre a terra."},{"texto":"Mt 11:29-30","livro":"Mt","capitulo":11,"versiculo":"29-30","conteudo":"Tomai sobre vós o meu jugo, e aprendei de mim, que sou manso e humilde de coração; e encontrareis descanso para as vossas almas. Porque o meu jugo é suave e o meu fardo é leve."}]},{"id":"q3","numero":3,"texto":"Quem tem a obrigação de participar da proclamação?","opcoes":[{"id":"a","texto":"Somente os pastores e missionários"},{"id":"b","texto":"Todos os membros da Igreja sentem a obrigação"},{"id":"c","texto":"Apenas os que têm dom de pregação"},{"id":"d","texto":"Somente os que recebem remuneração para isso"}],"resposta_correta":"b","explicacao":"Todos os membros da Igreja sentem a obrigação pessoal de participar na proclamação do Evangelho, não apenas pastores e obreiros remunerados.","referencias":[{"texto":"Mc 16:15-16","livro":"Mc","capitulo":16,"versiculo":"15-16","conteudo":"E disse-lhes: Ide por todo o mundo, pregai o evangelho a toda criatura. Quem crer e for batizado será salvo; mas quem não crer será condenado."}]},{"id":"q4","numero":4,"texto":"Até quando vigora a Grande Comissão de Mateus 28:19-20?","opcoes":[{"id":"a","texto":"Até que todas as nações sejam cristãs"},{"id":"b","texto":"Até a consumação do mundo — todos os dias"},{"id":"c","texto":"Até o próximo concílio da Conferência Geral"},{"id":"d","texto":"Até que não haja mais pagãos no mundo"}],"resposta_correta":"b","explicacao":"A Grande Comissão vigora até a consumação do mundo, significa todos os dias até o retorno de Cristo, sem limite de tempo ou condição.","referencias":[{"texto":"Mt 28:19-20","livro":"Mt","capitulo":28,"versiculo":"19-20","conteudo":"Portanto, ide, ensinai todas as nações, batizando-as em nome do Pai, e do Filho, e do Espírito Santo; ensinando-as a guardar todas as coisas que vos tenho mandado; e eis que eu estou convosco todos os dias, até à consumação dos séculos. Amém."}]},{"id":"q5","numero":5,"texto":"Além de ensinar, o que deve acompanhar a pregação do Evangelho?","opcoes":[{"id":"a","texto":"A construção de hospitais e escolas"},{"id":"b","texto":"O ensino a guardar todas as coisas que Jesus mandou"},{"id":"c","texto":"A distribuição de alimentos e roupas"},{"id":"d","texto":"A organização de eventos sociais"}],"resposta_correta":"b","explicacao":"Além de ensinar a verdade evangélica, deve-se ensinar aos conversos a guardar todas as coisas que Cristo mandou, formando discípulos completos.","referencias":[{"texto":"Mt 28:19-20","livro":"Mt","capitulo":28,"versiculo":"19-20","conteudo":"Portanto, ide, ensinai todas as nações, batizando-as em nome do Pai, e do Filho, e do Espírito Santo; ensinando-as a guardar todas as coisas que vos tenho mandado; e eis que eu estou convosco todos os dias, até à consumação dos séculos. Amém."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a pregação é a grande comissão de Cristo."},{"id":"cf2","texto":"Reconheço meu dever pessoal de compartilhar a fé."},{"id":"cf3","texto":"Desejo ser instrumento de Deus na proclamação do Evangelho."}]'::jsonb)
