INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 32, 'Obediência e Submissão', 'A Sujeição à Liderança Fiel da Igreja', 'Os membros devem submeter-se à ordem da Igreja e às determinações dos dirigentes e oficiais enquanto estes permanecerem fiéis aos princípios de fé segundo a Palavra de Deus. A submissão baseia-se fundamentalmente na fidelidade dos dirigentes à Palavra de Deus. Se os dirigentes se desviarem dos princípios de fé, a obrigação de submissão cessa, pois a fidelidade a Deus é superior.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Os membros da Igreja devem submeter-se a quê?","opcoes":[{"id":"a","texto":"Às tradições culturais de cada região"},{"id":"b","texto":"À ordem da Igreja e às determinações dos dirigentes e oficiais"},{"id":"c","texto":"Às opiniões pessoais dos membros mais antigos"},{"id":"d","texto":"Somente à sua própria consciência individual"}],"resposta_correta":"b","explicacao":"Os membros da Igreja devem submeter-se à ordem da Igreja e às determinações de seus dirigentes e oficiais quando estão em harmonia com a Palavra de Deus.","referencias":[{"texto":"Hb 13:7,17","livro":"Hb","capitulo":13,"versiculo":"7","conteudo":"Texto bíblico indisponível"},{"texto":"1 Ts 5:12-13","livro":"1 Ts","capitulo":5,"versiculo":"12-13","conteudo":"E vos rogamos, irmãos, que reconheçais os que trabalham entre vós, e vos presidem no Senhor, e vos admoestam. E que os tenhais em grande estima e amor, pela sua obra. Tende paz uns com os outros."}]},{"id":"q2","numero":2,"texto":"Até quando os membros devem seguir as determinações dos dirigentes?","opcoes":[{"id":"a","texto":"Sempre, sem questionar"},{"id":"b","texto":"Enquanto estes permanecem fiéis aos princípios de fé segundo a Palavra de Deus"},{"id":"c","texto":"Enquanto forem populares entre os membros"},{"id":"d","texto":"Até que surjam novos líderes"}],"resposta_correta":"b","explicacao":"A submissão dos membros é válida enquanto os dirigentes permanecem fiéis aos princípios de fé segundo a Palavra de Deus.","referencias":[{"texto":"Hb 13:7,17","livro":"Hb","capitulo":13,"versiculo":"7","conteudo":"Texto bíblico indisponível"},{"texto":"1 Ts 5:12-13","livro":"1 Ts","capitulo":5,"versiculo":"12-13","conteudo":"E vos rogamos, irmãos, que reconheçais os que trabalham entre vós, e vos presidem no Senhor, e vos admoestam. E que os tenhais em grande estima e amor, pela sua obra. Tende paz uns com os outros."}]},{"id":"q3","numero":3,"texto":"A submissão é baseada em quê fundamentalmente?","opcoes":[{"id":"a","texto":"Na hierarquia administrativa da Igreja"},{"id":"b","texto":"Na fidelidade dos dirigentes à Palavra de Deus"},{"id":"c","texto":"Na antiguidade dos líderes no cargo"},{"id":"d","texto":"Na formação teológica dos oficiais"}],"resposta_correta":"b","explicacao":"A submissão é fundamentalmente baseada na fidelidade dos dirigentes à Palavra de Deus, não na hierarquia administrativa ou na autoridade humana em si.","referencias":[{"texto":"Hb 13:7,17","livro":"Hb","capitulo":13,"versiculo":"7","conteudo":"Texto bíblico indisponível"}]},{"id":"q4","numero":4,"texto":"O que acontece se os dirigentes se desviarem dos princípios de fé?","opcoes":[{"id":"a","texto":"Os membros devem continuar obedecendo"},{"id":"b","texto":"A obrigação de submissão cessa, pois a fidelidade a Deus é superior"},{"id":"c","texto":"Os membros devem sair da Igreja imediatamente"},{"id":"d","texto":"Nada muda na relação de submissão"}],"resposta_correta":"b","explicacao":"Se os dirigentes se desviam dos princípios de fé, a obrigação de submissão cessa, pois a fidelidade a Deus é sempre superior à obediência a líderes falhos.","referencias":[{"texto":"Hb 13:7,17","livro":"Hb","capitulo":13,"versiculo":"7","conteudo":"Texto bíblico indisponível"},{"texto":"1 Ts 5:12-13","livro":"1 Ts","capitulo":5,"versiculo":"12-13","conteudo":"E vos rogamos, irmãos, que reconheçais os que trabalham entre vós, e vos presidem no Senhor, e vos admoestam. E que os tenhais em grande estima e amor, pela sua obra. Tende paz uns com os outros."}]},{"id":"q5","numero":5,"texto":"A obediência e submissão na Igreja são exercícios de quê?","opcoes":[{"id":"a","texto":"De disciplina militar"},{"id":"b","texto":"De fé e confiança na organização que Deus estabeleceu"},{"id":"c","texto":"De tradição cultural religiosa"},{"id":"d","texto":"De dependência dos líderes humanos"}],"resposta_correta":"b","explicacao":"A obediência e submissão na Igreja são exercícios de fé e confiança genuína na organização que Deus estabeleceu, não de medo ou dependência humana.","referencias":[{"texto":"Hb 13:7,17","livro":"Hb","capitulo":13,"versiculo":"7","conteudo":"Texto bíblico indisponível"},{"texto":"1 Ts 5:12-13","livro":"1 Ts","capitulo":5,"versiculo":"12-13","conteudo":"E vos rogamos, irmãos, que reconheçais os que trabalham entre vós, e vos presidem no Senhor, e vos admoestam. E que os tenhais em grande estima e amor, pela sua obra. Tende paz uns com os outros."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio na autoridade apropriada dos líderes da Igreja."},{"id":"cf2","texto":"Reconheço que a submissão deve basear-se na fidelidade bíblica."},{"id":"cf3","texto":"Desejo obedecer aos líderes que me guiam em verdade."}]'::jsonb)
