INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 33, 'A Segunda Vinda de Cristo', 'O Retorno Pessoal e Visível do Rei', 'A segunda vinda de Cristo está muito próxima. Será pessoal e visível — Cristo virá com grande poder e glória acompanhado de Seus santos anjos. Os que morreram em Cristo ressuscitarão primeiro, e os vivos fiéis serão transformados instantaneamente e arrebatados ao encontro do Senhor nos ares. Esta é a esperança abençoada da Igreja.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"A segunda vinda de Cristo está próxima ou distante?","opcoes":[{"id":"a","texto":"Está muito distante no futuro"},{"id":"b","texto":"Está muito próxima"},{"id":"c","texto":"Não há como saber"},{"id":"d","texto":"Depende do cumprimento de certas condições"}],"resposta_correta":"b","explicacao":"A segunda vinda de Cristo está muito próxima, conforme indicam os sinais nos céus e na terra que Jesus descreveu como precedentes de Seu retorno.","referencias":[{"texto":"Lc 21:25-27","livro":"Lc","capitulo":21,"versiculo":"25-27","conteudo":"E haverá sinais no sol, e na lua, e nas estrelas; e na terra angústia das nações, em perplexidade pelo bramido do mar e das ondas; desfalecendo os homens de medo, na expectação das coisas que sobrevirão ao mundo; porque as virtudes do céu serão abaladas. Então verão o Filho do Homem vindo numa nuvem com poder e grande glória."},{"texto":"Mt 24:3-14","livro":"Mt","capitulo":24,"versiculo":"3-14","conteudo":"E, estando assentado no Monte das Oliveiras, chegaram-se a ele os seus discípulos em particular, dizendo: Dize-nos, quando serão essas coisas? E qual será o sinal da tua vinda, e do fim do mundo?"}]},{"id":"q2","numero":2,"texto":"Como será a segunda vinda de Cristo?","opcoes":[{"id":"a","texto":"Secreta e invisível, apenas espiritual"},{"id":"b","texto":"Pessoal e visível — Cristo virá com grande poder e glória"},{"id":"c","texto":"Simbólica, representando uma mudança de era"},{"id":"d","texto":"Gradual, ao longo de muitos anos"}],"resposta_correta":"b","explicacao":"A segunda vinda de Cristo será pessoal e visível; Ele virá com grande poder e glória de forma visível a todo olho, não secreta ou apenas espiritual.","referencias":[{"texto":"Mt 24:30","livro":"Mt","capitulo":24,"versiculo":"30","conteudo":"Então aparecerá no céu o sinal do Filho do Homem; e então todas as tribos da terra se lamentarão, e verão o Filho do Homem vindo sobre as nuvens do céu, com poder e grande glória."},{"texto":"At 1:8-11","livro":"At","capitulo":1,"versiculo":"8-11","conteudo":"Mas recebereis a virtude do Espírito Santo, que há de vir sobre vós; e ser-me-eis testemunhas, tanto em Jerusalém como em toda a Judeia, e Samaria, e até aos confins da terra. E, dito isto, foi elevado às alturas, à vista deles, e uma nuvem o recebeu, ocultando-o a seus olhos. E estando com os olhos fitos no céu, enquanto ele subia, eis que se apresentaram dois homens vestidos de branco, que lhes disseram: Varões galileus, porque estais olhando para o céu? Esse Jesus, que de entre vós foi recebido no céu, há de vir assim como para o céu o vistes ir."}]},{"id":"q3","numero":3,"texto":"O que acontecerá com os que morreram em Cristo quando Ele voltar?","opcoes":[{"id":"a","texto":"Continuarão dormindo por mais mil anos"},{"id":"b","texto":"Ressuscitarão primeiro"},{"id":"c","texto":"Serão julgados antes de ressuscitar"},{"id":"d","texto":"Irão diretamente para a Nova Terra"}],"resposta_correta":"b","explicacao":"Os justos que morreram em Cristo ressuscitarão em primeiro lugar quando Ele voltar, precedendo a transformação dos vivos.","referencias":[{"texto":"1 Ts 4:15-17","livro":"1 Ts","capitulo":4,"versiculo":"15-17","conteudo":"Porque vos dizemos isto pela palavra do Senhor: que nós, os vivos, os que ficaremos até à vinda do Senhor, não precederemos os que já dormem. Porque o Senhor mesmo descerá do céu com alarido, e com a voz do arcanjo, e com a trombeta de Deus; e os mortos em Cristo ressuscitarão primeiro. Depois nós, os vivos, os que ficarmos, seremos arrebatados juntamente com eles nas nuvens, a encontrar o Senhor nos ares, e assim estaremos sempre com o Senhor."}]},{"id":"q4","numero":4,"texto":"O que acontecerá com os vivos fiéis na segunda vinda?","opcoes":[{"id":"a","texto":"Morrerão e ressuscitarão imediatamente"},{"id":"b","texto":"Serão transformados instantaneamente"},{"id":"c","texto":"Continuarão vivendo na Terra renovada"},{"id":"d","texto":"Serão levados gradualmente ao Céu"}],"resposta_correta":"b","explicacao":"Os vivos fiéis na segunda vinda serão transformados instantaneamente de morte para vida, recebendo corpos imortais sem passar pelo processo de morte.","referencias":[{"texto":"1 Co 15:51-52","livro":"1 Co","capitulo":15,"versiculo":"51-52","conteudo":"Eis que vos digo um mistério: Nem todos dormiremos, mas todos seremos transformados; num momento, num piscar de olhos, ao som da última trombeta; porque a trombeta soará, e os mortos ressuscitarão incorruptíveis, e nós seremos transformados."}]},{"id":"q5","numero":5,"texto":"Cristo virá acompanhado de quem?","opcoes":[{"id":"a","texto":"Somente do Espírito Santo"},{"id":"b","texto":"De grande poder e glória, com Seus santos anjos"},{"id":"c","texto":"De profetas ressuscitados"},{"id":"d","texto":"Somente de Moisés e Elias"}],"resposta_correta":"b","explicacao":"Cristo virá acompanhado de grande poder e glória, com Seus anjos santos, para executar juízo e levar Seus remidos para casa eternamente.","referencias":[{"texto":"Mt 16:27","livro":"Mt","capitulo":16,"versiculo":"27","conteudo":"Porque o Filho do Homem há de vir na glória de seu Pai, com seus anjos; e então pagará a cada um segundo as suas obras."},{"texto":"Mt 25:31","livro":"Mt","capitulo":25,"versiculo":"31","conteudo":"E quando o Filho do Homem vier em sua glória, e todos os anjos com ele, então se assentará no trono da sua glória."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que Jesus virá em breve para nos levar."},{"id":"cf2","texto":"Reconheço a urgência de preparar-me para Seu retorno."},{"id":"cf3","texto":"Desejo viver em constante esperança da segunda vinda."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 34, 'O Estado dos Mortos', 'A Inconsciência até a Ressurreição', 'Todos os mortos estão em estado de inconsciência e inatividade até a segunda vinda de Cristo. O homem não possui alma imortal. Os mortos não sabem coisa nenhuma e seus pensamentos perecem naquele mesmo dia. Até a hora da segunda vinda de Cristo os mortos permanecerão inconscientes, sem consciência ou conhecimento.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Em que estado se acham todos os mortos?","opcoes":[{"id":"a","texto":"Conscientes no céu ou no inferno"},{"id":"b","texto":"Em estado de inconsciência e inatividade até a segunda vinda de Cristo"},{"id":"c","texto":"Em purgatório aguardando intercessão"},{"id":"d","texto":"Em reencarnação em outros corpos"}],"resposta_correta":"b","explicacao":"Todos os mortos encontram-se em estado de inconsciência e inatividade completa até a segunda vinda de Cristo, quando a ressurreição ocorrerá.","referencias":[{"texto":"Ec 9:5-6","livro":"Ec","capitulo":9,"versiculo":"5-6","conteudo":"Porque os vivos sabem que hão de morrer, mas os mortos não sabem coisa nenhuma, nem tampouco terão eles mais recompensa; porque a sua memória é posta em esquecimento. Como também o seu amor, e o seu ódio, e a sua inveja, já pereceram; e já não têm mais parte nenhuma em tudo quanto se faz debaixo do sol."},{"texto":"Sl 146:4","livro":"Sl","capitulo":146,"versiculo":"4","conteudo":"Sai-lhe o espírito, e volta para a terra; naquele mesmo dia perecem todos os seus pensamentos."}]},{"id":"q2","numero":2,"texto":"O homem possui alma imortal?","opcoes":[{"id":"a","texto":"Sim, a alma sobrevive após a morte do corpo"},{"id":"b","texto":"Não — o homem não tem alma imortal"},{"id":"c","texto":"Depende de sua fidelidade a Deus em vida"},{"id":"d","texto":"Somente os justos possuem alma imortal"}],"resposta_correta":"b","explicacao":"O homem não possui alma imortal; o ser completo repousa na morte até a ressurreição, não havendo existência consciente entre a morte e a ressurreição.","referencias":[{"texto":"Ec 9:5-6","livro":"Ec","capitulo":9,"versiculo":"5-6","conteudo":"Porque os vivos sabem que hão de morrer, mas os mortos não sabem coisa nenhuma, nem tampouco terão eles mais recompensa; porque a sua memória é posta em esquecimento. Como também o seu amor, e o seu ódio, e a sua inveja, já pereceram; e já não têm mais parte nenhuma em tudo quanto se faz debaixo do sol."}]},{"id":"q3","numero":3,"texto":"Até quando os mortos permanecerão inconscientes?","opcoes":[{"id":"a","texto":"Até o julgamento final após o milênio"},{"id":"b","texto":"Até a hora da segunda vinda de Cristo"},{"id":"c","texto":"Eternamente, sem nunca mais despertar"},{"id":"d","texto":"Até que alguém interceda por eles"}],"resposta_correta":"b","explicacao":"Os mortos permanecerão inconscientes até a hora da segunda vinda de Cristo, quando haverá a ressurreição que Deus prometeu para Seus filhos fiéis.","referencias":[{"texto":"Ec 9:5-6","livro":"Ec","capitulo":9,"versiculo":"5-6","conteudo":"Porque os vivos sabem que hão de morrer, mas os mortos não sabem coisa nenhuma, nem tampouco terão eles mais recompensa; porque a sua memória é posta em esquecimento. Como também o seu amor, e o seu ódio, e a sua inveja, já pereceram; e já não têm mais parte nenhuma em tudo quanto se faz debaixo do sol."},{"texto":"Sl 146:4","livro":"Sl","capitulo":146,"versiculo":"4","conteudo":"Sai-lhe o espírito, e volta para a terra; naquele mesmo dia perecem todos os seus pensamentos."}]},{"id":"q4","numero":4,"texto":"Os mortos sabem alguma coisa segundo Eclesiastes 9:5?","opcoes":[{"id":"a","texto":"Sim, estão conscientes de tudo"},{"id":"b","texto":"Não — os mortos não sabem coisa nenhuma"},{"id":"c","texto":"Sabem apenas o que acontece com seus familiares"},{"id":"d","texto":"Têm consciência parcial em sonhos"}],"resposta_correta":"b","explicacao":"De acordo com Eclesiastes 9:5, os mortos absolutamente não sabem coisa nenhuma; todo conhecimento, sentimento e atividade cessam na morte.","referencias":[{"texto":"Ec 9:5","livro":"Ec","capitulo":9,"versiculo":"5","conteudo":"Porque os vivos sabem que hão de morrer, mas os mortos não sabem coisa nenhuma, nem tampouco terão eles mais recompensa; porque a sua memória é posta em esquecimento."}]},{"id":"q5","numero":5,"texto":"No dia da morte, o que acontece com os pensamentos do homem?","opcoes":[{"id":"a","texto":"Continuam em outro plano espiritual"},{"id":"b","texto":"Perecem — seus pensamentos perecem naquele mesmo dia"},{"id":"c","texto":"São transferidos para os anjos guardiões"},{"id":"d","texto":"São registrados nos livros do Céu para o juízo"}],"resposta_correta":"b","explicacao":"No dia da morte do homem, seus pensamentos perecem naquele mesmo dia; não há continuação de consciência ou atividade mental após a morte.","referencias":[{"texto":"Sl 146:4","livro":"Sl","capitulo":146,"versiculo":"4","conteudo":"Sai-lhe o espírito, e volta para a terra; naquele mesmo dia perecem todos os seus pensamentos."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a morte é um sono até a ressurreição."},{"id":"cf2","texto":"Reconheço que não há imortalidade inerente da alma."},{"id":"cf3","texto":"Desejo confiar em Deus durante a morte até a ressurreição."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 35, 'A Ressurreição', 'O Despertar Corporal dos Mortos em Cristo', 'Todos os que estão nas sepulturas sairão mediante uma ressurreição corporal. A primeira ressurreição ocorrerá na vinda do Senhor quando os justos serão despertados. A segunda ressurreição dos ímpios acontecerá depois de mil anos. Haverá duas ressurreições: a primeira dos justos e a segunda dos ímpios. Será uma ressurreição corporal do corpo físico.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"Todos os que estão nas sepulturas sairão mediante o quê?","opcoes":[{"id":"a","texto":"Uma evolução espiritual gradual"},{"id":"b","texto":"Uma ressurreição corporal"},{"id":"c","texto":"Uma transformação em seres espirituais"},{"id":"d","texto":"Uma reencarnação em novos corpos"}],"resposta_correta":"b","explicacao":"Todos os que estão nas sepulturas sairão mediante uma ressurreição corporal real, onde o corpo será despertado do repouso da morte.","referencias":[{"texto":"Jo 5:28-29","livro":"Jo","capitulo":5,"versiculo":"28-29","conteudo":"Não vos maravilheis disto; porque vem a hora em que todos os que estão nos sepulcros ouvirão a sua voz. E os que tiverem feito bem sairão para a ressurreição da vida; e os que tiverem feito mal sairão para a ressurreição da condenação."},{"texto":"At 24:15","livro":"At","capitulo":24,"versiculo":"15","conteudo":"Tendo esperança em Deus, como também estes a esperam, de que há de haver ressurreição de mortos, assim de justos como de injustos."}]},{"id":"q2","numero":2,"texto":"Quando terá lugar a primeira ressurreição?","opcoes":[{"id":"a","texto":"Imediatamente após a morte de cada justo"},{"id":"b","texto":"Na vinda do Senhor — os justos serão despertados"},{"id":"c","texto":"No início do milênio, após os mil anos no Céu"},{"id":"d","texto":"Ao final do juízo investigativo"}],"resposta_correta":"b","explicacao":"A primeira ressurreição ocorrerá na vinda do Senhor, quando os justos dormindo serão despertados e transformados em imortalidade.","referencias":[{"texto":"1 Ts 4:15","livro":"1 Ts","capitulo":4,"versiculo":"15","conteudo":"Porque vos dizemos isto pela palavra do Senhor: que nós, os vivos, os que ficarmos até à vinda do Senhor, não precederemos os que já dormem."},{"texto":"Hb 11:13","livro":"Hb","capitulo":11,"versiculo":"13","conteudo":"Todos estes morreram na fé, sem terem recebido as promessas; mas vendo-as de longe, e crendo-as, e abraçando-as, confessaram que eram estrangeiros e peregrinos na terra."},{"texto":"Ap 20:4-6","livro":"Ap","capitulo":20,"versiculo":"4-6","conteudo":"E vi tronos; e assentaram-se sobre eles, e foi-lhes dado o poder de julgar; e vi as almas dos que tinham sido mortos por causa do testemunho de Jesus, e por causa da palavra de Deus, e que não tinham adorado a besta, nem a sua imagem, e não tinham recebido o sinal na sua testa, nem na sua mão; e viveram, e reinaram com Cristo durante mil anos. Mas os outros mortos não reviveram, senão depois que os mil anos se acabaram. Esta é a primeira ressurreição."}]},{"id":"q3","numero":3,"texto":"Quando os ímpios se levantarão?","opcoes":[{"id":"a","texto":"Na mesma hora que os justos"},{"id":"b","texto":"Depois de mil anos — na segunda ressurreição"},{"id":"c","texto":"Nunca — permanecerão mortos eternamente"},{"id":"d","texto":"Antes dos justos, para serem julgados primeiro"}],"resposta_correta":"b","explicacao":"Os ímpios se levantarão na segunda ressurreição, que ocorre depois de mil anos, permanecendo na morte enquanto os justos reinam com Cristo.","referencias":[{"texto":"Ap 20:4-6","livro":"Ap","capitulo":20,"versiculo":"4-6","conteudo":"E vi tronos; e assentaram-se sobre eles, e foi-lhes dado o poder de julgar; e vi as almas dos que tinham sido mortos por causa do testemunho de Jesus, e por causa da palavra de Deus, e que não tinham adorado a besta, nem a sua imagem, e não tinham recebido o sinal na sua testa, nem na sua mão; e viveram, e reinaram com Cristo durante mil anos. Mas os outros mortos não reviveram, senão depois que os mil anos se acabaram. Esta é a primeira ressurreição."}]},{"id":"q4","numero":4,"texto":"Quantas ressurreições haverá segundo a Bíblia?","opcoes":[{"id":"a","texto":"Apenas uma, universal"},{"id":"b","texto":"Duas: a primeira (dos justos) e a segunda (dos ímpios, após mil anos)"},{"id":"c","texto":"Três: justos, mártires e ímpios"},{"id":"d","texto":"Nenhuma — a ressurreição é simbólica"}],"resposta_correta":"b","explicacao":"Haverá duas ressurreições segundo a Bíblia: a primeira dos justos e a segunda dos ímpios, ocorrendo em tempos diferentes e com destinos diferentes.","referencias":[{"texto":"Jo 5:28-29","livro":"Jo","capitulo":5,"versiculo":"28-29","conteudo":"Não vos maravilheis disto; porque vem a hora em que todos os que estão nos sepulcros ouvirão a sua voz. E os que tiverem feito bem sairão para a ressurreição da vida; e os que tiverem feito mal sairão para a ressurreição da condenação."},{"texto":"Ap 20:4-6","livro":"Ap","capitulo":20,"versiculo":"4-6","conteudo":"E vi tronos; e assentaram-se sobre eles, e foi-lhes dado o poder de julgar; e vi as almas dos que tinham sido mortos por causa do testemunho de Jesus, e por causa da palavra de Deus, e que não tinham adorado a besta, nem a sua imagem, e não tinham recebido o sinal na sua testa, nem na sua mão; e viveram, e reinaram com Cristo durante mil anos. Mas os outros mortos não reviveram, senão depois que os mil anos se acabaram. Esta é a primeira ressurreição."}]},{"id":"q5","numero":5,"texto":"Que tipo de ressurreição será?","opcoes":[{"id":"a","texto":"Espiritual — apenas o espírito se levantará"},{"id":"b","texto":"Corporal — uma ressurreição do corpo físico"},{"id":"c","texto":"Simbólica — representando uma nova era"},{"id":"d","texto":"Parcial — apenas a alma ressuscitará"}],"resposta_correta":"b","explicacao":"A ressurreição será corporal e física, envolvendo o corpo ressuscitado e transformado, não meramente espiritual ou simbólica.","referencias":[{"texto":"Jo 5:28-29","livro":"Jo","capitulo":5,"versiculo":"28-29","conteudo":"Não vos maravilheis disto; porque vem a hora em que todos os que estão nos sepulcros ouvirão a sua voz. E os que tiverem feito bem sairão para a ressurreição da vida; e os que tiverem feito mal sairão para a ressurreição da condenação."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio na ressurreição corporal de todos os mortos."},{"id":"cf2","texto":"Reconheço que a primeira ressurreição é privilégio dos justos."},{"id":"cf3","texto":"Desejo estar pronto para a ressurreição à vida eterna."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 36, 'O Milênio', 'Os Mil Anos de Governo Celestial', 'Os justos, após a primeira ressurreição, serão arrebatados ao Céu e sentarão sobre cadeiras de juízes por mil anos. Os ímpios serão destruídos pelo aparecimento de Cristo. A Terra ficará deserta — não se achará nela nenhum ser humano. Após o milênio terminado, Jesus descenderá com os Seus santos e a Nova Jerusalém descerá do Céu.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que acontecerá com os justos após a primeira ressurreição?","opcoes":[{"id":"a","texto":"Permanecerão na Terra renovada"},{"id":"b","texto":"Serão arrebatados ao Céu com o Senhor e sentarão sobre cadeiras de juízes por mil anos"},{"id":"c","texto":"Irão para o paraíso terrestre"},{"id":"d","texto":"Aguardarão na Terra o juízo dos ímpios"}],"resposta_correta":"b","explicacao":"Os justos após a primeira ressurreição serão arrebatados ao Céu com o Senhor e por mil anos sentarão sobre cadeiras de juízes exercendo autoridade.","referencias":[{"texto":"1 Ts 4:17","livro":"1 Ts","capitulo":4,"versiculo":"17","conteudo":"Depois nós, os vivos, os que ficarmos, seremos arrebatados juntamente com eles nas nuvens, a encontrar o Senhor nos ares, e assim estaremos sempre com o Senhor."},{"texto":"1 Co 6:3","livro":"1 Co","capitulo":6,"versiculo":"3","conteudo":"Não sabeis vós que havemos de julgar os anjos? Quanto mais as coisas desta vida?"},{"texto":"Ap 20:4","livro":"Ap","capitulo":20,"versiculo":"4","conteudo":"E vi tronos; e assentaram-se sobre eles, e foi-lhes dado o poder de julgar; e vi as almas dos que tinham sido mortos por causa do testemunho de Jesus, e por causa da palavra de Deus, e que não tinham adorado a besta, nem a sua imagem, e não tinham recebido o sinal na sua testa, nem na sua mão; e viveram, e reinaram com Cristo durante mil anos."}]},{"id":"q2","numero":2,"texto":"O que acontecerá com os ímpios na segunda vinda?","opcoes":[{"id":"a","texto":"Serão convertidos ao ver a glória de Cristo"},{"id":"b","texto":"Serão destruídos pelo Seu aparecimento"},{"id":"c","texto":"Serão levados cativos para outro planeta"},{"id":"d","texto":"Continuarão vivendo na Terra normalmente"}],"resposta_correta":"b","explicacao":"Os ímpios serão destruídos pelo Seu aparecimento ao final dos mil anos, consumidos pela glória de Sua vinda quando não tiverem oportunidade de se arrepender.","referencias":[{"texto":"2 Ts 1:6-8","livro":"2 Ts","capitulo":1,"versiculo":"6-8","conteudo":"Porque é justo para com Deus recompensar com tribulação aos que vos atribulam; e a vós, que sois atribulados, alívio conosco, quando se manifestar o Senhor Jesus do céu com os anjos da sua potência, em chama de fogo, tomando vingança dos que não conhecem a Deus, e dos que não obedecem ao evangelho de nosso Senhor Jesus Cristo."},{"texto":"2 Pe 3:10","livro":"2 Pe","capitulo":3,"versiculo":"10","conteudo":"Virá, porém, como ladrão na noite, o dia do Senhor, em que os céus passarão com grande estrondo, e os elementos se desfarão com intenso calor, e a terra, e as obras que nela há, serão descobertas."},{"texto":"Ap 6:15-16","livro":"Ap","capitulo":6,"versiculo":"15-16","conteudo":"E os reis da terra, e os grandes, e os ricos, e os capitães, e os poderosos, e todo o servo, e todo o livre, se esconderam nas cavernas e nas rochas das montanhas; e diziam aos montes e aos rochedos: Caí sobre nós, e escondei-nos da face daquele que está assentado sobre o trono, e da ira do Cordeiro."}]},{"id":"q3","numero":3,"texto":"Como ficará a Terra durante os mil anos?","opcoes":[{"id":"a","texto":"Renovada e habitada pelos justos"},{"id":"b","texto":"Deserta — não se achará nela nenhum ser humano"},{"id":"c","texto":"Parcialmente destruída mas habitável"},{"id":"d","texto":"Coberta de água como no dilúvio"}],"resposta_correta":"b","explicacao":"A Terra permanecerá deserta durante os mil anos, sem nenhum ser humano habitando-a; seus antigos habitantes e toda vida terrena terão sido removidos.","referencias":[{"texto":"Ap 20:1-3","livro":"Ap","capitulo":20,"versiculo":"1-3","conteudo":"Texto bíblico indisponível"}]},{"id":"q4","numero":4,"texto":"O que acontecerá após o milênio terminado no Céu?","opcoes":[{"id":"a","texto":"Os justos voltarão gradualmente à Terra"},{"id":"b","texto":"Jesus descerá com os Seus santos sobre o Monte das Oliveiras e baixará a Santa Cidade, a Nova Jerusalém"},{"id":"c","texto":"A Terra será criada novamente do nada"},{"id":"d","texto":"Os anjos reconstruirão a Terra antes da descida"}],"resposta_correta":"b","explicacao":"Após o milênio terminado no Céu, Jesus descerá com os Seus santos sobre o Monte das Oliveiras e baixará a Santa Cidade, a Nova Jerusalém, para Terra renovada.","referencias":[{"texto":"Zc 14:3-5","livro":"Zc","capitulo":14,"versiculo":"3-5","conteudo":"Depois sairá o Senhor, e pelejará contra aquelas nações, como quando pelejou no dia da batalha. E naquele dia estarão os seus pés sobre o monte das Oliveiras, que está defronte de Jerusalém para o oriente; e o monte das Oliveiras se fenderá pelo meio, para o oriente e para o ocidente, e haverá um vale muito grande; e metade do monte se apartará para o norte, e a outra metade para o sul. E fugireis pelo vale dos meus montes; porque o vale dos montes chegará até Azel; e fugireis como fugistes diante do terramoto, nos dias de Uzias, rei de Judá; e virão o Senhor meu Deus, e todos os santos contigo."},{"texto":"Ap 21:2","livro":"Ap","capitulo":21,"versiculo":"2","conteudo":"E eu, João, vi a santa cidade, a nova Jerusalém, que de Deus descia do céu, adornada como uma esposa ataviada para o seu marido."}]},{"id":"q5","numero":5,"texto":"O que acontecerá na segunda ressurreição?","opcoes":[{"id":"a","texto":"Os ímpios serão perdoados e aceitos"},{"id":"b","texto":"Um fogo consumidor purificará toda a Terra, e Satanás e todos os ímpios serão destruídos para sempre"},{"id":"c","texto":"Os ímpios receberão uma segunda chance"},{"id":"d","texto":"Haverá um novo período de prova de mil anos"}],"resposta_correta":"b","explicacao":"Na segunda ressurreição, um fogo consumidor purificará toda a Terra e completará a destruição de Satanás, de todos os ímpios e do pecado para sempre.","referencias":[{"texto":"Ap 20:11-13","livro":"Ap","capitulo":20,"versiculo":"11-13","conteudo":"E vi um grande trono branco, e o que estava assentado sobre ele, de cuja face fugiu a terra e o céu; e não se achou lugar para eles. E vi os mortos, grandes e pequenos, em pé diante de Deus, e abriram-se os livros; e abriu-se outro livro, que é o da vida; e os mortos foram julgados pelas coisas que estavam escritas nos livros, segundo as suas obras. E o mar entregou os mortos que nele havia; e a morte e o inferno entregaram os mortos que neles havia; e foram julgados cada um segundo as suas obras."},{"texto":"Ml 4:1-3","livro":"Ml","capitulo":4,"versiculo":"1-3","conteudo":"Porque eis que vem o dia ardente como uma fornalha; todos os soberbos, e todos os que cometem impiedade, serão como a palha; e o dia que vem os abrasará, diz o Senhor dos Exércitos, de sorte que não lhes deixará nem raiz nem ramo. Mas para vós, os que temeis o meu nome, nascerá o Sol da justiça, e cura debaixo das suas asas; e saireis, e crescereis como bezerros da estrebaria. E pisareis os ímpios, porque eles serão cinza debaixo das plantas de vossos pés, no dia em que eu fizer isto, diz o Senhor dos Exércitos."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que há mil anos de investigação e julgamento no Céu."},{"id":"cf2","texto":"Reconheço que a Terra será desolada durante os mil anos."},{"id":"cf3","texto":"Desejo estar entre os ressuscitados para o milênio."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('principios_fe', 37, 'O Novo Céu e a Nova Terra', 'A Herança Eterna dos Redimidos', 'A velha Terra será purificada com fogo, e haverá uma Nova Terra e um Novo Céu. A Nova Jerusalém é a Cidade Santa — a herança eterna dos santos. Os salvos habitarão na Nova Terra para sempre, felizes e com segurança completa. Não haverá mais morte, pranto, clamor e dor. Este é o fim glorioso da História e o início da eternidade com Deus.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"q1","numero":1,"texto":"O que acontecerá com a velha Terra?","opcoes":[{"id":"a","texto":"Será reformada gradualmente"},{"id":"b","texto":"Será purificada com fogo, e haverá uma Nova Terra e um Novo Céu"},{"id":"c","texto":"Continuará existindo eternamente como está"},{"id":"d","texto":"Será abandonada e os salvos viverão em outro planeta"}],"resposta_correta":"b","explicacao":"A velha Terra será purificada com fogo, transformando-se em uma Nova Terra, enquanto um Novo Céu substituirá o firmamento anterior nesta restauração final.","referencias":[{"texto":"2 Pe 3:13","livro":"2 Pe","capitulo":3,"versiculo":"13","conteudo":"Mas nós, segundo a sua promessa, esperamos novos céus e uma nova terra, em que habita a justiça."},{"texto":"Ap 21:1-4","livro":"Ap","capitulo":21,"versiculo":"1-4","conteudo":"E vi um novo céu, e uma nova terra. Porque já o primeiro céu e a primeira terra se foram, e o mar já não existe. E eu, João, vi a santa cidade, a nova Jerusalém, que de Deus descia do céu, adornada como uma esposa ataviada para o seu marido. E ouvi uma grande voz do céu, que dizia: Eis que o tabernáculo de Deus está com os homens, pois com eles habitará, e eles serão o seu povo, e o mesmo Deus estará com eles, e será o seu Deus. E Deus limpará de seus olhos toda a lágrima; e não haverá mais morte, nem pranto, nem clamor, nem dor; porque já as primeiras coisas são passadas."}]},{"id":"q2","numero":2,"texto":"Como é chamada a nova Terra com a Nova Jerusalém?","opcoes":[{"id":"a","texto":"O Paraíso Terrestre"},{"id":"b","texto":"A Cidade Santa — a herança eterna dos santos"},{"id":"c","texto":"O Jardim do Éden restaurado"},{"id":"d","texto":"O Reino Milenar de Cristo"}],"resposta_correta":"b","explicacao":"A nova Terra com a Nova Jerusalém é chamada de A Cidade Santa, que é a herança eterna reservada para os santos que foram fiéis a Deus.","referencias":[{"texto":"Ap 21:1-4","livro":"Ap","capitulo":21,"versiculo":"1-4","conteudo":"E vi um novo céu, e uma nova terra. Porque já o primeiro céu e a primeira terra se foram, e o mar já não existe. E eu, João, vi a santa cidade, a nova Jerusalém, que de Deus descia do céu, adornada como uma esposa ataviada para o seu marido. E ouvi uma grande voz do céu, que dizia: Eis que o tabernáculo de Deus está com os homens, pois com eles habitará, e eles serão o seu povo, e o mesmo Deus estará com eles, e será o seu Deus. E Deus limpará de seus olhos toda a lágrima; e não haverá mais morte, nem pranto, nem clamor, nem dor; porque já as primeiras coisas são passadas."}]},{"id":"q3","numero":3,"texto":"Onde os salvos habitarão para sempre?","opcoes":[{"id":"a","texto":"No Céu, sem nunca voltar à Terra"},{"id":"b","texto":"Na Nova Terra, felizes para sempre"},{"id":"c","texto":"Em outro planeta criado por Deus"},{"id":"d","texto":"Em um estado espiritual sem corpo físico"}],"resposta_correta":"b","explicacao":"Os salvos habitarão na Nova Terra felizes para sempre, realizando o propósito original de Deus de ter Seu povo vivendo em Sua presença eternamente.","referencias":[{"texto":"Ap 21:1-4","livro":"Ap","capitulo":21,"versiculo":"1-4","conteudo":"E vi um novo céu, e uma nova terra. Porque já o primeiro céu e a primeira terra se foram, e o mar já não existe. E eu, João, vi a santa cidade, a nova Jerusalém, que de Deus descia do céu, adornada como uma esposa ataviada para o seu marido. E ouvi uma grande voz do céu, que dizia: Eis que o tabernáculo de Deus está com os homens, pois com eles habitará, e eles serão o seu povo, e o mesmo Deus estará com eles, e será o seu Deus. E Deus limpará de seus olhos toda a lágrima; e não haverá mais morte, nem pranto, nem clamor, nem dor; porque já as primeiras coisas são passadas."},{"texto":"Sl 37:11,29","livro":"Sl","capitulo":37,"versiculo":"11","conteudo":"Texto bíblico indisponível"}]},{"id":"q4","numero":4,"texto":"O que não haverá mais na Nova Terra segundo Apocalipse 21?","opcoes":[{"id":"a","texto":"Trabalho ou atividade de qualquer tipo"},{"id":"b","texto":"Morte, pranto, clamor e dor"},{"id":"c","texto":"Árvores e vegetação"},{"id":"d","texto":"Luz do sol e da lua"}],"resposta_correta":"b","explicacao":"Não haverá morte, pranto, clamor ou dor na Nova Terra, conforme Apocalipse 21, significando fim completo do sofrimento humano.","referencias":[{"texto":"Ap 21:4","livro":"Ap","capitulo":21,"versiculo":"4","conteudo":"Texto bíblico indisponível"}]},{"id":"q5","numero":5,"texto":"A Nova Jerusalém descerá de onde?","opcoes":[{"id":"a","texto":"Será construída pelos santos na Terra"},{"id":"b","texto":"Do Céu, da parte de Deus"},{"id":"c","texto":"Surgirá da Terra renovada"},{"id":"d","texto":"Será trazida pelos anjos de outro mundo"}],"resposta_correta":"b","explicacao":"A Nova Jerusalém descerá do Céu, da parte de Deus, trazendo a habitação divina diretamente para a Terra renovada onde os santos residirão eternamente.","referencias":[{"texto":"Ap 21:2","livro":"Ap","capitulo":21,"versiculo":"2","conteudo":"E eu, João, vi a santa cidade, a nova Jerusalém, que de Deus descia do céu, adornada como uma esposa ataviada para o seu marido."}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que Deus criará um novo céu e uma nova terra."},{"id":"cf2","texto":"Reconheço a Nova Jerusalém como meu lar eterno."},{"id":"cf3","texto":"Desejo viver para sempre com Jesus na Nova Terra."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 1, 'A Divindade', 'O Pai, o Filho e o Espírito Santo', 'Este tema aborda a divindade, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_01_q1","numero":1,"texto":"Qual é a natureza de Deus segundo as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Deus é um Ser material e limitado"},{"id":"b","texto":"Deus é um Ser espiritual, eterno, infinito e imutável"},{"id":"c","texto":"Deus é uma força cósmica impessoal"},{"id":"d","texto":"Deus é simplesmente uma ideia abstrata"}],"resposta_correta":"b","explicacao":"Deus é um Ser espiritual, transcendente, eterno e infinito. Ele não é limitado pela materialidade nem pela condição humana, sendo perfeito e imutável em sua essência e caráter.","referencias":[{"texto":"1 João 4:24","livro":"1 João","capitulo":4,"versiculo":"24","conteudo":"Deus é espírito, e necessário é que os que o adoram o façam em espírito e em verdade."},{"texto":"Malaquias 3:6","livro":"Malaquias","capitulo":3,"versiculo":"6","conteudo":"Porque eu, o Senhor, não mudo."}]},{"id":"cf_01_q2","numero":2,"texto":"De acordo com as Crenças Fundamentais, como podemos conhecer a Deus?","opcoes":[{"id":"a","texto":"Apenas através da experiência mística e intuição pessoal"},{"id":"b","texto":"Por meio da revelação divina nas Santas Escrituras e da experiência pessoal com Ele"},{"id":"c","texto":"Somente através da razão humana e filosofia"},{"id":"d","texto":"Através de práticas rituais e cerimônias religiosas"}],"resposta_correta":"b","explicacao":"O conhecimento de Deus ocorre através da revelação divina registrada nas Escrituras Sagradas, combinado com a experiência pessoal e o relacionamento direto com o Criador. A Bíblia é o fundamento seguro para conhecer Deus.","referencias":[{"texto":"2 Timóteo 3:16","livro":"2 Timóteo","capitulo":3,"versiculo":"16","conteudo":"Toda a Escritura é inspirada por Deus e proveitosa para ensinar, para repreender, para corrigir, para instruir em justiça."}]},{"id":"cf_01_q3","numero":3,"texto":"Deus possui as qualidades de onipotência (todo-poderoso), onisciência (tudo sabe) e onipresença (presente em toda parte).","opcoes":[{"id":"a","texto":"Verdadeiro - Deus possui todas essas qualidades infinitas"},{"id":"b","texto":"Falso - Deus possui apenas poder, não conhecimento"},{"id":"c","texto":"Verdadeiro apenas para duas das três qualidades"},{"id":"d","texto":"Falso - Essas qualidades são apenas atribuições humanas"}],"resposta_correta":"a","explicacao":"Deus é onipotente (poder ilimitado), onisciente (conhecimento perfeito) e onipresente (presente em toda parte). Estas são qualidades infinitas e essenciais do caráter divino que definem Sua natureza suprema.","referencias":[{"texto":"Salmos 139:7-8","livro":"Salmos","capitulo":139,"versiculo":"7-8","conteudo":"Para onde me irei do teu Espírito? Ou para onde fugirei da tua face?"}]},{"id":"cf_01_q4","numero":4,"texto":"Segundo as Crenças Fundamentais, Deus _____ a humanidade à Sua imagem e semelhança para que tenhamos _____ com Ele e responsabilidade _____.","opcoes":[{"id":"a","texto":"criou / comunhão / moral"},{"id":"b","texto":"escolheu / amizade / espiritual"},{"id":"c","texto":"formou / relacionamento / religiosa"},{"id":"d","texto":"ungiu / troca / divina"}],"resposta_correta":"a","explicacao":"Deus criou o ser humano à Sua imagem para estabelecer comunhão com Ele e conferir responsabilidade moral. Esta criação especial confere dignidade e propósito ao ser humano de refletir o caráter divino.","referencias":[{"texto":"Gênesis 1:27","livro":"Gênesis","capitulo":1,"versiculo":"27","conteudo":"E criou Deus o homem à sua imagem, à imagem de Deus o criou; macho e fêmea os criou."}]},{"id":"cf_01_q5","numero":5,"texto":"Por que o conceito da Divindade é fundamental para a fé cristã?","opcoes":[{"id":"a","texto":"Porque define o caráter e propósito de Deus na salvação humana"},{"id":"b","texto":"Porque é um tema filosófico interessante"},{"id":"c","texto":"Porque estabelece a autoridade da Igreja"},{"id":"d","texto":"Porque determina as práticas rituais da religião"}],"resposta_correta":"a","explicacao":"Compreender a verdadeira natureza de Deus é essencial para entender Seu caráter de amor, justiça e misericórdia, bem como Seu propósito eterno de salvar a humanidade através de Cristo.","referencias":[{"texto":"João 3:16","livro":"João","capitulo":3,"versiculo":"16","conteudo":"Porque Deus amou o mundo de tal maneira que deu o seu Filho unigênito, para que todo aquele que nele crê não pereça, mas tenha a vida eterna."}]},{"id":"cf_01_q6","numero":6,"texto":"A Trindade (Pai, Filho e Espírito Santo) representa três deuses separados e distintos.","opcoes":[{"id":"a","texto":"Verdadeiro - São três deuses independentes"},{"id":"b","texto":"Falso - Representam um único Deus em três manifestações distintas"},{"id":"c","texto":"Verdadeiro - Mas com propósito unificado"},{"id":"d","texto":"Falso - É apenas uma metáfora simbólica"}],"resposta_correta":"b","explicacao":"A Trindade expressa a unidade perfeita de um único Deus em três pessoas distintas: Pai, Filho e Espírito Santo. Cada uma tem um papel específico, mas compartilham a mesma essência divina e propósito.","referencias":[{"texto":"1 João 5:7","livro":"1 João","capitulo":5,"versiculo":"7","conteudo":"Porque três são os que testificam no céu: o Pai, a Palavra e o Espírito Santo."}]},{"id":"cf_01_q7","numero":7,"texto":"Qual é a importância de entender que Deus é amor?","opcoes":[{"id":"a","texto":"Nos assegura que Deus está interessado no nosso bem e salvação"},{"id":"b","texto":"Prova que Deus não punirá o pecado"},{"id":"c","texto":"Demonstra que podemos viver como desejarmos"},{"id":"d","texto":"Indica que a moral e a ética não importam"}],"resposta_correta":"a","explicacao":"Entender que Deus é amor nos motiva a confiar em Seu cuidado e propósito para nossas vidas. Esse conhecimento nos tranquiliza quanto à Sua solicitude em nossa salvação e bem-estar eterno.","referencias":[{"texto":"1 João 4:8","livro":"1 João","capitulo":4,"versiculo":"8","conteudo":"Aquele que não ama não conhece a Deus, porque Deus é amor."}]},{"id":"cf_01_q8","numero":8,"texto":"Os atributos de Deus incluem justiça, misericórdia, _____ e _____.","opcoes":[{"id":"a","texto":"santidade / eternidade"},{"id":"b","texto":"poder / limitação"},{"id":"c","texto":"ira / ódio"},{"id":"d","texto":"fraqueza / imperfeição"}],"resposta_correta":"a","explicacao":"Os atributos de Deus incluem justiça, misericórdia, santidade e eternidade. Estes refletem Seu caráter perfeito e imutável, distinguindo-O de todas as outras entidades e estabelecendo Sua supremacia.","referencias":[{"texto":"Isaías 6:3","livro":"Isaías","capitulo":6,"versiculo":"3","conteudo":"Santo, Santo, Santo é o Senhor dos Exércitos; toda a terra está cheia da sua glória!"}]},{"id":"cf_01_q9","numero":9,"texto":"Como a compreensão da Divindade influencia nosso comportamento moral?","opcoes":[{"id":"a","texto":"Não tem influência alguma no comportamento moral"},{"id":"b","texto":"Nos motiva a refletir o caráter de Deus em nossas ações"},{"id":"c","texto":"Apenas determina o tipo de culto que praticamos"},{"id":"d","texto":"Faz com que abandonemos completamente a moral"}],"resposta_correta":"b","explicacao":"Quando compreendemos a verdadeira natureza de Deus, somos inspirados a refletir Seus atributos em nossa conduta. Isso nos impele a viver com integridade, justiça e amor semelhantes aos Seus.","referencias":[{"texto":"1 Pedro 1:15-16","livro":"1 Pedro","capitulo":1,"versiculo":"15-16","conteudo":"Mas, como é santo aquele que vos chamou, sê vós também santos em toda a vossa maneira de viver."}]},{"id":"cf_01_q10","numero":10,"texto":"As Crenças Fundamentais afirmam que Deus criou o ser humano com livre arbítrio.","opcoes":[{"id":"a","texto":"Verdadeiro - Deus criou o ser humano com liberdade de escolha"},{"id":"b","texto":"Falso - O ser humano é completamente controlado por Deus"},{"id":"c","texto":"Parcialmente verdadeiro - Apenas algumas pessoas têm livre arbítrio"},{"id":"d","texto":"Falso - O conceito de livre arbítrio é uma invenção humana"}],"resposta_correta":"a","explicacao":"Deus criou o ser humano com liberdade de escolha, permitindo que cada pessoa decida seguir ou rejeitar Seu caminho. Este livre arbítrio é essencial para uma relação genuína e significativa com Deus.","referencias":[{"texto":"Deuteronômio 30:15","livro":"Deuteronômio","capitulo":30,"versiculo":"15","conteudo":"Vê que te pus hoje diante de ti a vida e o bem, a morte e o mal."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço Deus como Pai, Filho e Espírito Santo — uma Trindade eterna e infinita."},{"id":"cf2","texto":"Comprometo-me a conhecer a Deus através da revelação bíblica e da experiência pessoal."},{"id":"cf3","texto":"Dedico-me a refletir os atributos de Deus (amor, justiça, misericórdia) em meu comportamento."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 2, 'As Santas Escrituras', 'A Palavra de Deus como Regra de Fé', 'Este tema aborda as santas escrituras, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_02_q1","numero":1,"texto":"Qual é a importância da inspiração divina das Escrituras nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"A Bíblia foi inspirada por Deus e é a palavra confiável para fé e prática"},{"id":"b","texto":"A Bíblia é um livro histórico importante, mas não é inspirada"},{"id":"c","texto":"A inspiração vem apenas da tradição eclesiástica"},{"id":"d","texto":"Cada leitor pode reinterpretar a Bíblia conforme sua opinião"}],"resposta_correta":"a","explicacao":"A Bíblia é a Palavra inspirada de Deus, escrita sob orientação divina para comunicar verdades essenciais sobre salvação e vontade de Deus. Sua inspiração a torna autoritativa para toda crença e conduta cristã.","referencias":[{"texto":"2 Timóteo 3:16","livro":"2 Timóteo","capitulo":3,"versiculo":"16","conteudo":"Toda a Escritura é inspirada por Deus e proveitosa para ensinar, para repreender, para corrigir, para instruir em justiça."}]},{"id":"cf_02_q2","numero":2,"texto":"Qual é a importância da autoridade bíblica nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"A Bíblia deve ser submetida à interpretação da Igreja"},{"id":"b","texto":"A Bíblia é a autoridade máxima para doutrina e prática cristã"},{"id":"c","texto":"A razão humana deve estar acima da Palavra de Deus"},{"id":"d","texto":"Cada pessoa pode ignorar partes da Bíblia que desagrada"}],"resposta_correta":"b","explicacao":"A Bíblia é a autoridade suprema na fé cristã. Nenhuma tradição, interpretação humana ou autoridade eclesiástica pode contradizer ou superseder a revelação escrita de Deus.","referencias":[{"texto":"Salmos 119:89","livro":"Salmos","capitulo":119,"versiculo":"89","conteudo":"Para sempre, ó Senhor, a tua palavra permanece nos céus."}]},{"id":"cf_02_q3","numero":3,"texto":"A revelação divina na Bíblia é completa ou Deus continua revelando novas doutrinas fora das Escrituras?","opcoes":[{"id":"a","texto":"Deus continua revelando novas verdades em visões e mensagens privadas"},{"id":"b","texto":"Apenas a Igreja tem autoridade para adicionar doutrinas"},{"id":"c","texto":"A revelação divina é completa nas Santas Escrituras"},{"id":"d","texto":"Cada pessoa pode receber revelações pessoais que contradizem a Bíblia"}],"resposta_correta":"c","explicacao":"A revelação de Deus está completa nas Escrituras Sagradas. O cânon bíblico contém toda a revelação necessária para salvação, fé e prática cristã. Nada pode ser acrescentado ou removido.","referencias":[{"texto":"Apocalipse 22:18-19","livro":"Apocalipse","capitulo":22,"versiculo":"18-19","conteudo":"Eu, a todo aquele que ouve as palavras da profecia deste livro, testifico: Se alguém acrescentar coisa alguma a estas coisas, Deus acrescentará sobre ele as pragas escritas neste livro."}]},{"id":"cf_02_q4","numero":4,"texto":"O que significa o cânon bíblico nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Livros que podem ser modificados conforme necessário"},{"id":"b","texto":"Escritos que perderam relevância para dias modernos"},{"id":"c","texto":"Documentos que a Igreja escolheu arbitrariamente"},{"id":"d","texto":"O conjunto de 66 livros reconhecidos como Palavra de Deus, inspirados e infalíveis"}],"resposta_correta":"d","explicacao":"O cânon bíblico compreende os 66 livros reconhecidos pela Igreja como inspirados por Deus e autoritativos. Estes formam a revelação completa e inerrante de Deus para a humanidade.","referencias":[{"texto":"2 Pedro 1:20-21","livro":"2 Pedro","capitulo":1,"versiculo":"20-21","conteudo":"Sabendo primeiramente isto: que nenhuma profecia da Escritura é de particular interpretação; porque a profecia nunca foi produzida por vontade de homem algum, mas os homens santos de Deus falaram inspirados pelo Espírito Santo."}]},{"id":"cf_02_q5","numero":5,"texto":"Como devemos interpretar as Escrituras de forma correta nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Com oração, estudo sério, busca do contexto histórico e uso da Bíblia para interpretar a Bíblia"},{"id":"b","texto":"Apenas com nossa intuição pessoal e sentimentos"},{"id":"c","texto":"Conforme a interpretação que nos agrada"},{"id":"d","texto":"Deixando toda interpretação para os líderes religiosos"}],"resposta_correta":"a","explicacao":"A interpretação correta das Escrituras requer oração, estudo diligente, consideração do contexto histórico e cultural, permitindo que a Bíblia explique a si mesma através da comparação de passagens.","referencias":[{"texto":"2 Timóteo 2:15","livro":"2 Timóteo","capitulo":2,"versiculo":"15","conteudo":"Procura apresentar-te a Deus aprovado, como obreiro que não tem de que se envergonhar, que maneja bem a palavra da verdade."}]},{"id":"cf_02_q6","numero":6,"texto":"A Bíblia é suficiente para nos ensinar tudo que precisamos saber para salvação e vida cristã?","opcoes":[{"id":"a","texto":"Não, precisamos de livros adicionais e revelações extrabiblícas"},{"id":"b","texto":"Sim, a Bíblia contém toda verdade necessária para salvação e doutrina cristã"},{"id":"c","texto":"Apenas parcialmente, alguns assuntos não são cobertos"},{"id":"d","texto":"Ela é insuficiente e precisa ser constantemente atualizada"}],"resposta_correta":"b","explicacao":"A Bíblia é suficiente e completa para fornecer orientação em toda questão de fé, doutrina e conduta. Ela é autossuficiente e não necessita de suplementos extrabiblícas para ser eficaz.","referencias":[{"texto":"Salmos 119:105","livro":"Salmos","capitulo":119,"versiculo":"105","conteudo":"Lâmpada para os meus pés é a tua palavra, e luz para o meu caminho."}]},{"id":"cf_02_q7","numero":7,"texto":"Qual é o significado da verdade bíblica nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"A Bíblia apresenta opiniões relativas que mudam com o tempo"},{"id":"b","texto":"A verdade bíblica é apenas simbólica e não factual"},{"id":"c","texto":"A Bíblia comunica verdades absolutas e inerrantes que são válidas para toda humanidade"},{"id":"d","texto":"Cada pessoa determina sua própria verdade a partir da Bíblia"}],"resposta_correta":"c","explicacao":"A verdade bíblica é revelação objetiva e inerrante de Deus. Não é relativa, mudável ou sujeita à interpretação pessoal. A verdade bíblica é válida e vinculante para todos em todos os tempos.","referencias":[{"texto":"João 17:17","livro":"João","capitulo":17,"versiculo":"17","conteudo":"Santifica-os na verdade; a tua palavra é a verdade."}]},{"id":"cf_02_q8","numero":8,"texto":"Qual é a importância da aplicação prática das Escrituras nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"O conhecimento bíblico não precisa ser aplicado na vida prática"},{"id":"b","texto":"Podemos aplicar a Bíblia seletivamente conforme nos agrada"},{"id":"c","texto":"A Bíblia é apenas para meditação, não para ação"},{"id":"d","texto":"Devemos estudar a Bíblia com intenção de obedecer e aplicar seus ensinamentos em nossa vida"}],"resposta_correta":"d","explicacao":"O estudo bíblico deve resultar em obediência prática e mudança de vida. A Palavra de Deus não é apenas para conhecimento intelectual, mas para transformar nosso caráter e condutas.","referencias":[{"texto":"Tiago 1:22","livro":"Tiago","capitulo":1,"versiculo":"22","conteudo":"Tornai-vos cumpridores da palavra, e não somente ouvintes, enganando-vos a vós mesmos."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço as Santas Escrituras como a Palavra de Deus, completa e inspirada."},{"id":"cf2","texto":"Comprometo-me a estudar a Bíblia com reverência e buscar sua interpretação verdadeira."},{"id":"cf3","texto":"Dedico-me a viver conforme os ensinamentos bíblicos em todos os aspectos da vida."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 3, 'Leis Divinas', 'A Lei Moral e a Lei Cerimonial', 'Este tema aborda leis divinas, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_03_q1","numero":1,"texto":"Qual é a importância dos Dez Mandamentos nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Expressam a vontade moral eterna de Deus e o padrão para conduta correta"},{"id":"b","texto":"São leis apenas para o Antigo Testamento e não mais aplicáveis"},{"id":"c","texto":"Foram abolidas e substituídas por novas regras eclesiásticas"},{"id":"d","texto":"Servem apenas para condenar, não para guiar"}],"resposta_correta":"a","explicacao":"Os Dez Mandamentos expressam a lei moral eterna de Deus. Eles revelam Seu caráter de santidade e estabelecem o padrão divino para conduta humana que continua válido.","referencias":[{"texto":"Êxodo 20:1-17","livro":"Êxodo","capitulo":20,"versiculo":"1-17","conteudo":"E Deus falou todas estas palavras, dizendo: Eu sou o Senhor teu Deus..."}]},{"id":"cf_03_q2","numero":2,"texto":"Qual é a importância da lei moral nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"É apenas cultural e pode ser ignorada"},{"id":"b","texto":"Reflete o caráter divino e é válida perpetuamente"},{"id":"c","texto":"É válida apenas durante certas épocas"},{"id":"d","texto":"Depende da opinião pessoal de cada crente"}],"resposta_correta":"b","explicacao":"A lei moral reflete o caráter eterno de Deus e permanece válida perpetuamente. É o fundamento da justiça divina e guia para conduta humana em todos os tempos.","referencias":[{"texto":"Romanos 3:31","livro":"Romanos","capitulo":3,"versiculo":"31","conteudo":"Anulamos, pois, a lei pela fé? De modo nenhum; antes estabelecemos a lei."}]},{"id":"cf_03_q3","numero":3,"texto":"As leis cerimoniais do Antigo Testamento continuam em vigor para os cristãos?","opcoes":[{"id":"a","texto":"Sim, devemos cumprir todas as cerimônias e rituais"},{"id":"b","texto":"Parcialmente, apenas algumas cerimônias continuam"},{"id":"c","texto":"Não, as cerimônias foram cumpridas em Cristo e já não são obrigatórias"},{"id":"d","texto":"As cerimônias nunca tiveram significado"}],"resposta_correta":"c","explicacao":"As leis cerimoniais apontavam para o sacrifício de Cristo. Com Sua morte e ressurreição, o sistema cerimonial alcançou seu cumprimento e não é mais obrigatório para os cristãos.","referencias":[{"texto":"Colossenses 2:14-17","livro":"Colossenses","capitulo":2,"versiculo":"14-17","conteudo":"Havendo cancelado o escrito de dívida que havia contra nós..."}]},{"id":"cf_03_q4","numero":4,"texto":"O que caracteriza a lei civil no sistema de leis de Deus?","opcoes":[{"id":"a","texto":"Regras que nunca tiveram aplicação"},{"id":"b","texto":"Leis que só existem no Novo Testamento"},{"id":"c","texto":"Punições para violações da lei moral no contexto de Israel"},{"id":"d","texto":"Leis específicas para Israel que aplicavam princípios morais em seu contexto político e social"}],"resposta_correta":"d","explicacao":"As leis civis eram regulações específicas para a nação de Israel baseadas em princípios morais. Embora não sejam mais vinculantes na forma original, os princípios morais subjacentes permanecem válidos.","referencias":[{"texto":"Mateus 22:37-40","livro":"Mateus","capitulo":22,"versiculo":"37-40","conteudo":"Amarás o Senhor teu Deus de todo o teu coração..."}]},{"id":"cf_03_q5","numero":5,"texto":"A obediência à lei de Deus nos salva ou é resultado da salvação?","opcoes":[{"id":"a","texto":"A obediência à lei é resultado do amor por Deus e da experiência da salvação em Cristo"},{"id":"b","texto":"Guardamos a lei para obter salvação"},{"id":"c","texto":"Não precisamos mais guardar a lei depois de salvos"},{"id":"d","texto":"A lei nunca teve importância para cristãos"}],"resposta_correta":"a","explicacao":"A salvação vem pela graça através de Cristo, não pela lei. Porém, aqueles que são salvos obedecem a lei como resposta de amor ao Seu amor redentor, não para obter salvação.","referencias":[{"texto":"Romanos 6:14-15","livro":"Romanos","capitulo":6,"versiculo":"14-15","conteudo":"Porque o pecado não terá domínio sobre vós; pois não estais debaixo da lei, mas debaixo da graça."}]},{"id":"cf_03_q6","numero":6,"texto":"Qual é o propósito da lei moral de Deus segundo as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Apenas condenar e punir os pecadores"},{"id":"b","texto":"Revelar o caráter de Deus, convencer de pecado e guiar para retidão"},{"id":"c","texto":"Tornar as pessoas perfeitas e salvas"},{"id":"d","texto":"Não tem propósito definido"}],"resposta_correta":"b","explicacao":"A lei serve múltiplos propósitos: revelar o caráter santo de Deus, convencer de pecado, e guiar os redimidos para uma vida de retidão. Ela é um instrumento de Deus para justiça e santificação.","referencias":[{"texto":"Romanos 7:12","livro":"Romanos","capitulo":7,"versiculo":"12","conteudo":"De modo que a lei é santa, e o mandamento é santo, justo e bom."}]},{"id":"cf_03_q7","numero":7,"texto":"Como a salvação e a lei se relacionam nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"A lei nos salva se a obedecermos perfeitamente"},{"id":"b","texto":"Não existe relação entre salvação e lei"},{"id":"c","texto":"A salvação é pela graça de Cristo, e a lei revela nossa necessidade e nos guia em justiça"},{"id":"d","texto":"A salvação torna a lei irrelevante"}],"resposta_correta":"c","explicacao":"A lei não salva, mas revela nossa culpa e necessidade de Salvador. A salvação é inteiramente pela graça de Cristo. Porém, a lei contém os princípios morais que Deus nos convida a seguir em gratidão.","referencias":[{"texto":"Gálatas 3:24","livro":"Gálatas","capitulo":3,"versiculo":"24","conteudo":"De maneira que a lei nos serviu de aio, para nos conduzir a Cristo..."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço os Dez Mandamentos como expressão da lei moral eterna de Deus."},{"id":"cf2","texto":"Comprometo-me a guardar a lei de Deus por amor a Ele e não por salvação própria."},{"id":"cf3","texto":"Dedico-me a entender a distinção entre leis morais, cerimoniais e civis."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 4, 'O Sábado', 'O Memorial da Criação', 'Este tema aborda o sábado, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_04_q1","numero":1,"texto":"Qual é o significado do Sábado nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Um dia arbitrário escolhido pela tradição humana"},{"id":"b","texto":"Um memorial sagrado da criação e sinal do repouso em Deus"},{"id":"c","texto":"Apenas um feriado cultural sem significado religioso"},{"id":"d","texto":"Um dia de trabalho como qualquer outro"}],"resposta_correta":"b","explicacao":"O Sábado é memorial da obra criadora de Deus e convite para descansar em Seu cuidado. Estabelecido na criação, continua sendo um sinal do repouso, santificação e comunhão com Deus.","referencias":[{"texto":"Gênesis 2:2-3","livro":"Gênesis","capitulo":2,"versiculo":"2-3","conteudo":"E, havendo Deus acabado no sétimo dia a sua obra, que tinha feito, repousou no sétimo dia..."}]},{"id":"cf_04_q2","numero":2,"texto":"Quem institui o Sábado conforme as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"A Igreja instituiu o Sábado em um concílio eclesiastico"},{"id":"b","texto":"Deus instituiu o Sábado na criação"},{"id":"c","texto":"Moisés criou o Sábado para Israel"},{"id":"d","texto":"O povo judeu inventou o Sábado"}],"resposta_correta":"b","explicacao":"Deus instituiu o Sábado na criação ao terminar Sua obra, abençoando e santificando o sétimo dia. É uma instituição divina, não uma criação humana ou eclesiástica.","referencias":[{"texto":"Êxodo 20:8-11","livro":"Êxodo","capitulo":20,"versiculo":"8-11","conteudo":"Lembra-te do dia do sábado, para o santificar..."}]},{"id":"cf_04_q3","numero":3,"texto":"Em qual dia da semana devemos guardar o Sábado?","opcoes":[{"id":"a","texto":"Qualquer dia que escolhermos pessoalmente"},{"id":"b","texto":"Apenas Quartas-feiras"},{"id":"c","texto":"O sétimo dia - do pôr do sol de sexta ao pôr do sol de sábado"},{"id":"d","texto":"O primeiro dia da semana (domingo)"}],"resposta_correta":"c","explicacao":"O Sábado é especificamente o sétimo dia da semana, do pôr do sol de sexta-feira ao pôr do sol de sábado-feira. Este é o dia que Deus abençoou e santificou na criação.","referencias":[{"texto":"Levítico 23:32","livro":"Levítico","capitulo":23,"versiculo":"32","conteudo":"É sábado de repouso para vós; e afligireis as vossas almas..."}]},{"id":"cf_04_q4","numero":4,"texto":"Como devemos guardar o Sábado segundo as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Apenas em templos e não em casa"},{"id":"b","texto":"Com repouso do trabalho, adoração, comunhão familiar e atividades que nos aproximem de Deus"},{"id":"c","texto":"Apenas com tristeza e lamento por nossos pecados"},{"id":"d","texto":"De forma severa e julgadora dos que não guardam"}],"resposta_correta":"b","explicacao":"Guardar o Sábado inclui cessar do trabalho secular, dedicar-se à adoração, comunhão familiar e atividades espiritualmente construtivas que trazem alegria e santificação.","referencias":[{"texto":"Isaías 58:13-14","livro":"Isaías","capitulo":58,"versiculo":"13-14","conteudo":"Se desviares do sábado o teu pé, de fazer a tua vontade no meu santo dia..."}]},{"id":"cf_04_q5","numero":5,"texto":"Qual é o significado do descanso e restauração no Sábado?","opcoes":[{"id":"a","texto":"Descanso físico e espiritual que restaura nosso relacionamento com Deus"},{"id":"b","texto":"Apenas um repouso físico para trabalho"},{"id":"c","texto":"Um dia para fazer mais trabalho de forma diferente"},{"id":"d","texto":"Não oferece nenhum benefício real"}],"resposta_correta":"a","explicacao":"O Sábado oferece descanso tanto físico quanto espiritual. Nos revigora e renova nosso compromisso com Deus. É um presente divino que nos restaura integralmente.","referencias":[{"texto":"Marcos 2:27","livro":"Marcos","capitulo":2,"versiculo":"27","conteudo":"E dizia-lhes: O sábado foi feito por causa do homem, e não o homem por causa do sábado."}]},{"id":"cf_04_q6","numero":6,"texto":"Como o Sábado se relaciona com a graça de Deus?","opcoes":[{"id":"a","texto":"O Sábado anula a graça de Deus"},{"id":"b","texto":"O Sábado é um presente de graça que nos convida ao descanso e comunhão com Deus"},{"id":"c","texto":"Não há relação entre Sábado e graça"},{"id":"d","texto":"A graça nos liberta de guardar o Sábado"}],"resposta_correta":"b","explicacao":"O Sábado é um presente gracioso de Deus para nossa bênção. Não é algo que nos torna dignos, mas uma dádiva de amor para renovação e comunhão.","referencias":[{"texto":"Hebreus 4:9-10","livro":"Hebreus","capitulo":4,"versiculo":"9-10","conteudo":"Portanto, resta ainda um repouso sabático para o povo de Deus."}]},{"id":"cf_04_q7","numero":7,"texto":"Por que o Sábado continua relevante para os cristãos modernos?","opcoes":[{"id":"a","texto":"É apenas uma tradição judaica antiquada"},{"id":"b","texto":"Continua sendo o sinal de santificação de Deus e lembrança de Sua criação"},{"id":"c","texto":"Não tem relevância na era moderna"},{"id":"d","texto":"Os cristãos devem ignorar completamente o Sábado"}],"resposta_correta":"b","explicacao":"O Sábado permanece relevante porque continua sendo sinal do caráter santificador de Deus e memorial de Sua criação. Sua importância não é cultural, mas inerente à revelação divina.","referencias":[{"texto":"Ezequiel 20:20","livro":"Ezequiel","capitulo":20,"versiculo":"20","conteudo":"E santificai os meus sábados, que sirvam de sinal entre mim e vós..."}]},{"id":"cf_04_q8","numero":8,"texto":"Quais são os benefícios de guardar o Sábado?","opcoes":[{"id":"a","texto":"Ganho de status social e riqueza material"},{"id":"b","texto":"Comunhão com Deus, renovação física e espiritual, família fortalecida"},{"id":"c","texto":"Nenhum benefício real"},{"id":"d","texto":"Apenas benefícios psicológicos imaginários"}],"resposta_correta":"b","explicacao":"Guardar o Sábado traz múltiplos benefícios: comunhão profunda com Deus, descanso e renovação física, fortalecimento dos relacionamentos familiares e paz espiritual.","referencias":[{"texto":"Salmos 118:24","livro":"Salmos","capitulo":118,"versiculo":"24","conteudo":"Este é o dia que o Senhor fez; regozijemo-nos e alegre-monos nele."}]},{"id":"cf_04_q9","numero":9,"texto":"O Sábado será observado na eternidade no novo céu e nova terra?","opcoes":[{"id":"a","texto":"Não, o Sábado é apenas para este mundo"},{"id":"b","texto":"Sim, o Sábado será eternamente observado como parte da vida celestial"},{"id":"c","texto":"Talvez, não sabemos com certeza"},{"id":"d","texto":"Será substituído por um novo dia de adoração"}],"resposta_correta":"b","explicacao":"O Sábado transcende o tempo. Será observado eternamente no novo céu e nova terra como memorial perpétuo da criação divina e como expressão contínua de comunhão com Deus.","referencias":[{"texto":"Isaías 66:22-23","livro":"Isaías","capitulo":66,"versiculo":"22-23","conteudo":"Porque, como os céus novos e a nova terra, que eu faço, permanecerão diante de mim..."}]},{"id":"cf_04_q10","numero":10,"texto":"Qual é a relação entre o Sábado e a criação de Deus?","opcoes":[{"id":"a","texto":"O Sábado não tem relação com a criação"},{"id":"b","texto":"O Sábado é memorial e celebração da criação de Deus"},{"id":"c","texto":"A criação não é importante para o Sábado"},{"id":"d","texto":"O Sábado nega a realidade da criação"}],"resposta_correta":"b","explicacao":"O Sábado é intrinsecamente vinculado à criação. Ao guardar o Sábado, celebramos e homenageamos a Deus como Criador e reconhecemos Sua supremacia sobre toda a criação.","referencias":[{"texto":"Êxodo 20:9-11","livro":"Êxodo","capitulo":20,"versiculo":"9-11","conteudo":"Seis dias trabalharás, e farás toda tua obra; mas o sétimo dia é o sábado do Senhor..."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço o Sábado como o sétimo dia estabelecido por Deus na criação."},{"id":"cf2","texto":"Comprometo-me a guardar o Sábado como dia sagrado de descanso e comunhão com Deus."},{"id":"cf3","texto":"Dedico-me a entender o Sábado como memorial da criação e sinal de santificação."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 5, 'Origem do Mal e Queda de Lúcifer', 'A Entrada do Pecado no Universo', 'Este tema aborda a origem do mal e queda de Lúcifer, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_05_q1","numero":1,"texto":"Qual é a origem do pecado e do mal segundo as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"O pecado e o mal surgiram da rebelião de Lúcifer contra a vontade de Deus"},{"id":"b","texto":"O pecado foi criado por Deus como parte de Seu plano perfeito"},{"id":"c","texto":"O mal é uma ilusão que não existe realmente"},{"id":"d","texto":"O pecado é meramente uma construção social sem significado espiritual"}],"resposta_correta":"a","explicacao":"O pecado não veio de Deus, mas da rebelião de Lúcifer, um ser criado livre. A origem do mal está na escolha de se rebelar contra Deus e sua rejeição da vontade divina, levando à queda do anjo que se tornou Satanás.","referencias":[{"texto":"Ezequiel 28:15-17","livro":"Ezequiel","capitulo":28,"versiculo":"15-17","conteudo":"Tu estavas numa posição perfeita, cheio de sabedoria e de beleza perfeita, mas elevou-se teu coração por causa da tua beleza..."}]},{"id":"cf_05_q2","numero":2,"texto":"Quem era Lúcifer antes de sua queda?","opcoes":[{"id":"a","texto":"Um anjo menor de importância secundária"},{"id":"b","texto":"O anjo mais elevado e poderoso, que cobria o trono de Deus"},{"id":"c","texto":"Um espírito de um homem morto que se rebelou"},{"id":"d","texto":"Uma criatura terrestre que nunca esteve no céu"}],"resposta_correta":"b","explicacao":"Lúcifer era o anjo mais elevado criado por Deus, um querubim protetor que cobria o trono de Deus. Sua posição era de grande honra e poder, mas seu coração se elevou em orgulho e ele se rebelou contra o Criador.","referencias":[{"texto":"Ezequiel 28:12-14","livro":"Ezequiel","capitulo":28,"versiculo":"12-14","conteudo":"Tu eras o sinete da perfeição, cheio de sabedoria e beleza perfeita... tu estavas no santo monte de Deus..."}]},{"id":"cf_05_q3","numero":3,"texto":"Qual foi a causa principal da queda de Lúcifer?","opcoes":[{"id":"a","texto":"Ele foi forçado por Deus a se rebelar"},{"id":"b","texto":"O orgulho e a ambição de se colocar acima de Deus"},{"id":"c","texto":"Uma ordem de Deus que ele desobedeceu"},{"id":"d","texto":"Circunstâncias do universo que o levaram a pecar"}],"resposta_correta":"b","explicacao":"A causa da queda foi o orgulho de Lúcifer. Seu coração se elevou por causa de sua beleza e posição, desejando ser igual a Deus e receber adoração que pertencia apenas ao Criador. Essa ambição o levou à rebelião.","referencias":[{"texto":"Isaías 14:12-14","livro":"Isaías","capitulo":14,"versiculo":"12-14","conteudo":"Como caíste do céu, ó estrela da manhã, filho da alva! Como foste lançado por terra, tu que dizias: Subirei acima das alturas das nuvens..."}]},{"id":"cf_05_q4","numero":4,"texto":"O que aconteceu quando Lúcifer se rebelou contra Deus?","opcoes":[{"id":"a","texto":"Ele foi imediatamente destruído por Deus"},{"id":"b","texto":"Ele foi expulso do céu junto com outros anjos que o seguiram"},{"id":"c","texto":"Ele foi colocado em prisão celestial, incapaz de agir"},{"id":"d","texto":"Deus permitiu sua rebelião para demonstrar Seu amor por livre arbítrio"}],"resposta_correta":"b","explicacao":"Quando Lúcifer se rebelou, Deus o expulsou do céu. Muitos anjos foram seduzidos por sua rebelião e o seguiram, tornando-se demônios. Essa guerra celestial resultou na queda desses seres do lugar de honra.","referencias":[{"texto":"Apocalipse 12:7-9","livro":"Apocalipse","capitulo":12,"versiculo":"7-9","conteudo":"Houve guerra no céu: Miguel e seus anjos guerreavam contra o dragão... Então foi lançado fora aquele grande dragão, a antiga serpente..."}]},{"id":"cf_05_q5","numero":5,"texto":"Como Lúcifer enganou o ser humano e levou à queda de Adão e Eva?","opcoes":[{"id":"a","texto":"Ele disfarçou-se de serpente e os persuadiu a desobedecer a Deus"},{"id":"b","texto":"Ele matou Adão e Eva e os substituiu por seus servos"},{"id":"c","texto":"Ele não teve envolvimento na queda da humanidade"},{"id":"d","texto":"Ele os puniu por obedecerem a Deus"}],"resposta_correta":"a","explicacao":"Após sua própria queda, Satanás (Lúcifer renomeado) procurou destruir os planos de Deus para a humanidade. Disfarçado de serpente, enganou Eva a desobedecer a Deus, convencendo-a a comer do fruto proibido, levando à queda de toda a humanidade.","referencias":[{"texto":"Gênesis 3:1-6","livro":"Gênesis","capitulo":3,"versiculo":"1-6","conteudo":"A serpente era o mais astuto dos animais... e disse à mulher: É assim que Deus disse: De toda árvore do jardim comereis..."}]},{"id":"cf_05_q6","numero":6,"texto":"Satanás continua exercendo influência no mundo mesmo após sua derrota?","opcoes":[{"id":"a","texto":"Não, ele foi completamente impotente após a crucifixão de Cristo"},{"id":"b","texto":"Sim, mas seu tempo está limitado e seu destino final é a destruição"},{"id":"c","texto":"Sim, e ele é tão poderoso quanto Deus"},{"id":"d","texto":"Sua influência é apenas psicológica, sem poder real"}],"resposta_correta":"b","explicacao":"Embora Cristo tenha conquistado a vitória sobre Satanás pela crucifixão e ressurreição, o inimigo ainda exerce influência nos últimos tempos. Porém, seu tempo é limitado e sua derrota final é certa na consumação de todas as coisas.","referencias":[{"texto":"Apocalipse 12:12","livro":"Apocalipse","capitulo":12,"versiculo":"12","conteudo":"...o diabo desceu para vós cheio de fúria, sabendo que pouco tempo lhe resta."}]},{"id":"cf_05_q7","numero":7,"texto":"Como os cristãos devem responder à realidade do mal e da influência de Satanás?","opcoes":[{"id":"a","texto":"Ignorar a existência de Satanás e do mal"},{"id":"b","texto":"Viver em constante medo e paranoia do diabo"},{"id":"c","texto":"Manter vigilância espiritual e confiar na proteção de Deus e na vitória de Cristo"},{"id":"d","texto":"Fazer pactos com Satanás para obter poder"}],"resposta_correta":"c","explicacao":"Os cristãos devem ser sábios quanto à existência e tática do maligno, mantendo vigilância espiritual. Porém, não deve haver medo, pois a vitória de Cristo é completa. Através da oração, da Palavra de Deus e da confiança em Seu poder, o crente é protegido.","referencias":[{"texto":"Efésios 6:10-12","livro":"Efésios","capitulo":6,"versiculo":"10-12","conteudo":"Revesti-vos de toda a armadura de Deus... porque a nossa luta não é contra a carne e o sangue, mas contra... as potestades do mal..."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço que o pecado e o mal não originaram de Deus, mas da rebelião de criaturas livres."},{"id":"cf2","texto":"Comprometo-me a entender a história da queda de Lúcifer e sua transformação em Satanás."},{"id":"cf3","texto":"Dedico-me a compreender como o mal afeta a humanidade e a manter vigilância espiritual."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 6, 'A Criação', 'Deus como Criador e Mantenedor', 'Este tema aborda a criação, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_06_q1","numero":1,"texto":"Qual é o significado da ordem da criação segundo as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Deus criou todas as coisas em ordem e perfeição, culminando com o ser humano no sexto dia"},{"id":"b","texto":"A criação aconteceu de forma caótica e desordenada"},{"id":"c","texto":"A ordem da criação não possui significado teológico"},{"id":"d","texto":"Os seres humanos foram criados antes de todas as outras criaturas"}],"resposta_correta":"a","explicacao":"A ordem da criação revela a sabedoria de Deus. Durante seis dias, Deus criou progressivamente: luz, céu, terra com vegetação, corpos celestes, animais, e finalmente o ser humano — a coroa da criação, feito à imagem de Deus.","referencias":[{"texto":"Gênesis 1:1-31","livro":"Gênesis","capitulo":1,"versiculo":"1-31","conteudo":"No princípio, criou Deus os céus e a terra... E viu Deus tudo quanto tinha feito, e eis que era muito bom."}]},{"id":"cf_06_q2","numero":2,"texto":"Quantos dias levou Deus para completar a criação?","opcoes":[{"id":"a","texto":"Três dias"},{"id":"b","texto":"Seis dias, descansando no sétimo"},{"id":"c","texto":"Um longo período indeterminado de bilhões de anos"},{"id":"d","texto":"Sete dias de trabalho contínuo"}],"resposta_correta":"b","explicacao":"Deus criou todas as coisas em seis dias e descansou no sétimo dia. Este repouso não foi por cansaço, mas para santificar o sétimo dia como memorial da criação e convite ao descanso em comunhão com o Criador.","referencias":[{"texto":"Gênesis 2:1-3","livro":"Gênesis","capitulo":2,"versiculo":"1-3","conteudo":"Assim foram acabados os céus e a terra e todo o seu exército. E, havendo Deus acabado no sétimo dia a sua obra... descansou..."}]},{"id":"cf_06_q3","numero":3,"texto":"O que distingue a criação do ser humano de todas as outras criaturas?","opcoes":[{"id":"a","texto":"O ser humano não tem distinção particular; é apenas um animal como os outros"},{"id":"b","texto":"Os seres humanos foram criados à imagem e semelhança de Deus com capacidade de relacionamento moral com Ele"},{"id":"c","texto":"Apenas os homens foram criados à imagem de Deus, não as mulheres"},{"id":"d","texto":"O ser humano foi criado imortal e incapaz de morrer"}],"resposta_correta":"b","explicacao":"O ser humano é a obra-prima da criação, criado à imagem e semelhança de Deus. Esta imagem confere dignidade especial, capacidade moral, livre arbítrio e potencial para relacionamento pessoal com o Criador — distinções não compartilhadas por outras criaturas.","referencias":[{"texto":"Gênesis 1:27","livro":"Gênesis","capitulo":1,"versiculo":"27","conteudo":"E criou Deus o homem à sua imagem, à imagem de Deus o criou; macho e fêmea os criou."}]},{"id":"cf_06_q4","numero":4,"texto":"Qual é o propósito da criação segundo as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Manifestar a glória, poder, sabedoria e amor de Deus através da existência de todas as coisas"},{"id":"b","texto":"Fornecer escravos para servir aos deuses celestiais"},{"id":"c","texto":"Criar um ambiente onde o mal e o bem competem igualmente"},{"id":"d","texto":"A criação não possui propósito definido; ela simplesmente existe"}],"resposta_correta":"a","explicacao":"O propósito da criação é manifestar os atributos eternos de Deus — Sua glória, poder infinito, sabedoria infinita e amor sem medida. Toda a criação, especialmente a humanidade, existe para refletir o caráter divino e render adoração ao Criador.","referencias":[{"texto":"Romanos 1:20","livro":"Romanos","capitulo":1,"versiculo":"20","conteudo":"Porque os atributos invisíveis de Deus, assim o seu eterno poder como também a sua própria divindade, claramente se reconhecem, desde o princípio do mundo, pela inteligência das coisas criadas."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço Deus como Criador de todas as coisas visíveis e invisíveis."},{"id":"cf2","texto":"Comprometo-me a aceitar a criação divina como narrativa fundamental da fé."},{"id":"cf3","texto":"Dedico-me a admirar e cuidar da criação como presente sagrado de Deus."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 7, 'O Plano da Redenção', 'Graça, Fé e Obras', 'Este tema aborda o plano da redenção, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_07_q1","numero":1,"texto":"Qual é o significado do Plano da Redenção nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"É o plano eterno de Deus para salvar a humanidade caída através da morte e ressurreição de Cristo"},{"id":"b","texto":"É um plano de Deus para punir eternamente toda a humanidade"},{"id":"c","texto":"É uma ideia tardia de Deus formulada após a queda do homem"},{"id":"d","texto":"É um plano de redenção que depende do merecimento da humanidade"}],"resposta_correta":"a","explicacao":"O Plano da Redenção é o propósito eterno de Deus para restaurar a humanidade pecaminosa. Através do sacrifício de Seu Filho Jesus Cristo, Deus oferece salvação gratuita a todos os que creem, reconciliando a humanidade consigo mesmo e abrindo o caminho para a vida eterna.","referencias":[{"texto":"Efésios 1:7-8","livro":"Efésios","capitulo":1,"versiculo":"7-8","conteudo":"Em quem temos a redenção pelo seu sangue, a remissão das ofensas, segundo as riquezas da sua graça..."}]},{"id":"cf_07_q2","numero":2,"texto":"Qual é o significado do sacrifício de Cristo na redenção?","opcoes":[{"id":"a","texto":"O sacrifício de Cristo é apenas um exemplo moral para a humanidade"},{"id":"b","texto":"O sacrifício de Cristo é a propiciação por nossos pecados e o cumprimento de todas as ofertas sacrificais"},{"id":"c","texto":"O sacrifício de Cristo não possui valor salvífico real"},{"id":"d","texto":"Existem muitos sacrifícios que salvam; o de Cristo é apenas um entre vários"}],"resposta_correta":"b","explicacao":"O sacrifício de Cristo na cruz é central para a redenção. Sua morte substitui nossa morte; Seu sangue limpa nossos pecados; Sua vida perfeita satisfaz a justiça de Deus. O sacrifício de Cristo cumpre e encerra o sistema de sacrifícios do Antigo Testamento, tornando-se a única oferta suficiente.","referencias":[{"texto":"Hebreus 9:26-28","livro":"Hebreus","capitulo":9,"versiculo":"26-28","conteudo":"...agora, uma única vez, na consumação dos séculos, se manifestou, para aniquilar... o pecado pelo sacrifício de si mesmo."}]},{"id":"cf_07_q3","numero":3,"texto":"A salvação é pela graça de Deus ou pelos nossos próprios esforços?","opcoes":[{"id":"a","texto":"A salvação depende inteiramente dos nossos esforços e mérito moral"},{"id":"b","texto":"A salvação é um presente gratuito de Deus, não merecido e adquirido pela fé em Cristo"},{"id":"c","texto":"A salvação é metade graça e metade nossos esforços"},{"id":"d","texto":"Deus salva automaticamente toda a humanidade sem necessidade de fé"}],"resposta_correta":"b","explicacao":"A salvação é inteiramente pela graça de Deus. Não podemos nos salvar pelos nossos próprios esforços ou justiça; ela é um presente divino. Recebemos esta graça através da fé em Cristo, não por obras, embora a fé genuína produza obras de obediência.","referencias":[{"texto":"Efésios 2:8-9","livro":"Efésios","capitulo":2,"versiculo":"8-9","conteudo":"Porque pela graça sois salvos, mediante a fé; e isto não vem de vós; é dom de Deus; não de obras, para que ninguém se glorie."}]},{"id":"cf_07_q4","numero":4,"texto":"Qual é o papel de Cristo na redenção?","opcoes":[{"id":"a","texto":"Cristo é meramente um profeta que ensinou sobre salvação"},{"id":"b","texto":"Cristo é nosso Redentor, Mediador e Defensor que se ofereceu em nosso lugar"},{"id":"c","texto":"Cristo é um entre muitos salvadores possíveis"},{"id":"d","texto":"Cristo tem um papel secundário na salvação; Deus o Pai salva diretamente"}],"resposta_correta":"b","explicacao":"Cristo é absolutamente central na redenção. Como nosso Redentor, Ele nos liberta do pecado e seus efeitos. Como Mediador, intercede por nós diante de Deus. Como Defensor (Advogado), representa nossa causa ante o Pai. Seu sacrifício substitutivo é o fundamento de toda a salvação.","referencias":[{"texto":"1 Timóteo 2:5-6","livro":"1 Timóteo","capitulo":2,"versiculo":"5-6","conteudo":"Porque há um só Deus, e um só mediador entre Deus e os homens, Jesus Cristo, homem; que se deu a si mesmo em resgate por todos..."}]},{"id":"cf_07_q5","numero":5,"texto":"Qual é a importância da ressurreição de Cristo para a redenção?","opcoes":[{"id":"a","texto":"A ressurreição prova que Cristo venceu a morte e oferece esperança de vida eterna aos crentes"},{"id":"b","texto":"A ressurreição é um evento histórico sem importância espiritual"},{"id":"c","texto":"A ressurreição de Cristo não afeta a salvação"},{"id":"d","texto":"Apenas a morte de Cristo importa; a ressurreição é secundária"}],"resposta_correta":"a","explicacao":"A ressurreição de Cristo é fundamental para a redenção. Prova Sua vitória sobre a morte e sobre Satanás. Oferece às vítimas do pecado esperança de ressurreição eterna. Sem a ressurreição, a morte teria a última palavra; com ela, a vida eterna é garantida aos crentes.","referencias":[{"texto":"Romanos 6:9-10","livro":"Romanos","capitulo":6,"versiculo":"9-10","conteudo":"Cristo, ressurreto dentre os mortos, não mais morre. A morte não tem mais domínio sobre ele. Pois, quanto a ter morrido, de uma vez por todas morreu para o pecado..."}]},{"id":"cf_07_q6","numero":6,"texto":"Qual é o papel de Cristo no céu como nosso Intercessor?","opcoes":[{"id":"a","texto":"Cristo não faz nada no céu; Sua obra terminou na cruz"},{"id":"b","texto":"Cristo está sentado à destra de Deus e intercede continuamente por todos os crentes"},{"id":"c","texto":"Cristo apenas repousa no céu sem qualquer atividade"},{"id":"d","texto":"Precisamos ir diretamente a Deus Pai; Cristo não intercede por nós"}],"resposta_correta":"b","explicacao":"Após Sua ascensão, Cristo está à destra do Pai no céu, onde funciona como nosso Sumo Sacerdote e Intercessor. Ele continuamente apresenta nossas orações e nossas necessidades ao Pai, nunca cessando de interceder por aqueles que nele creem, assegurando nossa aceitação diante de Deus.","referencias":[{"texto":"Hebreus 7:25","livro":"Hebreus","capitulo":7,"versiculo":"25","conteudo":"Por isso, pode também salvar completamente os que por ele se chegam a Deus, vivendo sempre para interceder por eles."}]},{"id":"cf_07_q7","numero":7,"texto":"Como o perdão de pecados é garantido através da redenção?","opcoes":[{"id":"a","texto":"Deus perdoa automaticamente todos os pecados sem qualquer resposta do ser humano"},{"id":"b","texto":"O perdão é garantido pela confissão sincera, arrependimento e fé na morte e ressurreição de Cristo"},{"id":"c","texto":"O perdão é possível apenas através de rituais da Igreja"},{"id":"d","texto":"Alguns pecados não podem ser perdoados, independentemente da fé"}],"resposta_correta":"b","explicacao":"O perdão dos pecados é um benefício da redenção oferecido a todos. Porém, requer nossa resposta: confissão sincera do pecado, arrependimento genuíno (mudança de direção), e fé em Cristo. Quando respondemos assim, Deus remove completamente nossos pecados e nos restaura ao relacionamento com Ele.","referencias":[{"texto":"1 João 1:8-9","livro":"1 João","capitulo":1,"versiculo":"8-9","conteudo":"Se dissermos que não temos pecado, enganamos a nós mesmos... se confessarmos os nossos pecados, ele é fiel e justo para perdoar os nossos pecados..."}]},{"id":"cf_07_q8","numero":8,"texto":"Qual é a restauração oferecida pela redenção?","opcoes":[{"id":"a","texto":"Apenas o perdão dos pecados, sem mudança de natureza"},{"id":"b","texto":"Restauração completa: perdão do passado, transformação presente e esperança de vida eterna futura"},{"id":"c","texto":"Restauração apenas do corpo físico; a alma permanece danificada"},{"id":"d","texto":"Restauração que depende do comportamento contínuo do crente"}],"resposta_correta":"b","explicacao":"A redenção oferece restauração integral. Passado: perdão completo de toda culpa. Presente: transformação pelo Espírito Santo, sendo renovados à imagem de Cristo. Futuro: esperança de vida eterna, ressurreição, e novo céu e nova terra. A redenção toca toda pessoa — espírito, alma e corpo.","referencias":[{"texto":"2 Coríntios 5:17","livro":"2 Coríntios","capitulo":5,"versiculo":"17","conteudo":"De modo que, se alguém está em Cristo, é nova criatura; as coisas antigas passaram; eis que se fizeram novas."}]},{"id":"cf_07_q9","numero":9,"texto":"A redenção é um evento único ou um processo contínuo?","opcoes":[{"id":"a","texto":"A redenção é apenas um momento único de conversão, sem necessidade de crescimento posterior"},{"id":"b","texto":"A redenção é um processo contínuo de transformação espiritual após nossa resposta inicial de fé"},{"id":"c","texto":"A redenção acontece apenas uma vez a cada semana"},{"id":"d","texto":"A redenção não oferece transformação; é apenas um escape futuro do inferno"}],"resposta_correta":"b","explicacao":"A redenção começa com um ato de fé em Cristo, mas continua como processo. A justificação é instantânea; a santificação é progressiva. O Espírito Santo continuamente nos transforma, levando-nos a maior semelhança com Cristo até a glorificação final.","referencias":[{"texto":"Filipenses 1:6","livro":"Filipenses","capitulo":1,"versiculo":"6","conteudo":"Estando persuadido disto, que aquele que começou em vós boa obra a aperfeiçoará até ao dia de Jesus Cristo."}]},{"id":"cf_07_q10","numero":10,"texto":"Como a morte de Cristo garante nossa vida eterna?","opcoes":[{"id":"a","texto":"A morte de Cristo não oferece qualquer garantia de vida eterna"},{"id":"b","texto":"Através de Sua morte substitutiva, Cristo pagou o preço do pecado e venceu a morte, abrindo o caminho para a ressurreição eterna"},{"id":"c","texto":"Apenas os que vivem perfeitamente herdam a vida eterna; a morte de Cristo é opcional"},{"id":"d","texto":"A vida eterna é garantida independentemente de nossa fé em Cristo"}],"resposta_correta":"b","explicacao":"A morte de Cristo é substitutiva — Ele morreu em nosso lugar, pagando a penalidade do pecado que é morte. Sua ressurreição prova poder sobre a morte. Quando cremos em Cristo, participamos de Sua morte (morte para o pecado) e ressurreição (vida eterna), garantindo nossa ressurreição e imortalidade futura.","referencias":[{"texto":"Romanos 5:8-9","livro":"Romanos","capitulo":5,"versiculo":"8-9","conteudo":"Mas Deus prova o seu próprio amor para conosco pelo fato de Cristo ter morrido por nós quando ainda éramos pecadores... muito mais, pois, sendo justificados agora pelo seu sangue, seremos salvos da ira por ele."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço a salvação como plano eterno de Deus através de Cristo."},{"id":"cf2","texto":"Comprometo-me a aceitar a graça salvadora de Deus pela fé em Cristo."},{"id":"cf3","texto":"Dedico-me a demonstrar a fé através de obras de amor e obediência a Deus."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 8, 'Batismo', 'O Sinal Exterior da Conversão Interior', 'Este tema aborda batismo, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_08_q1","numero":1,"texto":"Qual é o significado do batismo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"O batismo é um ato solene de dedicação a Cristo, sinal visível de morte ao pecado, sepultamento com Cristo, e ressurreição para nova vida"},{"id":"b","texto":"O batismo é apenas uma cerimônia tradicional sem significado espiritual profundo"},{"id":"c","texto":"O batismo é um sacramento que concede salvação automaticamente"},{"id":"d","texto":"O batismo é uma prática opcional que não afeta a fé cristã"}],"resposta_correta":"a","explicacao":"O batismo é um ato solene onde o crente se dedica a Cristo e é identificado com Sua morte, sepultamento e ressurreição. É o sinal exterior de uma transformação interior, representando morte ao pecado e ressurreição para nova vida espiritual.","referencias":[{"texto":"Romanos 6:3-4","livro":"Romanos","capitulo":6,"versiculo":"3-4","conteudo":"Ou não sabeis que todos quantos fomos batizados em Jesus Cristo fomos batizados na sua morte? De sorte que fomos sepultados com ele pelo batismo na morte..."}]},{"id":"cf_08_q2","numero":2,"texto":"Qual é a forma correta de batismo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"O batismo deve ser feito por aspersão (borrifar água)"},{"id":"b","texto":"O batismo deve ser feito por imersão (imergir completamente no água)"},{"id":"c","texto":"O batismo pode ser feito de qualquer forma que o oficiante escolher"},{"id":"d","texto":"A forma do batismo não tem importância bíblica"}],"resposta_correta":"b","explicacao":"O batismo por imersão é a forma bíblica que melhor representa a morte, sepultamento e ressurreição de Cristo. A imersão completa na água simboliza de forma mais apropriada o ato de enterramento com Cristo e a nova ressurreição espiritual.","referencias":[{"texto":"Atos 8:36-39","livro":"Atos","capitulo":8,"versiculo":"36-39","conteudo":"E, indo pelo caminho, chegaram a um poço de água; e disse o eunuco: Eis aqui água; que impede que eu seja batizado? E respondeu Felipe: Se crês de todo coração, bem o podes."}]},{"id":"cf_08_q3","numero":3,"texto":"Quem pode ser batizado segundo as Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Apenas crianças recém-nascidas devem ser batizadas"},{"id":"b","texto":"Qualquer pessoa, independentemente de sua fé, pode ser batizada"},{"id":"c","texto":"Aqueles que acreditam em Jesus Cristo, se arrependem de seus pecados e fazem uma decisão consciente de seguir a Cristo"},{"id":"d","texto":"O batismo é reservado apenas para pessoas de uma determinada idade"}],"resposta_correta":"c","explicacao":"O batismo é para aqueles que experimentaram novo nascimento espiritual genuíno. Requer fé consciente em Cristo, arrependimento sincero de pecados, e decisão deliberada de seguir Jesus. O batismo de crentes, não de infantes, é o modelo bíblico.","referencias":[{"texto":"Atos 2:37-38","livro":"Atos","capitulo":2,"versiculo":"37-38","conteudo":"E, ouvindo isto, compungiram-se em seu coração, e perguntaram a Pedro e aos outros apóstolos: Homens irmãos, que faremos? E disse-lhes Pedro: Arrependei-vos, e cada um de vós seja batizado..."}]},{"id":"cf_08_q4","numero":4,"texto":"Qual é a relação entre o batismo e a salvação nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"O batismo em si salva a pessoa automaticamente"},{"id":"b","texto":"O batismo não tem nenhuma relação com a salvação"},{"id":"c","texto":"A salvação vem pela graça de Cristo mediante a fé, e o batismo é a resposta obediente daquele que já foi salvo"},{"id":"d","texto":"O batismo é uma salvação parcial até a pessoa viver corretamente"}],"resposta_correta":"c","explicacao":"A salvação é pela graça de Deus através de Cristo, apropriada pela fé. O batismo é o ato obediente de quem já foi salvo, expressando publicamente a decisão de entregar-se a Cristo e vivificar a nova vida em Seu serviço.","referencias":[{"texto":"Efésios 2:8-9","livro":"Efésios","capitulo":2,"versiculo":"8-9","conteudo":"Porque pela graça sois salvos, por meio da fé; e isto não vem de vós, é dom de Deus; não vem das obras, para que ninguém se glorie."}]},{"id":"cf_08_q5","numero":5,"texto":"Qual é o propósito de renovação de votos ou rededição ao batismo?","opcoes":[{"id":"a","texto":"Renovar o compromisso com Cristo e as promessas feitas no batismo quando há necessidade de consagração renovada"},{"id":"b","texto":"Fazer um novo batismo para apagar pecados cometidos depois do primeiro batismo"},{"id":"c","texto":"A renovação de votos não é bíblica ou apropriada"},{"id":"d","texto":"A renovação de votos torna o primeiro batismo inválido"}],"resposta_correta":"a","explicacao":"A renovação de votos batismais é apropriada quando o crente busca rededição renovada a Cristo após afastamento ou falha espiritual. Não é um novo batismo, mas uma reafirmação solene do compromisso original feito com Cristo no batismo.","referencias":[{"texto":"2 Pedro 1:10","livro":"2 Pedro","capitulo":1,"versiculo":"10","conteudo":"Pelo que, irmãos, procurai com diligência fazer firme a vossa vocação e eleição; porque, fazendo isto, nunca tropeçareis."}]},{"id":"cf_08_q6","numero":6,"texto":"O batismo bíblico requer uma confissão pública de fé em Jesus Cristo?","opcoes":[{"id":"a","texto":"Não, o batismo é um ato privado e individual sem necessidade de confissão pública"},{"id":"b","texto":"Sim, o batismo envolve confissão pública de fé em Jesus Cristo diante de testemunhas"},{"id":"c","texto":"A confissão de fé é opcional e depende da pessoa"},{"id":"d","texto":"A confissão de fé só é necessária após o batismo, não antes"}],"resposta_correta":"b","explicacao":"O batismo bíblico inclui confissão pública de fé em Cristo. Esta confissão é parte essencial do ato batismal, representando compromisso aberto e declarado de seguir Jesus como Senhor e Salvador diante da comunidade.","referencias":[{"texto":"Mateus 10:32-33","livro":"Mateus","capitulo":10,"versiculo":"32-33","conteudo":"Portanto, qualquer que me confessar diante dos homens, eu o confessarei também diante de meu Pai que está nos céus. Mas qualquer que me negar diante dos homens, eu o negarei também..."}]},{"id":"cf_08_q7","numero":7,"texto":"Por que a imersão completa é preferida ao invés de outras formas de batismo?","opcoes":[{"id":"a","texto":"A imersão é menos prática e simbólica que outras formas"},{"id":"b","texto":"A imersão é apenas uma preferência cultural sem base bíblica"},{"id":"c","texto":"A imersão completa melhor simboliza o sepultamento com Cristo e a ressurreição em nova vida, conforme revelado na Escritura"},{"id":"d","texto":"Todas as formas de batismo têm igual valor simbólico"}],"resposta_correta":"c","explicacao":"A imersão completa é a forma que melhor apresenta o significado teológico do batismo. Submerge-se na água como sepultamento, representando morte ao pecado e identificação com a morte de Cristo, e emerge-se como ressurreição para nova vida.","referencias":[{"texto":"Colossenses 2:12","livro":"Colossenses","capitulo":2,"versiculo":"12","conteudo":"Sepultados com ele no batismo, nele também ressuscitastes pela fé no poder de Deus, que o ressuscitou dos mortos."}]},{"id":"cf_08_q8","numero":8,"texto":"Qual tipo de fé é necessária antes do batismo?","opcoes":[{"id":"a","texto":"Nenhuma fé é necessária; o batismo funciona por si"},{"id":"b","texto":"Uma fé teórica superficial é suficiente"},{"id":"c","texto":"Uma fé instrumental onde se acredita mas não há compromisso"},{"id":"d","texto":"Uma fé genuína e viva em Jesus Cristo como Salvador pessoal, com arrependimento sincero e compromisso de discipulado"}],"resposta_correta":"d","explicacao":"O batismo requer fé verdadeira e viva em Cristo. Não é suficiente apenas crer intelectualmente; é necessário arrependimento genuíno do pecado e compromisso sincero de seguir Jesus como Senhor e Mestre da vida.","referencias":[{"texto":"Marcos 16:16","livro":"Marcos","capitulo":16,"versiculo":"16","conteudo":"Quem crer e for batizado será salvo; mas quem não crer será condenado."}]},{"id":"cf_08_q9","numero":9,"texto":"O batismo está intrinsecamente conectado ao novo nascimento espiritual?","opcoes":[{"id":"a","texto":"Sim, o batismo é a manifestação pública e obediente do novo nascimento que já ocorreu na conversão"},{"id":"b","texto":"Não, o novo nascimento e batismo não têm relação"},{"id":"c","texto":"Apenas o batismo causa novo nascimento, independentemente da fé"},{"id":"d","texto":"O novo nascimento ocorre apenas após muitos anos de vida cristã batizada"}],"resposta_correta":"a","explicacao":"O batismo é a resposta obediente e pública do novo nascimento espiritual. Primeiro ocorre a conversão — morte ao pecado e novo nascimento pela graça de Deus — depois o batismo a declara publicamente perante a comunidade de fé.","referencias":[{"texto":"João 3:3-7","livro":"João","capitulo":3,"versiculo":"3-7","conteudo":"Jesus respondeu e disse-lhe: Na verdade, na verdade te digo que aquele que não nascer de novo, não pode ver o reino de Deus... O que é nascido da carne é carne, e o que é nascido do Espírito é espírito."}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço o batismo como ato solene de consagração a Cristo e identificação com Sua morte, sepultamento e ressurreição."},{"id":"cf2","texto":"Comprometo-me a entender o batismo como sinal exterior de uma transformação interior e novo nascimento espiritual."},{"id":"cf3","texto":"Dedico-me a preparar-me conscientemente para receber o batismo por imersão após confissão de fé em Jesus Cristo."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 9, 'A Cerimônia da Comunhão', 'Lava-pés e Santa Ceia', 'Este tema aborda a cerimônia da comunhão, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_09_q1","numero":1,"texto":"Qual é a importância de significado da Comunhão nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a significado da Comunhão"},{"id":"b","texto":"Opção B relacionada a significado da Comunhão"},{"id":"c","texto":"Opção C relacionada a significado da Comunhão"},{"id":"d","texto":"Opção D relacionada a significado da Comunhão"}],"resposta_correta":"a","explicacao":"A Comunhão representa o memorial do sacrifício de Cristo e a renovação do compromisso com Ele. É um ato central na adoração cristã que simboliza a aceitação da morte expiatória de Jesus.","referencias":[{"texto":"Porque eu recebi do Senhor aquilo que também vos entreguei","livro":"1 Coríntios","capitulo":11,"versiculo":23,"conteudo":"Porque eu recebi do Senhor aquilo que também vos entreguei: que o Senhor Jesus, na noite em que foi traído, tomou pão;"}]},{"id":"cf_09_q2","numero":2,"texto":"Qual é a importância de pão e vinho nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a pão e vinho"},{"id":"b","texto":"Opção B relacionada a pão e vinho"},{"id":"c","texto":"Opção C relacionada a pão e vinho"},{"id":"d","texto":"Opção D relacionada a pão e vinho"}],"resposta_correta":"b","explicacao":"O pão representa o corpo de Cristo quebrantado por nós, enquanto o vinho simboliza seu sangue derramado pela remissão dos pecados.","referencias":[{"texto":"E, tomando um pão, depois de dar graças, partiu-o e lhes deu","livro":"Lucas","capitulo":22,"versiculo":19,"conteudo":"E, tomando um pão, depois de dar graças, partiu-o e lhes deu, dizendo: Isto é o meu corpo, que por vós é dado; fazei isto em memória de mim."}]},{"id":"cf_09_q3","numero":3,"texto":"Qual é a importância de frequência nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a frequência"},{"id":"b","texto":"Opção B relacionada a frequência"},{"id":"c","texto":"Opção C relacionada a frequência"},{"id":"d","texto":"Opção D relacionada a frequência"}],"resposta_correta":"c","explicacao":"A frequência apropriada da Comunhão é regular, geralmente mensal. Esta frequência permite uma renovação contínua do compromisso com Cristo.","referencias":[{"texto":"Fazei isto em memória de mim","livro":"1 Coríntios","capitulo":11,"versiculo":25,"conteudo":"Fazei isto em memória de mim"}]},{"id":"cf_09_q4","numero":4,"texto":"Qual é a importância de quem pode participar nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a quem pode participar"},{"id":"b","texto":"Opção B relacionada a quem pode participar"},{"id":"c","texto":"Opção C relacionada a quem pode participar"},{"id":"d","texto":"Opção D relacionada a quem pode participar"}],"resposta_correta":"d","explicacao":"Apenas membros batizados da igreja que professam fé em Cristo podem participar. Esta prática protege a sacralidade e mantém a unidade espiritual.","referencias":[{"texto":"Portanto, qualquer que comer este pão ou beber o cálice do Senhor indignamente","livro":"1 Coríntios","capitulo":11,"versiculo":27,"conteudo":"Portanto, qualquer que comer este pão ou beber o cálice do Senhor indignamente, será culpado do corpo e do sangue do Senhor."}]},{"id":"cf_09_q5","numero":5,"texto":"Qual é a importância de preparação nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a preparação"},{"id":"b","texto":"Opção B relacionada a preparação"},{"id":"c","texto":"Opção C relacionada a preparação"},{"id":"d","texto":"Opção D relacionada a preparação"}],"resposta_correta":"a","explicacao":"A preparação espiritual é essencial antes de participar, incluindo exame de consciência, arrependimento, reconciliação com o próximo e renovação da dedicação a Cristo.","referencias":[{"texto":"Examine-se o homem a si mesmo","livro":"1 Coríntios","capitulo":11,"versiculo":28,"conteudo":"Examine-se o homem a si mesmo, e assim coma do pão, e beba do cálice."}]},{"id":"cf_09_q6","numero":6,"texto":"Qual é a importância de perdão de pecados nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a perdão de pecados"},{"id":"b","texto":"Opção B relacionada a perdão de pecados"},{"id":"c","texto":"Opção C relacionada a perdão de pecados"},{"id":"d","texto":"Opção D relacionada a perdão de pecados"}],"resposta_correta":"b","explicacao":"A Comunhão afirma visualmente a remissão de pecados através do sacrifício de Cristo. Reafirma continuamente a confiança no perdão divino.","referencias":[{"texto":"isto é o meu sangue da aliança, que é derramado por muitos para remissão dos pecados","livro":"Mateus","capitulo":26,"versiculo":28,"conteudo":"Porque isto é o meu sangue da aliança, que é derramado por muitos para remissão dos pecados."}]},{"id":"cf_09_q7","numero":7,"texto":"Qual é a importância de lembança nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a lembança"},{"id":"b","texto":"Opção B relacionada a lembança"},{"id":"c","texto":"Opção C relacionada a lembança"},{"id":"d","texto":"Opção D relacionada a lembança"}],"resposta_correta":"c","explicacao":"A Comunhão é um ato de memória - \"Fazei isto em memória de mim\". Mantém fresca na memória a morte de Cristo e seus benefícios.","referencias":[{"texto":"Fazei isto em memória de mim","livro":"Lucas","capitulo":22,"versiculo":19,"conteudo":"E, tomando um pão, depois de dar graças, partiu-o e lhes deu, dizendo: Isto é o meu corpo, que por vós é dado; fazei isto em memória de mim."}]},{"id":"cf_09_q8","numero":8,"texto":"Qual é a importância de comunhão com Cristo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a comunhão com Cristo"},{"id":"b","texto":"Opção B relacionada a comunhão com Cristo"},{"id":"c","texto":"Opção C relacionada a comunhão com Cristo"},{"id":"d","texto":"Opção D relacionada a comunhão com Cristo"}],"resposta_correta":"d","explicacao":"Através da Comunhão, participamos espiritualmente da vida e vitória de Cristo. Esta representa uma real experiência espiritual de identificação com Cristo.","referencias":[{"texto":"porque todos nós somos um só corpo em Cristo","livro":"Romanos","capitulo":12,"versiculo":5,"conteudo":"assim também nós, embora muitos, somos um só corpo em Cristo, mas individualmente somos membros uns dos outros."}]},{"id":"cf_09_q9","numero":9,"texto":"Qual é a importância de poder espiritual nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a poder espiritual"},{"id":"b","texto":"Opção B relacionada a poder espiritual"},{"id":"c","texto":"Opção C relacionada a poder espiritual"},{"id":"d","texto":"Opção D relacionada a poder espiritual"}],"resposta_correta":"a","explicacao":"A celebração da Comunhão com fé libera poder espiritual na vida do crente. Fortalece a fé, renova o compromisso espiritual.","referencias":[{"texto":"porque este é o meu corpo. Fazei isto em memória de mim","livro":"1 Coríntios","capitulo":11,"versiculo":24,"conteudo":"e, tendo dado graças, partiu-o e disse: Isto é o meu corpo, que é por vós; fazei isto em memória de mim."}]}]'::jsonb, '[{"id":"cf1","texto":"Participar regularmente da Santa Ceia como memorial da morte de Cristo e expressão de fé no sacrifício expiatório."},{"id":"cf2","texto":"Preparar-se espiritualmente para a cerimônia através do exame de consciência e reconciliação com o próximo."},{"id":"cf3","texto":"Praticar a cerimônia do lava-pés como ato de humildade e amor fraternale demonstração de disposição para servir."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 10, 'O Santuário', 'O Ministério de Cristo no Céu', 'Este tema aborda o santuário, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_10_q1","numero":1,"texto":"Qual é a importância de estrutura do Santuário nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a estrutura do Santuário"},{"id":"b","texto":"Opção B relacionada a estrutura do Santuário"},{"id":"c","texto":"Opção C relacionada a estrutura do Santuário"},{"id":"d","texto":"Opção D relacionada a estrutura do Santuário"}],"resposta_correta":"a","explicacao":"O santuário tinha três seções principais: o pátio, o lugar santo e o santíssimo lugar, cada um representando aspectos diferentes do ministério de Cristo e nossa experiência de salvação com Ele.","referencias":[{"texto":"Ele fez, segundo o padrão que o Senhor lhe havia mostrado","livro":"Êxodo","capitulo":36,"versiculo":1,"conteudo":"Assim trabalhou Bezaleel e Ooliabe, e todo aquele que o Senhor deu sabedoria e inteligência para saber como fazer toda obra do santuário."}]},{"id":"cf_10_q2","numero":2,"texto":"Qual é a importância de significado do Santuário nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a significado do Santuário"},{"id":"b","texto":"Opção B relacionada a significado do Santuário"},{"id":"c","texto":"Opção C relacionada a significado do Santuário"},{"id":"d","texto":"Opção D relacionada a significado do Santuário"}],"resposta_correta":"b","explicacao":"O santuário terrestre foi um modelo do ministério celestial de Cristo. Seus móveis e serviços ilustravam a salvação através da morte de Cristo e seu intercessão contínua em nosso favor no céu.","referencias":[{"texto":"porque eles servem de cópia e sombra das coisas celestiais","livro":"Hebreus","capitulo":8,"versiculo":5,"conteudo":"os quais servem de cópia e sombra das coisas celestiais, como foi revelado a Moisés quando ia edificar o tabernáculo; porque foi dito: Atende que tudo faças conforme o modelo que te foi mostrado no monte."}]},{"id":"cf_10_q3","numero":3,"texto":"Qual é a importância de serviço diário nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a serviço diário"},{"id":"b","texto":"Opção B relacionada a serviço diário"},{"id":"c","texto":"Opção C relacionada a serviço diário"},{"id":"d","texto":"Opção D relacionada a serviço diário"}],"resposta_correta":"c","explicacao":"O serviço diário do santuário incluía o sacrifício da manhã e da tarde, simbolizando a obra contínua de Cristo. Isto prefigurava seu ministério perpétuo de intercessão em nosso favor no santuário celestial.","referencias":[{"texto":"sempre vivendo para interceder por eles","livro":"Hebreus","capitulo":7,"versiculo":25,"conteudo":"por isso também pode salvar completamente os que por ele se chegam a Deus, vivendo sempre para interceder por eles."}]},{"id":"cf_10_q4","numero":4,"texto":"Qual é a importância de serviço anual nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a serviço anual"},{"id":"b","texto":"Opção B relacionada a serviço anual"},{"id":"c","texto":"Opção C relacionada a serviço anual"},{"id":"d","texto":"Opção D relacionada a serviço anual"}],"resposta_correta":"d","explicacao":"O Dia da Expiação era o ponto culminante do ano religioso, quando o sumo sacerdote entrava no santíssimo lugar para fazer expiação pelos pecados. Isto representava o ministério final de purificação de Cristo.","referencias":[{"texto":"ele mesmo é a propiciação pelos nossos pecados","livro":"1 João","capitulo":2,"versiculo":2,"conteudo":"E ele é a propiciação pelos nossos pecados, e não somente pelos nossos, mas também pelos de todo o mundo."}]},{"id":"cf_10_q5","numero":5,"texto":"Qual é a importância de Dia da Expiação nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a Dia da Expiação"},{"id":"b","texto":"Opção B relacionada a Dia da Expiação"},{"id":"c","texto":"Opção C relacionada a Dia da Expiação"},{"id":"d","texto":"Opção D relacionada a Dia da Expiação"}],"resposta_correta":"a","explicacao":"O Dia da Expiação representava o juízo investigativo e a purificação final. Sua celebração anual prefigurava os eventos dos últimos dias quando Cristo faria sua obra final de expiação.","referencias":[{"texto":"para purgar os pecados do povo","livro":"Hebreus","capitulo":1,"versiculo":3,"conteudo":"sendo ele o resplendor da glória, e a expressa imagem da sua pessoa, e sustentando todas as coisas pela palavra do seu poder, havendo feito por si mesmo a purificação dos nossos pecados, assentou-se à destra da majestade nas alturas;"}]},{"id":"cf_10_q6","numero":6,"texto":"Qual é a importância de símbolos nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a símbolos"},{"id":"b","texto":"Opção B relacionada a símbolos"},{"id":"c","texto":"Opção C relacionada a símbolos"},{"id":"d","texto":"Opção D relacionada a símbolos"}],"resposta_correta":"b","explicacao":"Cada elemento do santuário era simbólico: o altar de bronze representava o calvário, a pia de bronze a purificação, o candelabro a iluminação divina, a mesa dos pães a sustentação, e o altar de incenso a intercessão.","referencias":[{"texto":"Tudo isto lhes sobreveio como figuras","livro":"1 Coríntios","capitulo":10,"versiculo":11,"conteudo":"Ora, tudo isto lhes sobreveio como figuras, e foi escrito para nossa admoestação, para quem já são chegados os fins dos séculos."}]},{"id":"cf_10_q7","numero":7,"texto":"Qual é a importância de sacerdócio nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a sacerdócio"},{"id":"b","texto":"Opção B relacionada a sacerdócio"},{"id":"c","texto":"Opção C relacionada a sacerdócio"},{"id":"d","texto":"Opção D relacionada a sacerdócio"}],"resposta_correta":"c","explicacao":"Cristo é nosso Sumo Sacerdote que ofereceu o sacrifício perfeito uma vez por todas. Ele intercede continuamente por nós, garantindo a aplicação de sua morte salvadora à nossa vida individual.","referencias":[{"texto":"temos um grande sumo sacerdote","livro":"Hebreus","capitulo":4,"versiculo":14,"conteudo":"Temos, pois, um grande sumo sacerdote, Jesus, Filho de Deus, que penetrou os céus; retenhamos a nossa confissão."}]},{"id":"cf_10_q8","numero":8,"texto":"Qual é a importância de cortina do véu nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a cortina do véu"},{"id":"b","texto":"Opção B relacionada a cortina do véu"},{"id":"c","texto":"Opção C relacionada a cortina do véu"},{"id":"d","texto":"Opção D relacionada a cortina do véu"}],"resposta_correta":"d","explicacao":"O véu separava o lugar santo do santíssimo lugar, representando a separação entre Deus e o homem pecador. Quando Cristo morreu, o véu se rasgou, indicando acesso direto a Deus através de Cristo.","referencias":[{"texto":"o véu do templo se rasgou em dois, de alto a baixo","livro":"Mateus","capitulo":27,"versiculo":51,"conteudo":"E eis que o véu do templo se rasgou em dois, de alto a baixo; e tremeu a terra, e as pedras se fenderam;"}]},{"id":"cf_10_q9","numero":9,"texto":"Qual é a importância de Santíssimo lugar nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a Santíssimo lugar"},{"id":"b","texto":"Opção B relacionada a Santíssimo lugar"},{"id":"c","texto":"Opção C relacionada a Santíssimo lugar"},{"id":"d","texto":"Opção D relacionada a Santíssimo lugar"}],"resposta_correta":"a","explicacao":"O Santíssimo lugar era o local mais sagrado, onde se encontrava a Arca da Aliança e onde Deus manifestava sua presença. Representava a presença divina no santuário celestial onde Cristo trabalha.","referencias":[{"texto":"aquele que é verdadeiramente tabernáculo, que o Senhor armou","livro":"Hebreus","capitulo":8,"versiculo":2,"conteudo":"ministro do santuário, e do verdadeiro tabernáculo, que o Senhor armou, e não o homem."}]},{"id":"cf_10_q10","numero":10,"texto":"Qual é a importância de propósito tipológico nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a propósito tipológico"},{"id":"b","texto":"Opção B relacionada a propósito tipológico"},{"id":"c","texto":"Opção C relacionada a propósito tipológico"},{"id":"d","texto":"Opção D relacionada a propósito tipológico"}],"resposta_correta":"b","explicacao":"Todo o sistema de santuário era tipológico, apontando para Cristo como o antitripo. A compreensão deste sistema profético ajuda-nos a apreciar plenamente a obra redentora de Cristo.","referencias":[{"texto":"porque a lei tem a sombra dos bens futuros","livro":"Hebreus","capitulo":10,"versiculo":1,"conteudo":"Porque a lei, tendo a sombra dos bens futuros, e não a imagem exata das coisas, nunca pode com os mesmos sacrifícios, que continuamente se oferecem cada ano, aperfeiçoar os que a eles se chegam."}]}]'::jsonb, '[{"id":"cf1","texto":"Aceitar a realidade do santuário celestial e o ministério contínuo de Cristo como nosso sumo sacerdote intercessor."},{"id":"cf2","texto":"Compreender o significado tipológico do santuário terrestre como prefiguração do ministério de Cristo no céu."},{"id":"cf3","texto":"Aplicar os princípios do santuário à vida espiritual, reconhecendo Cristo como nosso sacrifício perpétuo e intercessor."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 11, 'As Mensagens dos Três Anjos', 'A Última Advertência ao Mundo', 'Este tema aborda as mensagens dos três anjos, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_11_q1","numero":1,"texto":"Qual é a importância de primeira mensagem angélica nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a primeira mensagem angélica"},{"id":"b","texto":"Opção B relacionada a primeira mensagem angélica"},{"id":"c","texto":"Opção C relacionada a primeira mensagem angélica"},{"id":"d","texto":"Opção D relacionada a primeira mensagem angélica"}],"resposta_correta":"a","explicacao":"A primeira mensagem convida ao temor de Deus e adoração verdadeira, anunciando o evangelho eterno antes do juízo divino.","referencias":[{"texto":"Então vi outro anjo voando pelo meio do céu","livro":"Apocalipse","capitulo":14,"versiculo":6,"conteudo":"Então vi outro anjo voando pelo meio do céu, que tinha o evangelho eterno para pregá-lo aos que habitam sobre a terra, e a toda a nação, e tribo, e língua, e povo,"}]},{"id":"cf_11_q2","numero":2,"texto":"Qual é a importância de segunda mensagem angélica nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a segunda mensagem angélica"},{"id":"b","texto":"Opção B relacionada a segunda mensagem angélica"},{"id":"c","texto":"Opção C relacionada a segunda mensagem angélica"},{"id":"d","texto":"Opção D relacionada a segunda mensagem angélica"}],"resposta_correta":"b","explicacao":"A segunda mensagem anuncia a queda de Babilônia, representando o colapso de sistemas religiosos falsos e organizações que se opõem à verdade divina.","referencias":[{"texto":"Caiu, caiu a grande Babilônia","livro":"Apocalipse","capitulo":14,"versiculo":8,"conteudo":"E seguiu-o outro anjo, dizendo: Caiu, caiu a grande Babilônia, que fez beber a todas as nações do vinho da ira da sua fornicação."}]},{"id":"cf_11_q3","numero":3,"texto":"Qual é a importância de terceira mensagem angélica nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a terceira mensagem angélica"},{"id":"b","texto":"Opção B relacionada a terceira mensagem angélica"},{"id":"c","texto":"Opção C relacionada a terceira mensagem angélica"},{"id":"d","texto":"Opção D relacionada a terceira mensagem angélica"}],"resposta_correta":"c","explicacao":"A terceira mensagem adverte contra a adoração da besta e sua imagem, exortando a manter os mandamentos de Deus e a fé em Jesus.","referencias":[{"texto":"Se alguém adorar a besta e a sua imagem","livro":"Apocalipse","capitulo":14,"versiculo":9,"conteudo":"E o terceiro anjo os seguiu, dizendo com grande voz: Se alguém adorar a besta, e a sua imagem, e receber o sinal na sua testa, ou na sua mão,"}]},{"id":"cf_11_q4","numero":4,"texto":"Qual é a importância de propósito das mensagens nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a propósito das mensagens"},{"id":"b","texto":"Opção B relacionada a propósito das mensagens"},{"id":"c","texto":"Opção C relacionada a propósito das mensagens"},{"id":"d","texto":"Opção D relacionada a propósito das mensagens"}],"resposta_correta":"d","explicacao":"O propósito destas mensagens é chamar as pessoas ao arrependimento e preparação para os eventos finais antes da volta de Cristo.","referencias":[{"texto":"Isto requer perseverança dos santos","livro":"Apocalipse","capitulo":14,"versiculo":12,"conteudo":"Aqui está a paciência dos santos; aqui estão os que guardam os mandamentos de Deus, e a fé em Jesus."}]},{"id":"cf_11_q5","numero":5,"texto":"Qual é a importância de tempo das mensagens nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a tempo das mensagens"},{"id":"b","texto":"Opção B relacionada a tempo das mensagens"},{"id":"c","texto":"Opção C relacionada a tempo das mensagens"},{"id":"d","texto":"Opção D relacionada a tempo das mensagens"}],"resposta_correta":"a","explicacao":"Estas mensagens são especialmente relevantes nos últimos dias antes da segunda vinda de Cristo.","referencias":[{"texto":"Os seus dias serão cento e vinte anos","livro":"Gênesis","capitulo":6,"versiculo":3,"conteudo":"Então disse o Senhor: O meu Espírito não contenderá para sempre com o homem; porque ele é também carne; mas os seus dias serão cento e vinte anos."}]},{"id":"cf_11_q6","numero":6,"texto":"Qual é a importância de conteúdo das mensagens nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a conteúdo das mensagens"},{"id":"b","texto":"Opção B relacionada a conteúdo das mensagens"},{"id":"c","texto":"Opção C relacionada a conteúdo das mensagens"},{"id":"d","texto":"Opção D relacionada a conteúdo das mensagens"}],"resposta_correta":"b","explicacao":"O conteúdo enfatiza adoração verdadeira, rejeição da falsidade religiosa e obediência aos mandamentos divinos.","referencias":[{"texto":"Aqui está a paciência dos santos","livro":"Apocalipse","capitulo":14,"versiculo":12,"conteudo":"Aqui está a paciência dos santos; aqui estão os que guardam os mandamentos de Deus, e a fé em Jesus."}]},{"id":"cf_11_q7","numero":7,"texto":"Qual é a importância de relevância atual nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a relevância atual"},{"id":"b","texto":"Opção B relacionada a relevância atual"},{"id":"c","texto":"Opção C relacionada a relevância atual"},{"id":"d","texto":"Opção D relacionada a relevância atual"}],"resposta_correta":"c","explicacao":"Estas mensagens têm relevância contínua para os crentes modernos, chamando-os à fidelidade em face das pressões mundanas e espirituais.","referencias":[{"texto":"Que o juízo de Deus nos encontre firmes","livro":"1 Pedro","capitulo":4,"versiculo":17,"conteudo":"Porque já é tempo de que comece o julgamento pela casa de Deus; e se primeiro começa por nós, qual será o fim dos que não obedecem ao evangelho de Deus?"}]},{"id":"cf_11_q8","numero":8,"texto":"Qual é a importância de aceitação das mensagens nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a aceitação das mensagens"},{"id":"b","texto":"Opção B relacionada a aceitação das mensagens"},{"id":"c","texto":"Opção C relacionada a aceitação das mensagens"},{"id":"d","texto":"Opção D relacionada a aceitação das mensagens"}],"resposta_correta":"d","explicacao":"Aceitar estas mensagens significa responder ao chamado divino, separar-se do mundo e preparar-se espiritualmente para a segunda vinda.","referencias":[{"texto":"Ouça quem tem ouvidos","livro":"Apocalipse","capitulo":2,"versiculo":7,"conteudo":"Quem tem ouvidos, ouça o que o Espírito diz às igrejas. Ao que vencer, dar-lhe-ei a comer da árvore da vida, que está no meio do paraíso de Deus."}]},{"id":"cf_11_q9","numero":9,"texto":"Qual é a importância de rejeição das mensagens nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a rejeição das mensagens"},{"id":"b","texto":"Opção B relacionada a rejeição das mensagens"},{"id":"c","texto":"Opção C relacionada a rejeição das mensagens"},{"id":"d","texto":"Opção D relacionada a rejeição das mensagens"}],"resposta_correta":"a","explicacao":"A rejeição destas mensagens coloca as pessoas em perigo de serem apanhadas desprevenidas pelo dia do julgamento divino.","referencias":[{"texto":"Porque não ouviram a verdade","livro":"2 Tessalonicenses","capitulo":2,"versiculo":10,"conteudo":"e com todo o engano da injustiça para os que perecem, porque não receberam o amor da verdade para se salvarem."}]},{"id":"cf_11_q10","numero":10,"texto":"Qual é a importância de cumprimento profético nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a cumprimento profético"},{"id":"b","texto":"Opção B relacionada a cumprimento profético"},{"id":"c","texto":"Opção C relacionada a cumprimento profético"},{"id":"d","texto":"Opção D relacionada a cumprimento profético"}],"resposta_correta":"b","explicacao":"O cumprimento profético das três mensagens confirma a confiabilidade da Bíblia e a certeza do retorno de Cristo.","referencias":[{"texto":"As palavras do Senhor são verdadeiras","livro":"Provérbios","capitulo":22,"versiculo":21,"conteudo":"Para te fazer conhecer a certeza das palavras da verdade; para que possas responder palavras de verdade aos que te perguntarem?"}]}]'::jsonb, '[{"id":"cf1","texto":"Aceitar e proclamar as três mensagens angélicas como a última chamada de Deus antes da volta de Cristo."},{"id":"cf2","texto":"Viver de acordo com os princípios revelados nestas mensagens, incluindo a guarda do sábado e obediência aos mandamentos."},{"id":"cf3","texto":"Preparar-se espiritualmente para os últimos eventos, confiando na proteção e provisão de Deus."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

