VALUES ('crencas_fundamentais', 12, 'Aquele Outro Anjo', 'O Alto Clamor de Apocalipse 18', 'Este tema aborda aquele outro anjo, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_12_q1","numero":1,"texto":"Qual é a importância de identidade do anjo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a identidade do anjo"},{"id":"b","texto":"Opção B relacionada a identidade do anjo"},{"id":"c","texto":"Opção C relacionada a identidade do anjo"},{"id":"d","texto":"Opção D relacionada a identidade do anjo"}],"resposta_correta":"a","explicacao":"Esta pergunta aborda um aspecto importante do tema estudado e requer reflexão sobre seu significado bíblico e aplicação prática na vida cristã.","referencias":[{"texto":"Assim como está escrito","livro":"Romanos","capitulo":1,"versiculo":1,"conteudo":"Paulo, servo de Jesus Cristo, chamado para ser apóstolo, separado para o evangelho de Deus,"}]},{"id":"cf_12_q2","numero":2,"texto":"Qual é a importância de momento de aparição nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a momento de aparição"},{"id":"b","texto":"Opção B relacionada a momento de aparição"},{"id":"c","texto":"Opção C relacionada a momento de aparição"},{"id":"d","texto":"Opção D relacionada a momento de aparição"}],"resposta_correta":"b","explicacao":"Esta pergunta aborda um aspecto importante do tema estudado e requer reflexão sobre seu significado bíblico e aplicação prática na vida cristã.","referencias":[{"texto":"Assim como está escrito","livro":"Romanos","capitulo":1,"versiculo":1,"conteudo":"Paulo, servo de Jesus Cristo, chamado para ser apóstolo, separado para o evangelho de Deus,"}]},{"id":"cf_12_q3","numero":3,"texto":"Qual é a importância de papel do anjo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a papel do anjo"},{"id"