VALUES ('crencas_fundamentais', 13, 'O Dom de Profecia', 'O Testemunho de Jesus na Igreja', 'Este tema aborda o dom de profecia, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_13_q1","numero":1,"texto":"Qual é a importância de natureza do dom de profecia nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a natureza do dom de profecia"},{"id":"b","texto":"Opção B relacionada a natureza do dom de profecia"},{"id":"c","texto":"Opção C relacionada a natureza do dom de profecia"},{"id":"d","texto":"Opção D relacionada a natureza do dom de profecia"}],"resposta_correta":"a","explicacao":"Esta pergunta aborda um aspecto importante do tema estudado e requer reflexão sobre seu significado bíblico e aplicação prática na vida cristã.","referencias":[{"texto":"Assim como está escrito","livro":"Romanos","capitulo":1,"versiculo":1,"conteudo":"Paulo, servo de Jesus Cristo, chamado para ser apóstolo, separado para o evangelho de Deus,"}]},{"id":"cf_13_q2","numero":2,"texto":"Qual é a importância de propósito do dom nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a propósito do dom"},{"id":"b","texto":"Opção B relacionada a propósito do dom"},{"id":"c","texto":"Opção C relacionada a propósito do dom"},{"id":"d","texto":"Opção D relacionada a propósito do dom"}],"resposta_correta":"b","explicacao":"Esta pergunta aborda um aspecto importante do tema estudado e requer reflexão sobre seu significado bíblico e aplicação prática na vida cristã.","referencias":[{"texto":"Assim como está escrito","livro":"Romanos","capitulo":1,"versiculo":1,"conteudo":"Paulo, servo de Jesus Cristo, chamado para ser apóstolo, separado para o evangelho de Deus,"}]},{"id":"cf_13_q3","numero":3,"texto":"Qual é a importância de como opera nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacio