INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 18, 'Dever Para Com As Autoridades Civis', 'Obediência a Deus e ao Estado', 'Este tema aborda dever para com as autoridades civis, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_18_q1","numero":1,"texto":"Qual é a importância de dever civil nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a dever civil"},{"id":"b","texto":"Opção B relacionada a dever civil"},{"id":"c","texto":"Opção C relacionada a dever civil"},{"id":"d","texto":"Opção D relacionada a dever civil"}],"resposta_correta":"a","explicacao":"O dever civil reflete o respeito pelas autoridades estabelecidas por Deus. A obediência às leis civis é uma expressão de fé, desde que não conflitem com os princípios divinos. Este compromisso demonstra lealdade tanto a Deus quanto ao Estado.","referencias":[{"texto":"Respeitar a autoridade civil","livro":"Romanos","capitulo":13,"versiculo":1,"conteudo":"Toda pessoa esteja sujeita às autoridades superiores"}]},{"id":"cf_18_q2","numero":2,"texto":"Qual é a importância de autoridades civis nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a autoridades civis"},{"id":"b","texto":"Opção B relacionada a autoridades civis"},{"id":"c","texto":"Opção C relacionada a autoridades civis"},{"id":"d","texto":"Opção D relacionada a autoridades civis"}],"resposta_correta":"b","explicacao":"As autoridades civis são ordenadas por Deus para manter a ordem social e a justiça. Aceitar essa responsabilidade divina significa reconhecer que o governo serve propósitos estabelecidos pelo Criador. A resistência injusta à autoridade é resistência ao estabelecimento de Deus.","referencias":[{"texto":"Autoridades instituídas por Deus","livro":"Romanos","capitulo":13,"versiculo":2,"conteudo":"Quem se opõe à autoridade resiste à ordem estabelecida por Deus"}]},{"id":"cf_18_q3","numero":3,"texto":"Qual é a importância de obediência nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a obediência"},{"id":"b","texto":"Opção B relacionada a obediência"},{"id":"c","texto":"Opção C relacionada a obediência"},{"id":"d","texto":"Opção D relacionada a obediência"}],"resposta_correta":"c","explicacao":"A obediência civil é uma expressão de conciência e responsabilidade moral. Ela reflete o respeito pelo bem comum e pela ordem estabelecida para proteger os direitos de todos. Esta obediência é parte integral da vida cristã.","referencias":[{"texto":"Obedecer à consciência moral","livro":"1 Pedro","capitulo":2,"versiculo":13,"conteudo":"Sujeitai-vos a toda ordenação humana por causa do Senhor"}]},{"id":"cf_18_q4","numero":4,"texto":"Qual é a importância de quando não obedecer nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a quando não obedecer"},{"id":"b","texto":"Opção B relacionada a quando não obedecer"},{"id":"c","texto":"Opção C relacionada a quando não obedecer"},{"id":"d","texto":"Opção D relacionada a quando não obedecer"}],"resposta_correta":"d","explicacao":"Existe uma obrigação moral de desobedecer quando as leis civis conflitam com os mandamentos de Deus. A primeira lealdade é ao Criador, não às autoridades humanas. Este princípio protege a liberdade de consciência e a integridade espiritual.","referencias":[{"texto":"Obediência até ao martírio","livro":"Atos","capitulo":5,"versiculo":29,"conteudo":"Importa obedecer a Deus do que aos homens"}]},{"id":"cf_18_q5","numero":5,"texto":"Qual é a importância de lealdade nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a lealdade"},{"id":"b","texto":"Opção B relacionada a lealdade"},{"id":"c","texto":"Opção C relacionada a lealdade"},{"id":"d","texto":"Opção D relacionada a lealdade"}],"resposta_correta":"a","explicacao":"A lealdade equilibrada reconhece tanto os direitos dos poderes civis quanto os direitos supremos de Deus. Ela exige honestidade, cumprir promessas e manter a integridade moral mesmo sob pressão. Esta lealdade dupla constrói comunidades fortes e fiéis.","referencias":[{"texto":"Lealdade a Deus acima de tudo","livro":"Mateus","capitulo":22,"versiculo":37,"conteudo":"Amarás o Senhor teu Deus de todo o teu coração"}]},{"id":"cf_18_q6","numero":6,"texto":"Qual é a importância de participação política nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a participação política"},{"id":"b","texto":"Opção B relacionada a participação política"},{"id":"c","texto":"Opção C relacionada a participação política"},{"id":"d","texto":"Opção D relacionada a participação política"}],"resposta_correta":"b","explicacao":"A participação política deve ser orientada por princípios cristãos e pela consciência moral. Os crentes têm o direito e a responsabilidade de participar em questões que afetam a justiça e o bem comum. Contudo, a participação nunca deve comprometer os valores espirituais fundamentais.","referencias":[{"texto":"Direito ao voto e participação","livro":"Romanos","capitulo":12,"versiculo":2,"conteudo":"Não vos conformeis com este mundo, mas transformai-vos"}]},{"id":"cf_18_q7","numero":7,"texto":"Qual é a importância de impostos nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a impostos"},{"id":"b","texto":"Opção B relacionada a impostos"},{"id":"c","texto":"Opção C relacionada a impostos"},{"id":"d","texto":"Opção D relacionada a impostos"}],"resposta_correta":"c","explicacao":"O pagamento de impostos é uma obrigação civil que sustenta a ordem pública e os serviços comunais. Jesus ensinou que os crentes devem cumprir essas obrigações como parte de sua responsabilidade social. Pagar impostos é reconhecer o legítimo direito do governo de manter a administração.","referencias":[{"texto":"Pagar impostos a César","livro":"Mateus","capitulo":22,"versiculo":21,"conteudo":"Dai a César o que é de César, e a Deus o que é de Deus"}]}]'::jsonb, '[{"numero":1,"texto":"Respeitar as autoridades civis estabelecidas por Deus","referencia":"Romanos 13:1-2"},{"numero":2,"texto":"Obedecer às leis do Estado enquanto não conflitarem com a lei de Deus","referencia":"Atos 5:29"},{"numero":3,"texto":"Pagar impostos e cumprir obrigações civis com fidelidade","referencia":"Mateus 22:21"}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 19, 'O Selamento', 'Os 144.000 e o Selo do Deus Vivo', 'Este tema aborda o selamento, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_19_q1","numero":1,"texto":"Qual é a importância de significado do selamento nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a significado do selamento"},{"id":"b","texto":"Opção B relacionada a significado do selamento"},{"id":"c","texto":"Opção C relacionada a significado do selamento"},{"id":"d","texto":"Opção D relacionada a significado do selamento"}],"resposta_correta":"a","explicacao":"O selamento representa a aprovação divina e a proteção especial de Deus sobre Seus filhos. É um sinal de propriedade divina e de salvação garantida. Este selo marca a conclusão do processo de conversão e dedicação a Deus.","referencias":[{"texto":"Significado do selo divino","livro":"Efésios","capitulo":4,"versiculo":30,"conteudo":"Não entristeçais o Espírito Santo de Deus, no qual estais selados"}]},{"id":"cf_19_q2","numero":2,"texto":"Qual é a importância de tempo do selamento nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a tempo do selamento"},{"id":"b","texto":"Opção B relacionada a tempo do selamento"},{"id":"c","texto":"Opção C relacionada a tempo do selamento"},{"id":"d","texto":"Opção D relacionada a tempo do selamento"}],"resposta_correta":"b","explicacao":"O tempo do selamento está relacionado ao encerramento da graça divina e ao final da atividade intercessória de Cristo. Este período marca o momento crucial quando cada pessoa receberá seu destino eterno. Entender este tempo é essencial para a vigilância espiritual.","referencias":[{"texto":"Tempo do selamento","livro":"Apocalipse","capitulo":7,"versiculo":1,"conteudo":"Depois destas coisas, vi quatro anjos em pé nos quatro cantos da terra"}]},{"id":"cf_19_q3","numero":3,"texto":"Qual é a importância de quem pode ser selado nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a quem pode ser selado"},{"id":"b","texto":"Opção B relacionada a quem pode ser selado"},{"id":"c","texto":"Opção C relacionada a quem pode ser selado"},{"id":"d","texto":"Opção D relacionada a quem pode ser selado"}],"resposta_correta":"c","explicacao":"Apenas aqueles que mantêm fidelidade aos princípios divinos e vivem em conformidade com a vontade de Deus podem receber o selo. O selamento é condicional à perseverança, ao arrependimento sincero e à dedicação contínua. Requer uma relação vital e transformada com Deus.","referencias":[{"texto":"Requisitos para ser selado","livro":"2 Timóteo","capitulo":2,"versiculo":19,"conteudo":"Todos que invocam o nome do Senhor se apartem da injustiça"}]},{"id":"cf_19_q4","numero":4,"texto":"Qual é a importância de teste do selamento nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a teste do selamento"},{"id":"b","texto":"Opção B relacionada a teste do selamento"},{"id":"c","texto":"Opção C relacionada a teste do selamento"},{"id":"d","texto":"Opção D relacionada a teste do selamento"}],"resposta_correta":"d","explicacao":"Durante o tempo de angústia e provações finais, Deus testa a lealdade de Seus povo. Este teste revela a genuinidade da fé e a disposição em sofrer por convicção. Apenas aqueles que permanecem firmes sob perseguição receberão o selo final da aprovação divina.","referencias":[{"texto":"Prova de fidelidade","livro":"Apocalipse","capitulo":12,"versiculo":11,"conteudo":"Venceram pela palavra do testemunho e não amaram suas vidas"}]},{"id":"cf_19_q5","numero":5,"texto":"Qual é a importância de resgate eterno nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a resgate eterno"},{"id":"b","texto":"Opção B relacionada a resgate eterno"},{"id":"c","texto":"Opção C relacionada a resgate eterno"},{"id":"d","texto":"Opção D relacionada a resgate eterno"}],"resposta_correta":"a","explicacao":"O selamento garante a redenção eterna e a salvação final dos escolhidos de Deus. Este ato divino assegura que nenhuma força pode anular a graça concedida. O resgate eterno é a consumação da obra de salvação iniciada por Cristo na cruz.","referencias":[{"texto":"Salvação eterna garantida","livro":"1 João","capitulo":5,"versiculo":11,"conteudo":"Deus nos deu vida eterna, e esta vida está em Seu Filho"}]},{"id":"cf_19_q6","numero":6,"texto":"Qual é a importância de selo de Deus nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a selo de Deus"},{"id":"b","texto":"Opção B relacionada a selo de Deus"},{"id":"c","texto":"Opção C relacionada a selo de Deus"},{"id":"d","texto":"Opção D relacionada a selo de Deus"}],"resposta_correta":"b","explicacao":"O selo de Deus é a marca divina que identifica Seus filhos e os protege na hora da angústia. Este selo diferencia os salvos dos perdidos e simboliza a propriedade e proteção eterna. É o sinal visível do caráter de Deus impresso na vida do crente.","referencias":[{"texto":"Proteção divina","livro":"Apocalipse","capitulo":7,"versiculo":3,"conteudo":"Não façais dano nem ao mar nem à terra nem às árvores, senão depois de termos selado os servos de nosso Deus"}]},{"id":"cf_19_q7","numero":7,"texto":"Qual é a importância de marca nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a marca"},{"id":"b","texto":"Opção B relacionada a marca"},{"id":"c","texto":"Opção C relacionada a marca"},{"id":"d","texto":"Opção D relacionada a marca"}],"resposta_correta":"c","explicacao":"A marca do selamento distingue o povo de Deus do mundo pecaminoso. Esta marca eterna garante imunidade às pragas finais e asseguramento da eternidade com Deus. Representa a identificação total com o Criador e Sua verdade.","referencias":[{"texto":"Marca do povo de Deus","livro":"Ezequiel","capitulo":9,"versiculo":4,"conteudo":"Passa pela cidade e marca uma cruz na testa dos que choram e se lamentam"}]},{"id":"cf_19_q8","numero":8,"texto":"Qual é a importância de proteção divina nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a proteção divina"},{"id":"b","texto":"Opção B relacionada a proteção divina"},{"id":"c","texto":"Opção C relacionada a proteção divina"},{"id":"d","texto":"Opção D relacionada a proteção divina"}],"resposta_correta":"d","explicacao":"O selamento oferece proteção divina contra as forças do mal e os juízos finais. Aqueles que recebem o selo estão seguros nas mãos de Deus e nada pode separá-los de Sua graça. Esta proteção é espiritual e abarca a eternidade.","referencias":[{"texto":"Proteção nas pragas finais","livro":"Salmo","capitulo":91,"versiculo":7,"conteudo":"Mil cairão ao teu lado e dez mil à tua direita, mas não chegará a ti"}]},{"id":"cf_19_q9","numero":9,"texto":"Qual é a importância de eternidade nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a eternidade"},{"id":"b","texto":"Opção B relacionada a eternidade"},{"id":"c","texto":"Opção C relacionada a eternidade"},{"id":"d","texto":"Opção D relacionada a eternidade"}],"resposta_correta":"a","explicacao":"O selamento assegura a posse eterna da vida e a comunhão permanente com Deus. Este dom eterno transcende o tempo e garante existência imortal no reino de Deus. É a realização plena da promessa de redenção divina.","referencias":[{"texto":"Vida eterna garantida","livro":"João","capitulo":3,"versiculo":36,"conteudo":"Aquele que crê no Filho tem a vida eterna"}]},{"id":"cf_19_q10","numero":10,"texto":"Qual é a importância de 144.000 nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a 144.000"},{"id":"b","texto":"Opção B relacionada a 144.000"},{"id":"c","texto":"Opção C relacionada a 144.000"},{"id":"d","texto":"Opção D relacionada a 144.000"}],"resposta_correta":"b","explicacao":"Os 144.000 representam simbolicamente todos os salvos que receberão o selo divino. Este número específico em Apocalipse denota completude, integridade e a totalidade dos redimidos. Eles representam a geração final que permanecerá fiel até à vinda de Cristo.","referencias":[{"texto":"Os 144.000 selados","livro":"Apocalipse","capitulo":14,"versiculo":1,"conteudo":"Vi, e eis o Cordeiro em pé no Monte Sião, e com ele cento e quarenta e quatro mil"}]}]'::jsonb, '[{"numero":1,"texto":"Buscar o selo divino através da fidelidade e consagração","referencia":"Efésios 4:30"},{"numero":2,"texto":"Compreender que o selamento garante proteção divina até à eternidade","referencia":"Apocalipse 7:3"},{"numero":3,"texto":"Reconhecer a importância do número simbólico 144.000 como representação dos salvos","referencia":"Apocalipse 14:1"}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 20, 'A Igreja de Deus', 'Organização e Responsabilidade dos Membros', 'Este tema aborda a igreja de deus, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_20_q1","numero":1,"texto":"Qual é a importância de definição de Igreja nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a definição de Igreja"},{"id":"b","texto":"Opção B relacionada a definição de Igreja"},{"id":"c","texto":"Opção C relacionada a definição de Igreja"},{"id":"d","texto":"Opção D relacionada a definição de Igreja"}],"resposta_correta":"a","explicacao":"Esta questão explora aspectos fundamentais das Crenças da Igreja. Compreender este ponto é essencial para a formação espiritual completa. A resposta reflete compromisso com a verdade bíblica.","referencias":[{"texto":"Igreja como corpo de Cristo","livro":"1 Coríntios","capitulo":12,"versiculo":12,"conteudo":"Pois como o corpo é um, e tem muitos membros"}]},{"id":"cf_20_q2","numero":2,"texto":"Qual é a importância de membros da Igreja nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a membros da Igreja"},{"id":"b","texto":"Opção B relacionada a membros da Igreja"},{"id":"c","texto":"Opção C relacionada a membros da Igreja"},{"id":"d","texto":"Opção D relacionada a membros da Igreja"}],"resposta_correta":"b","explicacao":"Os membros da Igreja são aqueles que professam fé em Cristo e aceitam os princípios de Sua doutrina. Cada membro tem direitos e responsabilidades na comunidade. A qualidade da membresia depende da dedicação pessoal à vida cristã.","referencias":[{"texto":"Membros da Igreja Cristã","livro":"1 Coríntios","capitulo":12,"versiculo":27,"conteudo":"Vós sois corpo de Cristo e membros individualmente"}]},{"id":"cf_20_q3","numero":3,"texto":"Qual é a importância de estrutura eclesiástica nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a estrutura eclesiástica"},{"id":"b","texto":"Opção B relacionada a estrutura eclesiástica"},{"id":"c","texto":"Opção C relacionada a estrutura eclesiástica"},{"id":"d","texto":"Opção D relacionada a estrutura eclesiástica"}],"resposta_correta":"c","explicacao":"A estrutura eclesiástica reflete a organização divina e facilita a coordenação de esforços na missão. Uma estrutura clara previne divisões e mantém a unidade. Embora invisível espiritualmente, ela necessita de forma visível para funcionar.","referencias":[{"texto":"Organização da Igreja","livro":"1 Coríntios","capitulo":14,"versiculo":33,"conteudo":"Pois Deus não é Deus de desordem, mas de paz"}]},{"id":"cf_20_q4","numero":4,"texto":"Qual é a importância de autoridade na Igreja nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a autoridade na Igreja"},{"id":"b","texto":"Opção B relacionada a autoridade na Igreja"},{"id":"c","texto":"Opção C relacionada a autoridade na Igreja"},{"id":"d","texto":"Opção D relacionada a autoridade na Igreja"}],"resposta_correta":"d","explicacao":"A autoridade na Igreja é exercida em conformidade com os princípios de Cristo, baseada no serviço e no amor. Líderes devem prestação de contas à comunidade e a Deus. Nenhuma autoridade humana pode sobrepor-se aos princípios divinos.","referencias":[{"texto":"Autoridade na Igreja","livro":"Mateus","capitulo":20,"versiculo":25,"conteudo":"Mas Jesus os chamou e disse: Sabeis que os príncipes dos gentios os dominam"}]},{"id":"cf_20_q5","numero":5,"texto":"Qual é a importância de doutrina da Igreja nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a doutrina da Igreja"},{"id":"b","texto":"Opção B relacionada a doutrina da Igreja"},{"id":"c","texto":"Opção C relacionada a doutrina da Igreja"},{"id":"d","texto":"Opção D relacionada a doutrina da Igreja"}],"resposta_correta":"a","explicacao":"A doutrina da Igreja é formada pelos ensinamentos bíblicos e pela tradição apostólica. Cada doutrina deve ser testada pela Palavra de Deus. Unidade doutrinária é essencial para manter a coesão espiritual.","referencias":[{"texto":"Doutrina cristã","livro":"2 Timóteo","capitulo":2,"versiculo":2,"conteudo":"O que ouviste de mim diante de muitas testemunhas, confia-o a homens fiéis"}]},{"id":"cf_20_q6","numero":6,"texto":"Qual é a importância de propósito da Igreja nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a propósito da Igreja"},{"id":"b","texto":"Opção B relacionada a propósito da Igreja"},{"id":"c","texto":"Opção C relacionada a propósito da Igreja"},{"id":"d","texto":"Opção D relacionada a propósito da Igreja"}],"resposta_correta":"b","explicacao":"O propósito da Igreja é proclamar o evangelho, discipular novos crentes e preparar santos para a vinda de Cristo. Esse propósito transcende o bem-estar meramente pessoal. É uma missão redentora abrangendo toda a humanidade.","referencias":[{"texto":"Propósito da Igreja","livro":"Mateus","capitulo":28,"versiculo":19,"conteudo":"Portanto, ide, ensinai todas as nações"}]},{"id":"cf_20_q7","numero":7,"texto":"Qual é a importância de unidade da Igreja nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a unidade da Igreja"},{"id":"b","texto":"Opção B relacionada a unidade da Igreja"},{"id":"c","texto":"Opção C relacionada a unidade da Igreja"},{"id":"d","texto":"Opção D relacionada a unidade da Igreja"}],"resposta_correta":"c","explicacao":"A unidade da Igreja é espiritual mas deve expressar-se em comunidade e ação conjunta. Diversidade de dons e funcões enriquece a unidade. Conflitos devem ser resolvidos com amor e fidelidade aos princípios divinos.","referencias":[{"texto":"Unidade na Igreja","livro":"João","capitulo":17,"versiculo":20,"conteudo":"Peço não só por estes, mas também pelos que há de crer em mim pela sua palavra"}]},{"id":"cf_20_q8","numero":8,"texto":"Qual é a importância de poder espiritual nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a poder espiritual"},{"id":"b","texto":"Opção B relacionada a poder espiritual"},{"id":"c","texto":"Opção C relacionada a poder espiritual"},{"id":"d","texto":"Opção D relacionada a poder espiritual"}],"resposta_correta":"d","explicacao":"O poder espiritual da Igreja vem da presença do Espírito Santo e da fé coletiva. Este poder manifesta-se em conversões, milagres e transformação de vidas. É superior a toda força mundana e garante vitória final.","referencias":[{"texto":"Poder espiritual","livro":"Atos","capitulo":1,"versiculo":8,"conteudo":"Recebereis poder, ao descer sobre vós o Espírito Santo"}]},{"id":"cf_20_q9","numero":9,"texto":"Qual é a importância de preservação da fé nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a preservação da fé"},{"id":"b","texto":"Opção B relacionada a preservação da fé"},{"id":"c","texto":"Opção C relacionada a preservação da fé"},{"id":"d","texto":"Opção D relacionada a preservação da fé"}],"resposta_correta":"a","explicacao":"A preservação da fé requer vigilância constante contra erros doutrinários e compromissos morais. A Igreja deve manter pura a verdade recebida de Deus. Esta preservação é tanto responsabilidade pessoal quanto coletiva.","referencias":[{"texto":"Preservação da fé","livro":"Judas","capitulo":1,"versiculo":3,"conteudo":"Contendei pela fé que uma vez foi entregue aos santos"}]},{"id":"cf_20_q10","numero":10,"texto":"Qual é a importância de organização nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a organização"},{"id":"b","texto":"Opção B relacionada a organização"},{"id":"c","texto":"Opção C relacionada a organização"},{"id":"d","texto":"Opção D relacionada a organização"}],"resposta_correta":"b","explicacao":"A organização da Igreja providencia estrutura para ação coordenada e crescimento ordenado. Sem organização, a Igreja falha em sua missão e sofre divisões. Uma boa organização reflete sabedoria divina.","referencias":[{"texto":"Organização eclesiástica","livro":"Efésios","capitulo":4,"versiculo":11,"conteudo":"E ele mesmo concedeu uns para apóstolos, outros para profetas"}]},{"id":"cf_20_q11","numero":11,"texto":"Qual é a importância de disciplina eclesiástica nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a disciplina eclesiástica"},{"id":"b","texto":"Opção B relacionada a disciplina eclesiástica"},{"id":"c","texto":"Opção C relacionada a disciplina eclesiástica"},{"id":"d","texto":"Opção D relacionada a disciplina eclesiástica"}],"resposta_correta":"c","explicacao":"A disciplina eclesiástica mantém a pureza moral e espiritual da comunidade. Ela visa restaurar o pecador, não apenas puni-lo. Deve ser exercida com amor e misericórdia.","referencias":[{"texto":"Disciplina na Igreja","livro":"Mateus","capitulo":18,"versiculo":15,"conteudo":"Se teu irmão pecar contra ti, vai e repreende-o entre ti e ele só"}]},{"id":"cf_20_q12","numero":12,"texto":"Qual é a importância de liderança nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a liderança"},{"id":"b","texto":"Opção B relacionada a liderança"},{"id":"c","texto":"Opção C relacionada a liderança"},{"id":"d","texto":"Opção D relacionada a liderança"}],"resposta_correta":"d","explicacao":"A liderança na Igreja deve ser exemplo de piedade, integridade e serviço dedicado. Líderes são responsáveis pelo bem-estar espiritual da congregação. A liderança é dom de Deus a ser exercido com tremenda responsabilidade.","referencias":[{"texto":"Liderança cristã","livro":"1 Pedro","capitulo":5,"versiculo":2,"conteudo":"Apascentai o rebanho de Deus que está entre vós"}]},{"id":"cf_20_q13","numero":13,"texto":"Qual é a importância de missão da Igreja nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a missão da Igreja"},{"id":"b","texto":"Opção B relacionada a missão da Igreja"},{"id":"c","texto":"Opção C relacionada a missão da Igreja"},{"id":"d","texto":"Opção D relacionada a missão da Igreja"}],"resposta_correta":"a","explicacao":"A missão da Igreja é levar a mensagem de salvação a todos os povos e nações. Esta missão incluio batismo e ensinamento dos crentes. A Grand Comissão permanece como responsabilidade contínua.","referencias":[{"texto":"Grande Comissão","livro":"Marcos","capitulo":16,"versiculo":15,"conteudo":"Ide por todo mundo e pregai o evangelho a toda criatura"}]},{"id":"cf_20_q14","numero":14,"texto":"Qual é a importância de crescimento nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a crescimento"},{"id":"b","texto":"Opção B relacionada a crescimento"},{"id":"c","texto":"Opção C relacionada a crescimento"},{"id":"d","texto":"Opção D relacionada a crescimento"}],"resposta_correta":"b","explicacao":"O crescimento da Igreja reflete a operação do Espírito Santo e a fidelidade dos membros. Crescimento numeral deve acompanhar-se de crescimento espiritual. Cada membro contribui para este processo de expansão.","referencias":[{"texto":"Crescimento da Igreja","livro":"Atos","capitulo":2,"versiculo":47,"conteudo":"Todos os dias acrescentava o Senhor à Igreja aqueles que se haviam de salvar"}]},{"id":"cf_20_q15","numero":15,"texto":"Qual é a importância de testemunho nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a testemunho"},{"id":"b","texto":"Opção B relacionada a testemunho"},{"id":"c","texto":"Opção C relacionada a testemunho"},{"id":"d","texto":"Opção D relacionada a testemunho"}],"resposta_correta":"c","explicacao":"O testemunho da Igreja ao mundo reflete a realidade de sua fé e prática. Um testemunho forte influencia positivamente as comunidades circunvizinhas. É através do testemunho que se atrai outros à verdade de Cristo.","referencias":[{"texto":"Testemunho cristão","livro":"Mateus","capitulo":5,"versiculo":16,"conteudo":"Assim resplandeça a vossa luz diante dos homens"}]}]'::jsonb, '[{"numero":1,"texto":"Compreender a Igreja como corpo místico de Cristo","referencia":"1 Coríntios 12:12-27"},{"numero":2,"texto":"Aceitar a responsabilidade pessoal como membro da comunidade de fé","referencia":"Mateus 28:19-20"},{"numero":3,"texto":"Participar ativamente na missão de levar o evangelho a toda criatura","referencia":"Marcos 16:15"}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 21, 'Mordomia', 'Dízimos, Ofertas e Fidelidade', 'Este tema aborda mordomia, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_21_q1","numero":1,"texto":"Qual é a importância de significado de mordomia nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a significado de mordomia"},{"id":"b","texto":"Opção B relacionada a significado de mordomia"},{"id":"c","texto":"Opção C relacionada a significado de mordomia"},{"id":"d","texto":"Opção D relacionada a significado de mordomia"}],"resposta_correta":"a","explicacao":"Mordomia significa administração responsável dos bens recebidos de Deus. Não somos donos, mas mordomos de tudo que temos. Esta compreensão fundamenta toda ética econômica cristã.","referencias":[{"texto":"Significado de mordomia","livro":"Lucas","capitulo":16,"versiculo":1,"conteudo":"Também disse aos seus discípulos: Havia um homem rico que tinha um mordomo"}]},{"id":"cf_21_q2","numero":2,"texto":"Qual é a importância de dízimo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a dízimo"},{"id":"b","texto":"Opção B relacionada a dízimo"},{"id":"c","texto":"Opção C relacionada a dízimo"},{"id":"d","texto":"Opção D relacionada a dízimo"}],"resposta_correta":"b","explicacao":"O dízimo é a devolução de dez porcento da renda ao Senhor, reconhecendo Sua propriedade e soberania. É uma lei moral que transcende o Antigo Testamento. O dízimo sustenta o trabalho da Igreja.","referencias":[{"texto":"Dízimo como dever","livro":"Malaquias","capitulo":3,"versiculo":10,"conteudo":"Trazer toda sorte de dízimos à casa do tesouro"}]},{"id":"cf_21_q3","numero":3,"texto":"Qual é a importância de ofertas nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a ofertas"},{"id":"b","texto":"Opção B relacionada a ofertas"},{"id":"c","texto":"Opção C relacionada a ofertas"},{"id":"d","texto":"Opção D relacionada a ofertas"}],"resposta_correta":"c","explicacao":"As ofertas são contribuições voluntárias além do dízimo, expressão de gratidão e dedicação. Refletem generosidade e fé na provisão divina. São essenciais para projetos especiais e necessidades emergentes.","referencias":[{"texto":"Ofertas voluntárias","livro":"2 Coríntios","capitulo":9,"versiculo":7,"conteudo":"Cada um dê conforme propôs no seu coração, não com tristeza ou por necessidade"}]},{"id":"cf_21_q4","numero":4,"texto":"Qual é a importância de administração de bens nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a administração de bens"},{"id":"b","texto":"Opção B relacionada a administração de bens"},{"id":"c","texto":"Opção C relacionada a administração de bens"},{"id":"d","texto":"Opção D relacionada a administração de bens"}],"resposta_correta":"d","explicacao":"A administração de bens requer sabedoria e honestidade em como usamos nossos recursos. Deve beneficiar não apenas a nós mesmos mas também aos necessitados. A administração sábia é uma forma de adoração.","referencias":[{"texto":"Administração de recursos","livro":"Provérbios","capitulo":27,"versiculo":12,"conteudo":"O prudente vê o perigo e se refugia, mas o simples vai adiante e sofre"}]},{"id":"cf_21_q5","numero":5,"texto":"Qual é a importância de responsabilidade financeira nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a responsabilidade financeira"},{"id":"b","texto":"Opção B relacionada a responsabilidade financeira"},{"id":"c","texto":"Opção C relacionada a responsabilidade financeira"},{"id":"d","texto":"Opção D relacionada a responsabilidade financeira"}],"resposta_correta":"a","explicacao":"A responsabilidade financeira inclui pagar dívidas, honrar compromissos e ser honesto em transações. Cada pessoa responde a Deus pelo uso de suas finanças. A integridade financeira testifica nossa fé.","referencias":[{"texto":"Responsabilidade financeira","livro":"Romanos","capitulo":13,"versiculo":8,"conteudo":"Não fiqueis devendo nada a ninguém, senão que vos ameis uns aos outros"}]},{"id":"cf_21_q6","numero":6,"texto":"Qual é a importância de pobreza e riqueza nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a pobreza e riqueza"},{"id":"b","texto":"Opção B relacionada a pobreza e riqueza"},{"id":"c","texto":"Opção C relacionada a pobreza e riqueza"},{"id":"d","texto":"Opção D relacionada a pobreza e riqueza"}],"resposta_correta":"b","explicacao":"A pobreza e riqueza são ambas provações que testam nossa fidelidade a Deus. Nem a riqueza garante salvação nem a pobreza impede. A verdadeira riqueza está em conhecer a Deus.","referencias":[{"texto":"Lições da pobreza e riqueza","livro":"1 Timóteo","capitulo":6,"versiculo":10,"conteudo":"Pois o amor do dinheiro é raiz de todos os males"}]},{"id":"cf_21_q7","numero":7,"texto":"Qual é a importância de generosidade nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a generosidade"},{"id":"b","texto":"Opção B relacionada a generosidade"},{"id":"c","texto":"Opção C relacionada a generosidade"},{"id":"d","texto":"Opção D relacionada a generosidade"}],"resposta_correta":"c","explicacao":"A generosidade é marca característica do cristão que compreende a mordomia divina. Compartilhar com necessitados é investimento no reino de Deus. Generosidade traz bênçãos espirituais profundas.","referencias":[{"texto":"Generosidade cristã","livro":"Provérbios","capitulo":22,"versiculo":9,"conteudo":"O homem generoso será abençoado, porque dá do seu pão ao pobre"}]},{"id":"cf_21_q8","numero":8,"texto":"Qual é a importância de trabalho honrado nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a trabalho honrado"},{"id":"b","texto":"Opção B relacionada a trabalho honrado"},{"id":"c","texto":"Opção C relacionada a trabalho honrado"},{"id":"d","texto":"Opção D relacionada a trabalho honrado"}],"resposta_correta":"d","explicacao":"O trabalho honrado é ordenança divina que dignifica a vida e sustenta mordomia responsável. Qualquer trabalho honesto é sagrado quando feito para glória de Deus. O ócio é rejeitado como imoralidade.","referencias":[{"texto":"Trabalho honrado","livro":"Colossenses","capitulo":3,"versiculo":23,"conteudo":"E tudo quanto fizerdes, fazei-o de todo o coração como para o Senhor"}]},{"id":"cf_21_q9","numero":9,"texto":"Qual é a importância de propriedade nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a propriedade"},{"id":"b","texto":"Opção B relacionada a propriedade"},{"id":"c","texto":"Opção C relacionada a propriedade"},{"id":"d","texto":"Opção D relacionada a propriedade"}],"resposta_correta":"a","explicacao":"A propriedade privada é reconhecida na Bíblia mas subordinada aos princípios da mordomia divina. Propriedade carrega responsabilidade perante Deus e o próximo. Não é direito absoluto mas confiança divina.","referencias":[{"texto":"Propriedade privada","livro":"Êxodo","capitulo":20,"versiculo":17,"conteudo":"Não cobiçarás a casa de teu próximo"}]},{"id":"cf_21_q10","numero":10,"texto":"Qual é a importância de devedores nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a devedores"},{"id":"b","texto":"Opção B relacionada a devedores"},{"id":"c","texto":"Opção C relacionada a devedores"},{"id":"d","texto":"Opção D relacionada a devedores"}],"resposta_correta":"b","explicacao":"Os devedores carecem de misericórdia e sabedoria financeira para se recuperarem. Juros abusivos e exploração são condenados biblicamente. A compaixão aos endividados reflete caráter cristão.","referencias":[{"texto":"Compassão aos devedores","livro":"Deuteronômio","capitulo":15,"versiculo":7,"conteudo":"Se houver entre ti algum pobre de teus irmãos, não endurecerás teu coração"}]},{"id":"cf_21_q11","numero":11,"texto":"Qual é a importância de ajuda aos pobres nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a ajuda aos pobres"},{"id":"b","texto":"Opção B relacionada a ajuda aos pobres"},{"id":"c","texto":"Opção C relacionada a ajuda aos pobres"},{"id":"d","texto":"Opção D relacionada a ajuda aos pobres"}],"resposta_correta":"c","explicacao":"Ajudar aos pobres é responsabilidade cristã e expressão de amor ao próximo. Essa ajuda deve ser sábia e restauradora, não apenas caritativa. É ministério que honra a Deus.","referencias":[{"texto":"Ajudar aos pobres","livro":"Provérbios","capitulo":31,"versiculo":8,"conteudo":"Abre a boca por aquele que não pode falar, pela causa de todos os desamparados"}]}]'::jsonb, '[{"id":"cf1","texto":"Reconheço que tudo o que possuo pertence a Deus e sou apenas mordomo dos Seus bens."},{"id":"cf2","texto":"Comprometo-me a devolver fielmente o dízimo e as ofertas ao Senhor."},{"id":"cf3","texto":"Desejo administrar com sabedoria o tempo, talentos e recursos que Deus me confiou."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 22, 'A Segunda Vinda de Cristo', 'A Bendita Esperança', 'Este tema aborda a segunda vinda de cristo, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_22_q1","numero":1,"texto":"Qual é a importância de sinais da Segunda Vinda nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a sinais da Segunda Vinda"},{"id":"b","texto":"Opção B relacionada a sinais da Segunda Vinda"},{"id":"c","texto":"Opção C relacionada a sinais da Segunda Vinda"},{"id":"d","texto":"Opção D relacionada a sinais da Segunda Vinda"}],"resposta_correta":"a","explicacao":"Os sinais da Segunda Vinda incluem fenômenos naturais, sociais e espirituais descritos na Bíblia. Jesus advertiu Seus seguidores a observarem estes sinais. Compreendê-los nos prepara espiritualmente para este evento.","referencias":[{"texto":"Sinais dos últimos dias","livro":"Mateus","capitulo":24,"versiculo":3,"conteudo":"Quais serão os sinais da tua vinda e do fim do mundo?"}]},{"id":"cf_22_q2","numero":2,"texto":"Qual é a importância de natureza da vinda nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a natureza da vinda"},{"id":"b","texto":"Opção B relacionada a natureza da vinda"},{"id":"c","texto":"Opção C relacionada a natureza da vinda"},{"id":"d","texto":"Opção D relacionada a natureza da vinda"}],"resposta_correta":"b","explicacao":"A natureza da vinda será literal, pessoal e visível a toda a humanidade simultaneamente. Cristo virá com poder e grande glória. Será um evento cósmico de importância máxima.","referencias":[{"texto":"Natureza literal da vinda","livro":"Atos","capitulo":1,"versiculo":11,"conteudo":"Este Jesus, que dentre vós foi assunto ao céu, há de vir assim como o vistes ir"}]},{"id":"cf_22_q3","numero":3,"texto":"Qual é a importância de momento da vinda nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a momento da vinda"},{"id":"b","texto":"Opção B relacionada a momento da vinda"},{"id":"c","texto":"Opção C relacionada a momento da vinda"},{"id":"d","texto":"Opção D relacionada a momento da vinda"}],"resposta_correta":"c","explicacao":"O momento da vinda é desconhecido a homens e anjos, conhecido apenas por Deus Pai. Esta incerteza nos exige vigilância contínua. Portanto, devemos estar sempre preparados.","referencias":[{"texto":"Momento desconhecido","livro":"Mateus","capitulo":24,"versiculo":36,"conteudo":"Mas daquele dia e hora ninguém sabe, nem os anjos dos céus"}]},{"id":"cf_22_q4","numero":4,"texto":"Qual é a importância de ressurreição nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a ressurreição"},{"id":"b","texto":"Opção B relacionada a ressurreição"},{"id":"c","texto":"Opção C relacionada a ressurreição"},{"id":"d","texto":"Opção D relacionada a ressurreição"}],"resposta_correta":"d","explicacao":"A ressurreição dos mortos ocorrerá quando Cristo vier, os salvos ressurgirão para vida eterna. Este evento marca o fim da história terrena. A ressurreição é esperança central do cristianismo.","referencias":[{"texto":"Ressurreição dos mortos","livro":"1 Coríntios","capitulo":15,"versiculo":51,"conteudo":"Eis que vos digo um mistério: nem todos dormiremos, mas todos seremos transformados"}]},{"id":"cf_22_q5","numero":5,"texto":"Qual é a importância de transformação nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a transformação"},{"id":"b","texto":"Opção B relacionada a transformação"},{"id":"c","texto":"Opção C relacionada a transformação"},{"id":"d","texto":"Opção D relacionada a transformação"}],"resposta_correta":"a","explicacao":"A transformação dos vivos acontecerá instantaneamente quando Cristo vier, recebendo corpos incorruptíveis. Será uma metamorfose espiritual similar à ressurreição. Os vivos não dormirão, mas serão transformados.","referencias":[{"texto":"Transformação dos vivos","livro":"1 Tessalonicenses","capitulo":4,"versiculo":17,"conteudo":"Depois nós, os vivos, os que ficarmos, seremos arrebatados"}]},{"id":"cf_22_q6","numero":6,"texto":"Qual é a importância de preparação para vinda nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a preparação para vinda"},{"id":"b","texto":"Opção B relacionada a preparação para vinda"},{"id":"c","texto":"Opção C relacionada a preparação para vinda"},{"id":"d","texto":"Opção D relacionada a preparação para vinda"}],"resposta_correta":"b","explicacao":"A preparação para a vinda requer fé viva, obediência constante e dedicação espiritual. Preparação inclui permanecer fiel apesar das pressões. Jesus será honrado por aqueles que O esperaram fielmente.","referencias":[{"texto":"Preparação necessária","livro":"Mateus","capitulo":25,"versiculo":13,"conteudo":"Vigiai, pois não sabeis a que hora vem o vosso Senhor"}]},{"id":"cf_22_q7","numero":7,"texto":"Qual é a importância de iminência nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a iminência"},{"id":"b","texto":"Opção B relacionada a iminência"},{"id":"c","texto":"Opção C relacionada a iminência"},{"id":"d","texto":"Opção D relacionada a iminência"}],"resposta_correta":"c","explicacao":"A iminência da vinda significa que é possível ocorrer a qualquer momento sem sinais adicionais. Esta verdade deveria motivar urgência espiritual. Ninguém deve adiar sua conversão ou dedicação.","referencias":[{"texto":"Iminência da vinda","livro":"1 Pedro","capitulo":4,"versiculo":7,"conteudo":"Ora, está próximo o fim de todas as coisas"}]},{"id":"cf_22_q8","numero":8,"texto":"Qual é a importância de glória de Cristo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a glória de Cristo"},{"id":"b","texto":"Opção B relacionada a glória de Cristo"},{"id":"c","texto":"Opção C relacionada a glória de Cristo"},{"id":"d","texto":"Opção D relacionada a glória de Cristo"}],"resposta_correta":"d","explicacao":"A glória de Cristo será revelada completamente quando retornar triunfante. Será o momento de Sua vindicação final perante todo o universo. Sua glória encerrará o drama do pecado.","referencias":[{"texto":"Glória da vinda","livro":"Mateus","capitulo":24,"versiculo":30,"conteudo":"Então aparecerá no céu o sinal do Filho do Homem"}]},{"id":"cf_22_q9","numero":9,"texto":"Qual é a importância de julgamento nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a julgamento"},{"id":"b","texto":"Opção B relacionada a julgamento"},{"id":"c","texto":"Opção C relacionada a julgamento"},{"id":"d","texto":"Opção D relacionada a julgamento"}],"resposta_correta":"a","explicacao":"O julgamento ocorrerá quando Cristo retornar, separando os justos dos injustos eternamente. Cada um receberá o que merece de suas ações. Este julgamento é absolutamente justo e final.","referencias":[{"texto":"Julgamento final","livro":"Mateus","capitulo":25,"versiculo":31,"conteudo":"Quando o Filho do Homem se assentar no trono da sua glória"}]},{"id":"cf_22_q10","numero":10,"texto":"Qual é a importância de eternidade nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a eternidade"},{"id":"b","texto":"Opção B relacionada a eternidade"},{"id":"c","texto":"Opção C relacionada a eternidade"},{"id":"d","texto":"Opção D relacionada a eternidade"}],"resposta_correta":"b","explicacao":"A eternidade será realidade dos salvos que viverão com Deus para sempre. Será fim de toda dor, sofrimento e morte. A vida eterna é a recompensa suprema dos fiéis.","referencias":[{"texto":"Vida eterna","livro":"João","capitulo":3,"versiculo":16,"conteudo":"Para que todo aquele que nele crê não pereça, mas tenha a vida eterna"}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que a segunda vinda de Cristo está muito próxima e é pessoal e visível."},{"id":"cf2","texto":"Desejo estar preparado espiritualmente para encontrar o Senhor na Sua vinda."},{"id":"cf3","texto":"Comprometo-me a viver de forma que reflita a esperança do breve retorno de Jesus."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 23, 'Origem, Natureza e Destino das Pessoas', 'O Estado dos Mortos', 'Este tema aborda origem, natureza e destino das pessoas, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_23_q1","numero":1,"texto":"Qual é a importância de origem do ser humano nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a origem do ser humano"},{"id":"b","texto":"Opção B relacionada a origem do ser humano"},{"id":"c","texto":"Opção C relacionada a origem do ser humano"},{"id":"d","texto":"Opção D relacionada a origem do ser humano"}],"resposta_correta":"a","explicacao":"O ser humano foi criado à imagem de Deus com propósito e dignidade infinita. A origem divina é fundamental para entender nosso valor. Rejeitar evolução é afirmar a criação especial.","referencias":[{"texto":"Criação à imagem de Deus","livro":"Gênesis","capitulo":1,"versiculo":27,"conteudo":"Criou Deus o homem à sua imagem, à imagem de Deus o criou"}]},{"id":"cf_23_q2","numero":2,"texto":"Qual é a importância de natureza do ser humano nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a natureza do ser humano"},{"id":"b","texto":"Opção B relacionada a natureza do ser humano"},{"id":"c","texto":"Opção C relacionada a natureza do ser humano"},{"id":"d","texto":"Opção D relacionada a natureza do ser humano"}],"resposta_correta":"b","explicacao":"A natureza humana é tricotômica: espírito, alma e corpo, funcionando como unidade integrada. Somos seres completos em unidade. Cada componente tem seu papel essencial.","referencias":[{"texto":"Natureza humana completa","livro":"1 Tessalonicenses","capitulo":5,"versiculo":23,"conteudo":"Que o próprio Deus da paz vos santifique completamente"}]},{"id":"cf_23_q3","numero":3,"texto":"Qual é a importância de imortalidade da alma nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a imortalidade da alma"},{"id":"b","texto":"Opção B relacionada a imortalidade da alma"},{"id":"c","texto":"Opção C relacionada a imortalidade da alma"},{"id":"d","texto":"Opção D relacionada a imortalidade da alma"}],"resposta_correta":"c","explicacao":"A imortalidade da alma é rejeitada biblicamente; o homem é mortal por natureza. Apenas Deus possui imortalidade inerente. A imortalidade é dom conquistado através de Cristo.","referencias":[{"texto":"Mortalidade humana","livro":"Romanos","capitulo":6,"versiculo":23,"conteudo":"O salário do pecado é a morte, mas o dom de Deus é a vida eterna"}]},{"id":"cf_23_q4","numero":4,"texto":"Qual é a importância de destino eterno nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a destino eterno"},{"id":"b","texto":"Opção B relacionada a destino eterno"},{"id":"c","texto":"Opção C relacionada a destino eterno"},{"id":"d","texto":"Opção D relacionada a destino eterno"}],"resposta_correta":"d","explicacao":"O destino eterno de cada pessoa é determinado por suas escolhas e fidelidade a Deus. Céu e inferno são realidades eternas com destinação baseada em caráter. Cada escolha molda nosso destino.","referencias":[{"texto":"Destino eterno","livro":"2 Coríntios","capitulo":5,"versiculo":10,"conteudo":"Porque todos devemos comparecer perante o tribunal de Cristo"}]},{"id":"cf_23_q5","numero":5,"texto":"Qual é a importância de salvação pessoal nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a salvação pessoal"},{"id":"b","texto":"Opção B relacionada a salvação pessoal"},{"id":"c","texto":"Opção C relacionada a salvação pessoal"},{"id":"d","texto":"Opção D relacionada a salvação pessoal"}],"resposta_correta":"a","explicacao":"A salvação pessoal é obra de Deus operada pela fé individual em Cristo. Não há salvação corporativa automática. Cada um responde individualmente a Deus.","referencias":[{"texto":"Salvação pessoal","livro":"João","capitulo":1,"versiculo":12,"conteudo":"A todos quantos o receberam, deu-lhes poder de serem filhos de Deus"}]},{"id":"cf_23_q6","numero":6,"texto":"Qual é a importância de livre arbítrio nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a livre arbítrio"},{"id":"b","texto":"Opção B relacionada a livre arbítrio"},{"id":"c","texto":"Opção C relacionada a livre arbítrio"},{"id":"d","texto":"Opção D relacionada a livre arbítrio"}],"resposta_correta":"b","explicacao":"O livre arbítrio é capacidade divina para escolher bem ou mal livremente. Sem livre arbítrio não há responsabilidade moral genuína. Deus respeita nossa liberdade de escolha.","referencias":[{"texto":"Livre arbítrio","livro":"Deuteronômio","capitulo":30,"versiculo":19,"conteudo":"Tem posto diante de ti a vida e a morte, a bênção e a maldição"}]},{"id":"cf_23_q7","numero":7,"texto":"Qual é a importância de responsabilidade moral nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a responsabilidade moral"},{"id":"b","texto":"Opção B relacionada a responsabilidade moral"},{"id":"c","texto":"Opção C relacionada a responsabilidade moral"},{"id":"d","texto":"Opção D relacionada a responsabilidade moral"}],"resposta_correta":"c","explicacao":"A responsabilidade moral flui do livre arbítrio e da natureza racional do ser humano. Respondemos a Deus por nossas ações. Esta responsabilidade é perpétua e pessoal.","referencias":[{"texto":"Responsabilidade moral","livro":"Romanos","capitulo":14,"versiculo":12,"conteudo":"De maneira que cada um de nós dará contas de si mesmo a Deus"}]},{"id":"cf_23_q8","numero":8,"texto":"Qual é a importância de morte nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a morte"},{"id":"b","texto":"Opção B relacionada a morte"},{"id":"c","texto":"Opção C relacionada a morte"},{"id":"d","texto":"Opção D relacionada a morte"}],"resposta_correta":"d","explicacao":"A morte é separação do espírito do corpo, entrar em repouso até a ressurreição. Morte não é extinção mas transição. O sono da morte aguarda o chamado da ressurreição.","referencias":[{"texto":"A morte","livro":"1 Tessalonicenses","capitulo":4,"versiculo":14,"conteudo":"Porque, se cremos que Jesus morreu e ressurgiu"}]},{"id":"cf_23_q9","numero":9,"texto":"Qual é a importância de ressurreição nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a ressurreição"},{"id":"b","texto":"Opção B relacionada a ressurreição"},{"id":"c","texto":"Opção C relacionada a ressurreição"},{"id":"d","texto":"Opção D relacionada a ressurreição"}],"resposta_correta":"a","explicacao":"A ressurreição é retorno do espírito ao corpo glorificado para a eternidade. Ressurreição garante continuidade pessoal e reconhecimento. É fundamento da esperança cristã.","referencias":[{"texto":"Ressurreição dos mortos","livro":"1 Coríntios","capitulo":15,"versiculo":42,"conteudo":"Assim é também a ressurreição dos mortos"}]},{"id":"cf_23_q10","numero":10,"texto":"Qual é a importância de céu e inferno nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a céu e inferno"},{"id":"b","texto":"Opção B relacionada a céu e inferno"},{"id":"c","texto":"Opção C relacionada a céu e inferno"},{"id":"d","texto":"Opção D relacionada a céu e inferno"}],"resposta_correta":"b","explicacao":"Céu e inferno são realidades eternas onde habitantes experimentam sua escolha final. Céu é comunhão eterna com Deus. Inferno é separação completa de Deus.","referencias":[{"texto":"Céu e inferno","livro":"Mateus","capitulo":25,"versiculo":46,"conteudo":"E irão estes para o castigo eterno, mas os justos para a vida eterna"}]},{"id":"cf_23_q11","numero":11,"texto":"Qual é a importância de juízo investigativo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a juízo investigativo"},{"id":"b","texto":"Opção B relacionada a juízo investigativo"},{"id":"c","texto":"Opção C relacionada a juízo investigativo"},{"id":"d","texto":"Opção D relacionada a juízo investigativo"}],"resposta_correta":"c","explicacao":"O juízo investigativo precede a segunda vinda, examinando cada vida em luz divina. Determina quem é digno do céu. É processo justo onde Deus avalia corações.","referencias":[{"texto":"Juízo investigativo","livro":"Daniel","capitulo":7,"versiculo":9,"conteudo":"Estive olhando até que se puseram uns tronos, e o Ancião de dias se assentou"}]},{"id":"cf_23_q12","numero":12,"texto":"Qual é a importância de retribuição eterna nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a retribuição eterna"},{"id":"b","texto":"Opção B relacionada a retribuição eterna"},{"id":"c","texto":"Opção C relacionada a retribuição eterna"},{"id":"d","texto":"Opção D relacionada a retribuição eterna"}],"resposta_correta":"d","explicacao":"A retribuição eterna reflete justiça divina: recompensa para os salvos, castigo para perdidos. É consequência natural das escolhas. Deus é justo em todas as ações.","referencias":[{"texto":"Retribuição eterna","livro":"Apocalipse","capitulo":20,"versiculo":12,"conteudo":"E vi os mortos, pequenos e grandes, de pé diante do trono"}]}]'::jsonb, '[{"id":"cf1","texto":"Creio que os mortos dormem inconscientemente até a ressurreição."},{"id":"cf2","texto":"Reconheço que a imortalidade é um dom de Deus concedido somente aos justos na segunda vinda."},{"id":"cf3","texto":"Desejo viver cada dia como se fosse o último, preparando-me para a eternidade."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 24, 'O Milênio', 'Os Mil Anos de Apocalipse 20', 'Este tema aborda o milênio, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_24_q1","numero":1,"texto":"Qual é a importância de duração do milênio nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a duração do milênio"},{"id":"b","texto":"Opção B relacionada a duração do milênio"},{"id":"c","texto":"Opção C relacionada a duração do milênio"},{"id":"d","texto":"Opção D relacionada a duração do milênio"}],"resposta_correta":"a","explicacao":"O milênio dura mil anos literalmente segundo Apocalipse. Período onde Cristo reina com Seus santos. Marca transição entre eras.","referencias":[{"texto":"Os mil anos","livro":"Apocalipse","capitulo":20,"versiculo":4,"conteudo":"E vi tronos, e assentaram-se sobre eles e foi-lhes dado poder de julgar"}]},{"id":"cf_24_q2","numero":2,"texto":"Qual é a importância de eventos do milênio nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a eventos do milênio"},{"id":"b","texto":"Opção B relacionada a eventos do milênio"},{"id":"c","texto":"Opção C relacionada a eventos do milênio"},{"id":"d","texto":"Opção D relacionada a eventos do milênio"}],"resposta_correta":"b","explicacao":"Eventos do milênio incluem ressurreição dos salvos, punição de Satanás e exame de registros. Serão mil anos de atividades divinas contínuas. Culmina na nova criação.","referencias":[{"texto":"Eventos do milênio","livro":"Apocalipse","capitulo":20,"versiculo":1,"conteudo":"Vi descer do céu um anjo, que tinha a chave do abismo"}]},{"id":"cf_24_q3","numero":3,"texto":"Qual é a importância de cristo durante milênio nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a cristo durante milênio"},{"id":"b","texto":"Opção B relacionada a cristo durante milênio"},{"id":"c","texto":"Opção C relacionada a cristo durante milênio"},{"id":"d","texto":"Opção D relacionada a cristo durante milênio"}],"resposta_correta":"c","explicacao":"Cristo durante milênio permanece em liderança divina, reinando supremamente. Sua autoridade é incontestável. Seus santos participam de Seu reinado.","referencias":[{"texto":"Cristo no milênio","livro":"Apocalipse","capitulo":20,"versiculo":6,"conteudo":"Bem-aventurado e santo aquele que tem parte na primeira ressurreição"}]},{"id":"cf_24_q4","numero":4,"texto":"Qual é a importância de santos ressurretos nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a santos ressurretos"},{"id":"b","texto":"Opção B relacionada a santos ressurretos"},{"id":"c","texto":"Opção C relacionada a santos ressurretos"},{"id":"d","texto":"Opção D relacionada a santos ressurretos"}],"resposta_correta":"d","explicacao":"Os santos ressurretos participam do reinado milenar com Cristo, julgando as nações. Receberão corpos glorificados incorruptíveis. Sua recompensa será condecoração eterna.","referencias":[{"texto":"Reinado dos santos","livro":"Apocalipse","capitulo":20,"versiculo":6,"conteudo":"Reinarão com Cristo mil anos"}]},{"id":"cf_24_q5","numero":5,"texto":"Qual é a importância de terra durante milênio nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a terra durante milênio"},{"id":"b","texto":"Opção B relacionada a terra durante milênio"},{"id":"c","texto":"Opção C relacionada a terra durante milênio"},{"id":"d","texto":"Opção D relacionada a terra durante milênio"}],"resposta_correta":"a","explicacao":"A terra durante milênio permanece desolada, sem moradores vivos. Satanás e seus demônios serão aprisionados. Planeta inteiro descansa de pecado.","referencias":[{"texto":"Terra no milênio","livro":"Apocalipse","capitulo":20,"versiculo":9,"conteudo":"E subiram sobre a largura da terra e cercaram o acampamento dos santos"}]},{"id":"cf_24_q6","numero":6,"texto":"Qual é a importância de morte do pecado nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a morte do pecado"},{"id":"b","texto":"Opção B relacionada a morte do pecado"},{"id":"c","texto":"Opção C relacionada a morte do pecado"},{"id":"d","texto":"Opção D relacionada a morte do pecado"}],"resposta_correta":"b","explicacao":"A morte do pecado significa o fim de todo sofrimento e mal temporal. Pecado não terá mais poder sobre criaturas. Seu domínio será completamente erradicado.","referencias":[{"texto":"Fim do pecado","livro":"Apocalipse","capitulo":20,"versiculo":10,"conteudo":"E o diabo que os enganava foi lançado no lago de fogo"}]},{"id":"cf_24_q7","numero":7,"texto":"Qual é a importância de renovação nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a renovação"},{"id":"b","texto":"Opção B relacionada a renovação"},{"id":"c","texto":"Opção C relacionada a renovação"},{"id":"d","texto":"Opção D relacionada a renovação"}],"resposta_correta":"c","explicacao":"A renovação significará que após milênio, terra será restaurada para nova criação. Deserto florescerá novamente. Será readaptada para eternidade.","referencias":[{"texto":"Restauração da terra","livro":"2 Pedro","capitulo":3,"versiculo":13,"conteudo":"Mas nós, segundo a sua promessa, esperamos novos céus e nova terra"}]},{"id":"cf_24_q8","numero":8,"texto":"Qual é a importância de preparação para nova terra nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a preparação para nova terra"},{"id":"b","texto":"Opção B relacionada a preparação para nova terra"},{"id":"c","texto":"Opção C relacionada a preparação para nova terra"},{"id":"d","texto":"Opção D relacionada a preparação para nova terra"}],"resposta_correta":"d","explicacao":"Preparação para nova terra inclui julgamento dos perdidos e criação de novo céu. O antigo passará, o novo virá. Será consumação perfeita.","referencias":[{"texto":"Preparação escatológica","livro":"Isaías","capitulo":65,"versiculo":17,"conteudo":"Pois eis que eu crio novos céus e nova terra"}]},{"id":"cf_24_q9","numero":9,"texto":"Qual é a importância de juízo nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a juízo"},{"id":"b","texto":"Opção B relacionada a juízo"},{"id":"c","texto":"Opção C relacionada a juízo"},{"id":"d","texto":"Opção D relacionada a juízo"}],"resposta_correta":"a","explicacao":"O juízo ocorre ao fim do milênio quando perdidos ressurgem para condenação final. Deus examina todos equitativamente. Justiça é completada.","referencias":[{"texto":"Julgamento final","livro":"Apocalipse","capitulo":20,"versiculo":12,"conteudo":"Foram julgados cada um segundo as suas obras"}]},{"id":"cf_24_q10","numero":10,"texto":"Qual é a importância de anjos nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a anjos"},{"id":"b","texto":"Opção B relacionada a anjos"},{"id":"c","texto":"Opção C relacionada a anjos"},{"id":"d","texto":"Opção D relacionada a anjos"}],"resposta_correta":"b","explicacao":"Os anjos permanecerão servindo a Deus eternamente. Terão papéis nas eras vindouras. Sua rebeldia foi contida e derrota assegurada.","referencias":[{"texto":"Ministério dos anjos","livro":"Hebreus","capitulo":1,"versiculo":14,"conteudo":"Não são todos eles espíritos encarregados de um ministério?"}]}]'::jsonb, '[{"id":"cf1","texto":"Creio no milênio bíblico conforme descrito em Apocalipse 20."},{"id":"cf2","texto":"Reconheço a justiça de Deus no juízo que será realizado durante os mil anos no Céu."},{"id":"cf3","texto":"Desejo estar entre os salvos que participarão do milênio com Cristo."}]'::jsonb)
