INSERT INTO eb_pontos (modulo_id, ponto_numero, titulo, subtitulo, introducao, imagem_url, video_url, video_thumbnail, secoes, perguntas, compromissos_fe)
VALUES ('crencas_fundamentais', 25, 'A Nova Terra', 'A Herança Eterna dos Santos', 'Este tema aborda a nova terra, um dos pontos fundamentais das Crenças Fundamentais dos Adventistas do Sétimo Dia — Movimento de Reforma, baseado em princípios bíblicos e escriturísticos.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"cf_25_q1","numero":1,"texto":"Qual é a importância de características da nova terra nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a características da nova terra"},{"id":"b","texto":"Opção B relacionada a características da nova terra"},{"id":"c","texto":"Opção C relacionada a características da nova terra"},{"id":"d","texto":"Opção D relacionada a características da nova terra"}],"resposta_correta":"a","explicacao":"A nova terra será caracterizada por beleza perfeita, abundância e harmonia completa. Será superior a Éden antes da queda. Será refúgio eterno dos salvos.","referencias":[{"texto":"Características da nova terra","livro":"Apocalipse","capitulo":21,"versiculo":4,"conteudo":"Enxugará Deus toda lágrima dos olhos deles"}]},{"id":"cf_25_q2","numero":2,"texto":"Qual é a importância de transformação nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a transformação"},{"id":"b","texto":"Opção B relacionada a transformação"},{"id":"c","texto":"Opção C relacionada a transformação"},{"id":"d","texto":"Opção D relacionada a transformação"}],"resposta_correta":"b","explicacao":"A transformação inclui remoção de toda morte, doença e sofrimento. Natureza será restaurada à perfeição original. Será metamorfose cósmica.","referencias":[{"texto":"Transformação cósmica","livro":"2 Pedro","capitulo":3,"versiculo":12,"conteudo":"Esperando e apressando a vinda do dia de Deus"}]},{"id":"cf_25_q3","numero":3,"texto":"Qual é a importância de glória futura nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a glória futura"},{"id":"b","texto":"Opção B relacionada a glória futura"},{"id":"c","texto":"Opção C relacionada a glória futura"},{"id":"d","texto":"Opção D relacionada a glória futura"}],"resposta_correta":"c","explicacao":"A glória futura será revelação da graça e poder divinos em sua plenitude. Será incomparável em beleza e majestade. Excederá compreensão terrena.","referencias":[{"texto":"Glória da eternidade","livro":"1 Coríntios","capitulo":2,"versiculo":9,"conteudo":"Coisas que olhos não viram, e ouvidos não ouviram"}]},{"id":"cf_25_q4","numero":4,"texto":"Qual é a importância de habitação eterna nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a habitação eterna"},{"id":"b","texto":"Opção B relacionada a habitação eterna"},{"id":"c","texto":"Opção C relacionada a habitação eterna"},{"id":"d","texto":"Opção D relacionada a habitação eterna"}],"resposta_correta":"d","explicacao":"A habitação eterna será morada de Deus com o homem, comunhão perfeita. Será fim de exílio espiritual. Será retorno ao Paraíso.","referencias":[{"texto":"Habitação eterna","livro":"Apocalipse","capitulo":21,"versiculo":3,"conteudo":"Eis o tabernáculo de Deus com os homens"}]},{"id":"cf_25_q5","numero":5,"texto":"Qual é a importância de ausência de pecado nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a ausência de pecado"},{"id":"b","texto":"Opção B relacionada a ausência de pecado"},{"id":"c","texto":"Opção C relacionada a ausência de pecado"},{"id":"d","texto":"Opção D relacionada a ausência de pecado"}],"resposta_correta":"a","explicacao":"A ausência de pecado significará fim absoluto de toda maldade e rebelião. Ninguém conhecerá tentação ou queda. Será segurança perpétua.","referencias":[{"texto":"Ausência de pecado","livro":"Apocalipse","capitulo":21,"versiculo":27,"conteudo":"Nada impuro jamais entrará nela"}]},{"id":"cf_25_q6","numero":6,"texto":"Qual é a importância de comunhão com Deus nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a comunhão com Deus"},{"id":"b","texto":"Opção B relacionada a comunhão com Deus"},{"id":"c","texto":"Opção C relacionada a comunhão com Deus"},{"id":"d","texto":"Opção D relacionada a comunhão com Deus"}],"resposta_correta":"b","explicacao":"A comunhão com Deus será o bem supremo, presença pessoal e contínua. Ver Deus face a face será privilégio eterno. Será intimidade absoluta.","referencias":[{"texto":"Comunhão com Deus","livro":"Apocalipse","capitulo":22,"versiculo":4,"conteudo":"Verão o seu rosto, e o seu nome estará em suas frontes"}]},{"id":"cf_25_q7","numero":7,"texto":"Qual é a importância de alegria eterna nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a alegria eterna"},{"id":"b","texto":"Opção B relacionada a alegria eterna"},{"id":"c","texto":"Opção C relacionada a alegria eterna"},{"id":"d","texto":"Opção D relacionada a alegria eterna"}],"resposta_correta":"c","explicacao":"A alegria eterna será jubilação permanente, sem tristeza possível. Será celebração infinita. Corações conhecerão gozo completo.","referencias":[{"texto":"Alegria eterna","livro":"Apocalipse","capitulo":21,"versiculo":4,"conteudo":"Não haverá mais morte, nem tristeza, nem choro, nem dor"}]},{"id":"cf_25_q8","numero":8,"texto":"Qual é a importância de restauração nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a restauração"},{"id":"b","texto":"Opção B relacionada a restauração"},{"id":"c","texto":"Opção C relacionada a restauração"},{"id":"d","texto":"Opção D relacionada a restauração"}],"resposta_correta":"d","explicacao":"A restauração perfeitamente completará obra de redenção iniciada por Cristo. Será consumação de promessas divinas. Toda dor será vindicada.","referencias":[{"texto":"Restauração completa","livro":"Apocalipse","capitulo":21,"versiculo":5,"conteudo":"Eis que faço novas todas as coisas"}]},{"id":"cf_25_q9","numero":9,"texto":"Qual é a importância de natureza renovada nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a natureza renovada"},{"id":"b","texto":"Opção B relacionada a natureza renovada"},{"id":"c","texto":"Opção C relacionada a natureza renovada"},{"id":"d","texto":"Opção D relacionada a natureza renovada"}],"resposta_correta":"a","explicacao":"A natureza renovada será ambiente perfeito para vida eterna gloriosa. Será adaptada a necessidades dos salvos eternamente. Será beleza infinita.","referencias":[{"texto":"Natureza renovada","livro":"Isaías","capitulo":65,"versiculo":21,"conteudo":"Construirão casas e nelas habitarão"}]},{"id":"cf_25_q10","numero":10,"texto":"Qual é a importância de corpo glorificado nas Crenças Fundamentais?","opcoes":[{"id":"a","texto":"Opção A relacionada a corpo glorificado"},{"id":"b","texto":"Opção B relacionada a corpo glorificado"},{"id":"c","texto":"Opção C relacionada a corpo glorificado"},{"id":"d","texto":"Opção D relacionada a corpo glorificado"}],"resposta_correta":"b","explicacao":"O corpo glorificado será resultado da ressurreição, incorruptível e eterno. Será similar ao de Cristo ressurreto. Permitirá existência perfeita.","referencias":[{"texto":"Corpo glorificado","livro":"1 Coríntios","capitulo":15,"versiculo":53,"conteudo":"Este corpo corruptível há de se revestir de incorruptibilidade"}]}]'::jsonb, '[{"id":"cf1","texto":"Creio na promessa de Deus de criar novos céus e nova terra."},{"id":"cf2","texto":"Anseio pela Nova Jerusalém onde não haverá mais morte, dor ou sofrimento."},{"id":"cf3","texto":"Desejo habitar eternamente com Deus na Nova Terra prometida aos fiéis."}]'::jsonb)
ON CONFLICT (modulo_id, ponto_numero) DO UPDATE SET titulo=EXCLUDED.titulo, subtitulo=EXCLUDED.subtitulo, introducao=EXCLUDED.introducao, imagem_url=EXCLUDED.imagem_url, video_url=EXCLUDED.video_url, secoes=EXCLUDED.secoes, perguntas=EXCLUDED.perguntas, compromissos_fe=EXCLUDED.compromissos_fe, updated_at=now();

